INSERT INTO `plants` VALUES (185,'2025-12-05 16:38:43','1','2025-12-05 16:38:43','1',NULL,'','Lá và hoa Atiso chứa các acid phenolic.','Không dùng cho người mẫn cảm.','Cây thảo lớn, sống hai năm hoặc lâu năm, cao 1-1,2m, có thể lên đến 2m. Thân ngắn, thẳng và cứng có khía dọc, phủ lông trắng như bông.\nLá to, dài, mọc so le, phiến lá xẻ thùy sâu và có răng không đều, mặt trên màu xanh lục, mặt dưới có lông trắng, cuống lá to và ngắn.\nCụm hoa hình đầu ở ngọn các nhánh của thân màu đỏ hoặc tím lơ nhạt; lá bắc ngoài của cụm hoa rộng, dày và nhọn, đế cụm hoa nạc, phủ đầy lông tơ, mang toàn hoa hình ống.\nQuả nhẵn bóng, màu nâu sẫm, có mào lông trắng.\nMùa hoa quả: Tháng 12-2.',NULL,'Dạng trà: 2-3g lá Atiso khô.','Ở Việt Nam, atisô được trồng nhiều ở Đà Lạt, Sa Pa, và Tam Đảo – nơi có khí hậu mát mẻ quanh năm.',_binary '','Lá Atiso 10g.','Cynara',NULL,'Rối loạn chức năng gan...','Hỗ trợ chức năng gan...','Atiso','Atisô, Actiso','Lá, hoa, quả, rễ','DA_XUAT_BAN','Cynara scolymus','Hiếm khi gây tác dụng phụ.','atiso',0,18,'Tụ thành cụm lớn ở đầu cành, có màu tím. Phần được dùng làm thực phẩm là cụm hoa chưa nở, gọi là nụ atisô.','','Lớn, có răng cưa sâu, màu xanh lục đậm, mặt dưới có lông trắng xám. Lá mọSc cách và tập trung ở gốc.','Ăn sâu, phát triển mạnh.','Cây thảo sống lâu năm, cao 1–1,5 m.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764952720/vcybtuqp9gfgqxn6gavs.jpg'),(186,'2025-12-05 17:02:43','1','2025-12-05 17:02:43','1',NULL,'Gừng là cây thảo. Phổ biến ở Việt Nam','','Không dùng cho người viêm loét dạ dày.','Gừng là một loại thảo nhỏ, sống lâu năm, cao 0,6-1m. thân rễ nạc, mọc bò ngang, phân nhánh l\nLá mọc so le không cuống, có bẹ, hình mác dài 15-20cm, rộng chừng 2cm, mặt bong nhẵn, gân giữa hơi trắng nhạt, vò có mùi thơm.\nTrục hoa xuất phát từ gốc, dài tới 20cm, rộng 2-3cm, lá bắc hình trứng, dài 2,5cm, mép lưng màu vàng, đài hoa dài chừng 1cm, có 3 răng ngắn, 3 cành hoa dài chừng 2cm, màu vàng xanh, mép cánh hoa màu tím, nhị cũng tím. Loài gừng trồng ít ra hoa\nToàn cây, nhất là thân rễ có mùi thơm, vị cay nóng\nMùa hoa quả: Tháng 5-8.',NULL,'Trà: 1-2g gừng khô.','Gừng ưa khí hậu nóng ẩm.',_binary '','Gừng tươi 10g.','Zingiber',NULL,'Say tàu xe.','Kích thích tiêu hóa.','Gừng','Sinh khương','Thân rễ','DA_XUAT_BAN','Zingiber officinale','Hiếm khi gây tác dụng phụ.','gung',0,9,'Trục hoa xuất phát từ gốc, dài tới 20cm, rộng 2-3cm, lá bắc hình trứng, dài 2,5cm, mép lưng màu vàng, đài hoa dài chừng 1cm, có 3 răng ngắn, 3 cành hoa dài chừng 2cm, màu vàng xanh, mép cánh hoa màu tím, nhị cũng tím. Loài gừng trồng ít ra hoa\n','','Lá mọc so le không cuống, có bẹ, hình mác dài 15-20cm, rộng chừng 2cm, mặt bong nhẵn, gân giữa hơi trắng nhạt, vò có mùi thơm.\n','Toàn cây, nhất là thân rễ có mùi thơm, vị cay nóng\n','Thân rễ gừng chứa tinh dầu.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764954140/mqrnksiztwjhixzeoes6.jpg'),(187,'2025-12-05 17:06:51','1','2025-12-05 17:06:51','1',NULL,'Phổ biến ở Việt Nam','Thân rễ nghệ chứa curcuminoid.','Không dùng cho người mẫn cảm.','',NULL,'Bột: 1-3g/ngày.','Nghệ ưa khí hậu nóng ẩm.',_binary '','Nghệ 10g.','Curcuma',NULL,'Viêm loét dạ dày.','Kháng viêm.','Nghệ','Nghệ vàng','Thân rễ','DA_XUAT_BAN','Curcuma longa','Hiếm khi gây tác dụng phụ.','nghe',0,9,'','','','','Thân rễ nghệ chứa curcuminoid.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764954405/wiybet5a7phoat9kuhtm.jpg'),(188,'2025-12-05 17:17:40','1','2025-12-05 17:17:40','1',NULL,'Sả là loại cỏ sống lâu năm, mọc thành bụi, cao từ 0,8-1,5m hay hơn.\n','Tinh dầu sả cất từ loài Cymbopogon martinii var. motia chứa 15-95% geraniola còn var. Sofia chứa ancol perilic.\n\n','Dị ứng với sả hoặc các loại tinh dầu.\n\nPhụ nữ mang thai hoặc cho con bú nên dùng thận trọng.\n\nNgười huyết áp thấp hoặc đang dùng thuốc hạ huyết áp nên tham khảo ý kiến bác sĩ.','Sả là loại cỏ sống lâu năm, mọc thành bụi, cao từ 0,8-1,5m hay hơn.\nThân rễ trắng hay hơi tím.\nLá hẹp, dài giống như lá lúa, mép hơi nháp.\nCụm hoa gồm nhiều bông nhỏ không cuống.\nToàn cây có mùi thơm đặc biệt mùi sả.',NULL,'Pha trà: 1–2 lá sả tươi hoặc 2–3 g rễ sả khô cho 200–250 ml nước sôi, uống 1–2 lần/ngày.\n\nTinh dầu: pha loãng trước khi xông, massage hoặc bôi ngoài da.\n\nKhông uống tinh dầu nguyên chất.','Cây sả được trồng ở khắp nước ta, nhưng diện tích trồng làm thuốc không nhiều, chỉ có tính chất gia đình và người ta chỉ dùng rễ hoặc toàn cây đào về dùng tươi hay phơi trong râm mát.\n\n',_binary '','Trà sả với mật ong: giảm cảm lạnh, ho, đau họng.\n\nSả + gừng: giảm đầy hơi, khó tiêu, hỗ trợ tiêu hóa.\n\nXông hơi với sả: thư giãn, giảm đau đầu, căng thẳng.','Cymbopogon',NULL,'Hỗ trợ tiêu hóa: đầy hơi, khó tiêu, co thắt dạ dày.\n\nGiảm cảm lạnh, ho, sốt nhẹ.\n\nGiảm đau đầu, căng thẳng, mệt mỏi.\n\nKháng khuẩn, kháng nấm nhẹ ngoài da.','Giúp tiêu hóa, pha nước uống cho mát và tiêu, thông tiểu tiện, ra mồ hôi, chữa cảm sốt.','Cây sả chanh','Cỏ sả, mao hương, sả chanh, cà phéc','lá, thân','DA_XUAT_BAN','Cymbopogon citratus','Có thể gây kích ứng da nếu dùng tinh dầu chưa pha loãng.\n\nUống quá nhiều trà sả có thể gây buồn nôn hoặc đau bụng.\n\nHiếm gặp: dị ứng hoặc phản ứng nhạy cảm với tinh dầu.','cay-sa-chanh',0,7,'Cụm hoa gồm nhiều bông nhỏ không cuống.\n','','Lá hẹp, dài giống như lá lúa, mép hơi nháp.\n','','Thân rễ trắng hay hơi tím.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764955047/jlf2vlmhkntlpeljqdss.jpg'),(189,'2025-12-05 17:24:41','1','2025-12-05 17:24:41','1',NULL,'','Trong toàn cây tía tô có chứa 0,50% tinh dầu, trong tinh dầu, thành phần chủ yếu là perilla- andehyt C10H14O (55%), limonen (20-30%), CL- pinen và dihydrocumin C10H14O. Chất perilla andehyt có mùi thơm đặc biệt của tía tô, chất perilla andehyt antioxim ngọt gấp 2.000 lần đường, khó tan trong nước, đun nóng sẽ phân giải, có độc, cho nên không dùng làm chất điều vị được, nhưng có người dùng làm ngọt thuốc lá.\nChất màu trong lá tía tô là do este cùa chất xyanin clorit C27H31O16Cl. Ngoài các chất trên, trong tía tô còn chứa adenin C5H5N5 và acginin C6H14N4O2.\nTrong hạt tía tô có 45-50% chất dầu lỏng, màu vàng, mùi và vị của dầu lanh (huilede lin), thuộc loại dầu khô, có chỉ số iôt vào loại cao nhất (206), chỉ số xà phòng 189,6 tỷ trọng 0,930.\nHằng năm Nhật Bản và Triều Tiên trước đây sản xuất tới 60.000 tấn dầu này để quét lên dù làm cho dù không thấm nước hoặc quét lên loại giấy không thấm nước.','Người mẫn cảm với tía tô hoặc các cây họ Bạc hà (Lamiaceae).\n\nNgười có tiền sử rối loạn đông máu hoặc đang dùng thuốc chống đông cần tham khảo bác sĩ trước khi dùng lượng lớn.\n\nPhụ nữ mang thai và cho con bú nên hạn chế dùng liều cao, đặc biệt là tinh dầu hạt.','Tía tô là một loại cỏ mọc hằng năm, thân thẳng đứng có lông. Lá mọc đối, hình trứng, đầu nhọn, mép có răng cưa to; phiến lá dài 4-12cm rộng 2,5-10cm, màu tím hoặc xanh tím, trên có lông màu tím.\nNgưòi ta phân biệt thứ tía tô có lá màu tím hung là Perilla ocymoides var. purpurascens và thứ tía tô có lá màu lục, chỉ có gân màu hung (Perilla ocymoides var..bicolor). Cuống lá ngắn 2-3cm. Hoa nhỏ, màu trắng hoặc tím nhạt, mọc thành từng chùm ở kẽ lá hay đầu cành, chùm dài 6-20cm.\nQuả là hạch nhỏ, hình cầu, đường kính 1mm, màu nâu nhạt, có mạng.',NULL,'Dạng tươi: 5–10 lá/lần, nấu nước uống hoặc chế biến món ăn.\n\nDạng khô: 3–6 g/lần, nấu trà hoặc sắc thuốc.\n\nTinh dầu hạt: dùng theo chỉ định y học, tránh uống trực tiếp liều cao.\n\nCách dùng: Có thể nấu nước uống, hơ lá, nấu canh, hoặc đắp ngoài da.','Ánh sáng: Ưa sáng, sinh trưởng tốt dưới ánh sáng mặt trời trực tiếp, nhưng cũng chịu được bóng râm nhẹ.\n\nNhiệt độ: Thích hợp ở nhiệt độ 20–30°C; kém phát triển dưới 10°C hoặc trên 35°C.\n\nĐộ ẩm: Cần đất ẩm nhưng không ngập úng; độ ẩm cao giúp cây lá to, xanh tươi.\n\nĐất: Thích hợp với đất thịt nhẹ, tơi xốp, giàu mùn, pH khoảng 5,5–7,0. Không chịu được đất chua nặng hay đất mặn.',_binary '','Trị cảm cúm, ho, nghẹt mũi:\n\n10 lá tía tô + 1 lát gừng, đun sôi, uống 2–3 lần/ngày.\n\nHỗ trợ tiêu hóa:\n\n5–7 lá tía tô tươi nấu nước uống sau bữa ăn.\n\nGiảm mẩn ngứa, viêm da:\n\nLá tía tô giã nát, đắp trực tiếp lên vùng da bị ngứa.\n\nTrị nôn mửa, say tàu xe:\n\nLá tía tô hãm trà uống trước khi đi 15–30 phút.','Perilla',NULL,'Cây tía tô được sử dụng trong y học cổ truyền và hiện đại để:\n\nTrị cảm lạnh, ho, nghẹt mũi, đau đầu (lá tía tô hơ hoặc nấu uống).\n\nHỗ trợ tiêu hóa, giảm đầy bụng, nôn mửa (lá tía tô nấu nước uống).\n\nGiảm viêm, mẩn ngứa ngoài da (lá tía tô đắp hoặc tắm).\n\nHỗ trợ hen suyễn, viêm phế quản (tinh dầu trong hạt và lá).','phát tán phong hàn, lý khí khoan hung; giải uất, hoá đờm, an thai, giải độc của cua cá. Cành không có tác dụng phát biểu, chỉ có tác dụng lý khí.','Tía tô','Tía tô, Tô ngạch','lá, cành','DA_XUAT_BAN','Perilla frutescens','Dị ứng: Ngứa, phát ban, sưng môi/mặt ở người nhạy cảm.\n\nTiêu hóa: Uống quá nhiều có thể gây đầy bụng, nóng trong.\n\nTác dụng với thuốc: Tinh dầu tía tô có thể ảnh hưởng đến thuốc chống đông hoặc thuốc hạ đường huyết.','tia-to',0,6,'Hoa nhỏ, màu trắng hoặc tím nhạt, mọc thành từng chùm ở kẽ lá hay đầu cành, chùm dài 6-20cm.','Quả là hạch nhỏ, hình cầu, đường kính 1mm, màu nâu nhạt, có mạng.','Ngưòi ta phân biệt thứ tía tô có lá màu tím hung là Perilla ocymoides var. purpurascens và thứ tía tô có lá màu lục, chỉ có gân màu hung (Perilla ocymoides var..bicolor). Cuống lá ngắn 2-3cm','','Tía tô là một loại cỏ mọc hằng năm, thân thẳng đứng có lông. Lá mọc đối, hình trứng, đầu nhọn, mép có răng cưa to; phiến lá dài 4-12cm rộng 2,5-10cm, màu tím hoặc xanh tím, trên có lông màu tím.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764955475/xpqkygsnxhldycihshmv.jpg'),(190,'2025-12-05 17:31:50','1','2025-12-05 17:31:50','1',NULL,'Cây thân thảo, sống hàng năm hoặc lâu năm tùy giống.\n\nChiều cao: khoảng 30–60 cm, một số giống có thể cao tới 1 m.\n\nMùi thơm đặc trưng, dùng làm rau gia vị, dược liệu và tinh dầu.','Trong cây húng quế có từ 0,4 đến 0,8% tinh dầu. Tinh dầu màu vàng nhạt, thơm nhẹ, dễ chịu. Tùy theo nơi trồng, các chỉ số hoá lý có thay đổi.  Tinh dầu húng quế Việt Nam cất tại một số địa phương chứa tới 80-90% metylchavicola.\n\nTinh dầu các loài Ocimum khác như Ocimum viride có thành phần chủ yếu là xinamat metyl, 35 đến 65% tymola, Ocimum sanctum có thành phần chủ yếu là linalola hoặc xineola (14-15%), các phenola (7-22%) chủ yếu là chavibetola và các tecpen không xác định, Ocimum gratissimum có thành phần chủ yếu hoặc là eugenola hoặc là tymola, Ocimum canum hay Ocimum americanum có thành phần chủ yếu hoặc camphora mà không có tymola hoặc chủ yếu tymola và không có camphora hoặc nữa chủ yếu là xitral với một ít xitronelola, mycxen và oxymen; Ocimum pilosum có thành phần chủ yếu là xitral…','Người mẫn cảm với húng quế hoặc họ Lamiaceae.\n\nNgười đang dùng thuốc chống đông hoặc thuốc hạ đường huyết cần thận trọng.\n\nPhụ nữ mang thai hoặc cho con bú nên hạn chế dùng liều cao, đặc biệt tinh dầu.','Cây thuộc thảo, sống hằng năm, thân nhẵn hay có lông, thường phân cành ngay từ dưới gốc, cao 50-60cm.\nLá mọc đối có cuống, phiến lá hình thuôn dài, có thứ màu xanh lục, có thứ màu tím đen nhạt.\nHoa nhỏ màu trắng hay hơi tía, mọc thành chùm đơn hay phân nhánh với những hoa mọc thành vòng 5 đến 6 hoa một.\nQuả chứa hạt đen bóng, khi ngâm vào nước có chất nhầy màu trắng bao quanh.',NULL,'Lá tươi: 5–10 lá/lần, dùng nấu canh, hãm trà hoặc ăn sống.\n\nLá khô: 1–3 g/lần, dùng làm gia vị hoặc sắc thuốc.\n\nTinh dầu: dùng theo hướng dẫn y học, thường nhỏ vài giọt vào nước hoặc xông hơi.\n\nCách dùng: uống, hãm trà, chế biến món ăn, đắp ngoài da hoặc xông hơi.','Người ta cho rằng cây này vốn nguồn gốc ở Ấn Độ và Trung Quốc, nhưng hiện nay được trồng ở nhiều nước nhiệt đới và ôn đới thuộc châu Á, châu Âu (như Pháp, Đức, các nước thuộc Liên Xô cũ, Ý, Tây Ban Nha…). Tại những nước này thường trồng với mục đích như hái lá và toàn cây cất tinh dầu dùng làm thuốc hay trong công nghiệp chất thơm.\n\nỞ nước ta, tại miền Bắc trước đây chỉ thấy trồng lấy lá và ngọn làm gia vị. Từ năm 1975, tại một số tỉnh đã trồng trên quy mô lớn để cất tinh dầu húng quế dùng trong công nghiệp chất thơm ở trong và ngoài nước. Ở miền Nam, ngoài mục đích như làm gia vị như ở miền Bắc, người ta còn thu hoạch quả (gọi nhầm là hạt-Fructus Ocimi) để ăn cho mát và giải nhiệt gọi là hạt é.\n\nĐể làm thuốc, người ta chỉ hái lá và ngọn có hoa (Herba Ocimi) phơi hay sấy khô. Để cất tinh dầu người ta hái toàn cây, cất tươi hay để hơi héo mới cất.',_binary '','Trị ho, cảm cúm:\n\n5–7 lá húng quế + 1 lát gừng, đun nước uống 2–3 lần/ngày.\n\nHỗ trợ tiêu hóa:\n\nLá húng quế tươi nhai sống hoặc hãm nước uống sau bữa ăn.\n\nGiảm mẩn ngứa, viêm da:\n\nLá húng quế giã nát, đắp lên vùng da bị ngứa.\n\nGiảm căng thẳng, an thần:\n\nXông hơi với vài giọt tinh dầu húng quế.','Ocimum',NULL,'Hỗ trợ tiêu hóa: giảm đầy bụng, khó tiêu, ăn không tiêu.\n\nGiảm ho, cảm cúm, đau đầu: dùng lá tía hoặc tinh dầu trong dân gian.\n\nChống viêm, sát khuẩn: giúp giảm viêm nhẹ, mẩn ngứa ngoài da.\n\nHỗ trợ an thần, giảm stress: hương thơm tinh dầu giúp thư giãn.','Mát, hơi có tác dụng chống táo bón, chữa sốt, làm cho ra mồ hôi, chữa đau dạ dày, ăn uống không tiêu, thông tiểu, nấu nước súc miệng và ngậm chữa đau, sâu răng.','Húng quế','Húng tây,Rau húng,Basil,Holy basil','lá, thân','DA_XUAT_BAN','Ocimum basilicum','Dị ứng: phát ban, ngứa, sưng môi/mặt ở người nhạy cảm.\n\nTiêu hóa: dùng quá nhiều có thể gây đầy bụng hoặc nóng trong.\n\nTương tác thuốc: tinh dầu húng quế có thể ảnh hưởng thuốc chống đông, hạ đường huyết.','hung-que',0,6,'Hoa nhỏ màu trắng hay hơi tía, mọc thành chùm đơn hay phân nhánh với những hoa mọc thành vòng 5 đến 6 hoa một.\n','Quả chứa hạt đen bóng, khi ngâm vào nước có chất nhầy màu trắng bao quanh.\n','Lá mọc đối có cuống, phiến lá hình thuôn dài, có thứ màu xanh lục, có thứ màu tím đen nhạt.\n','','Cây thuộc thảo, sống hằng năm, thân nhẵn hay có lông, thường phân cành ngay từ dưới gốc, cao 50-60cm.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764955865/sacndr5izqzelarnc3an.png'),(191,'2025-12-05 17:37:50','1','2025-12-05 17:37:50','1',NULL,'Kinh giới là một loại cỏ sống hàng năm, mùi rất thơm, cao 0,6-0,8m, thân vuông, phía gốc màu hơi tía. toàn cây có lông ngắn. Lá mọc đối, lá dưới gốc không có cuống hay gần như không có cuống, xẻ sâu thành 5 thuỳ, lá phía trên cũng không cuống, xẻ 3 đến 5 thuỳ. Cụm hoa mọc thành bông gồm những hoa mọc vòng ở mỗi đốt. Bông hoa dài 38cm, hoa nhỏ màu tím nhạt. Quả hình trứng hay hình trái xoan, dài chừng 1mm, mặt bóng, màu nâu.\n','Tinh dầu: chứa perillaldehyde, limonene, linalool, cineole, tạo mùi thơm đặc trưng.\n\nFlavonoid và polyphenol: có tác dụng chống oxy hóa, kháng viêm.\n\nAxit rosmarinic và tannin: hỗ trợ chống viêm, diệt khuẩn.\n\nCác hợp chất khác: aldehyde, ketone, aldehyd thơm, ester… tùy giống và vùng trồng.\n\nTinh dầu kinh giới thường được chiết xuất từ lá và cành non.','Người mẫn cảm với kinh giới hoặc họ Lamiaceae.\n\nNgười mắc bệnh tiêu chảy nặng hoặc rối loạn tiêu hóa cấp tính nên hạn chế dùng liều cao.\n\nPhụ nữ mang thai hoặc cho con bú: dùng liều thấp, hạn chế tinh dầu đặc.','Thân: Thân thảo, cao khoảng 30–60 cm, mềm, phân nhánh nhiều.\n\nLá: Hình bầu dục thuôn nhọn, mép răng cưa, mặt trên xanh lục, mặt dưới có lông tơ, mùi thơm khi vò.\n\nHoa: Nhỏ, màu tím nhạt hoặc trắng, mọc thành bông ở đầu ngọn hoặc nách lá.\n\nQuả / Hạt: Quả nhỏ, chứa 4 hạt, màu nâu hoặc đen.\n\nRễ: Rễ cọc, ăn sâu để hút nước và dinh dưỡng.\n\nSinh thái: Thích đất ẩm, giàu mùn, chịu được ánh sáng trực tiếp, sinh trưởng tốt ở nhiệt độ 20–30°C.',NULL,'Lá tươi hoặc cành non: 10–15 g/lần, sắc nước uống hoặc hãm trà 1–2 lần/ngày.\n\nLá khô: 5–10 g/lần, sắc thuốc hoặc dùng làm gia vị.\n\nTinh dầu: dùng theo hướng dẫn y học, thường xông hơi hoặc nhỏ vài giọt vào nước.\n\nCách dùng: sắc uống, hãm trà, xông hơi, chế biến món ăn, đắp ngoài da.','Ánh sáng: Ưa sáng, sinh trưởng tốt dưới ánh nắng trực tiếp.\n\nĐất: Thích đất tơi xốp, giàu mùn, thoát nước tốt, pH 6–7.\n\nNhiệt độ: Sinh trưởng tốt ở 20–30°C, kém phát triển ở nhiệt độ dưới 10°C.\n\nĐộ ẩm: Cây ưa ẩm nhưng không chịu úng, phát triển tốt trên đất đủ ẩm.\n\nPhân bố: Gốc từ Đông Á, hiện trồng phổ biến ở Bắc Bộ, Trung Bộ Việt Nam, dùng làm rau gia vị và dược liệu.',_binary '','Trị cảm, ho, nghẹt mũi:\n\n10 g lá kinh giới + 5 g lá húng quế, sắc nước uống 2 lần/ngày.\n\nHỗ trợ tiêu hóa:\n\nLá kinh giới tươi nhai sống hoặc sắc uống sau bữa ăn.\n\nGiảm mẩn ngứa, viêm da nhẹ:\n\nLá giã nát, đắp trực tiếp lên vùng da bị ngứa.\n\nXông hơi thư giãn, giảm cảm lạnh:\n\nLá kinh giới + vài giọt tinh dầu, xông hơi 10–15 phút.','Elsholtzia',NULL,'Người bị cảm lạnh, ho, sốt, nghẹt mũi.\n\nNgười đầy bụng, khó tiêu, chướng hơi.\n\nTrường hợp ngứa ngoài da, mẩn đỏ nhẹ.','Trị cảm cúm, ho, sốt, nghẹt mũi: lá và cành hãm hoặc sắc thuốc.\n\nChống viêm, kháng khuẩn, sát trùng: nhờ tinh dầu chứa perillaldehyde và linalool.\n\nHỗ trợ tiêu hóa: giảm đầy bụng, chướng hơi, ăn uống kém tiêu.\n\nGiải độc, lợi tiểu nhẹ: dùng trong một số bài thuốc dân gian.','Kinh giới','Kinh giới, Kinh giới lá nhọn, Ngải thơm, ngải tía, lá tía','Lá và cành non, hoa, Thân','DA_XUAT_BAN','Elsholtzia ciliata','Dị ứng: phát ban, ngứa, sưng môi/mặt ở người nhạy cảm.\n\nTiêu hóa: dùng quá nhiều có thể gây đầy bụng, tiêu chảy nhẹ.\n\nTương tác thuốc: tinh dầu kinh giới có thể ảnh hưởng một số thuốc chống đông hoặc thuốc hạ đường huyết nếu dùng liều cao.','kinh-gioi',0,6,'Hoa nhỏ, không cuống, màu tím nhạt, mọc thành bông ở đầu cành, rất mau.',' Quả gồm 4 hạch nhỏ, nhẵn, dài 0,5cm.','Lá mọc đối, phiến lá thuôn nhọn, dài 5-8cm, rộng 3cm, mép có răng cưa, cuống gầy dài 2-3cm','','Cây cũng thuộc thảo, cao 0,30-0.45m, thân nhẵn, mọc thẳng đứng.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764956262/wdzmtrgomvvjil21oxg0.jpg'),(192,'2025-12-05 17:45:01','1','2025-12-05 17:45:01','1',NULL,'Cây thân thảo, sống lâu năm, cao khoảng 20–60 cm, mọc bò sát mặt đất.\n\nThường được dùng làm rau ăn, dược liệu, nổi tiếng với tác dụng giải nhiệt, mát gan, làm đẹp da.\n\nPhát triển tốt ở vùng ẩm, đất giàu dinh dưỡng.','Saponin triterpenoid: asiaticoside, madecassoside, asiatic acid, madecassic acid (tác dụng tái tạo mô, làm lành vết thương).\n\nFlavonoid và polyphenol: chống oxy hóa, kháng viêm.\n\nCác hợp chất khác: tinh dầu, tannin, vitamin A, C, E, một số khoáng chất như kẽm, sắt.','Người mẫn cảm với rau má hoặc các thành phần của cây.\n\nNgười suy thận hoặc tiểu nhiều quá mức cần thận trọng.\n\nPhụ nữ mang thai hoặc cho con bú: dùng liều vừa phải, tránh tinh chất cô đặc.','Thân: Thân bò, mảnh, mềm, phân nhánh nhiều, dài từ 20–60 cm, mọc sát mặt đất.\n\nLá:\n\nHình thận hoặc hình tròn, có răng cưa nhỏ ở mép.\n\nPhiến lá mỏng, màu xanh lục, cuống dài 2–10 cm.\n\nMặt lá nhẵn, mịn, có mùi thơm nhẹ khi vò.\n\nHoa: Nhỏ, màu trắng hoặc hồng nhạt, mọc thành tán kép nhỏ, thường nở vào mùa hè.\n\nQuả / Hạt: Quả nhỏ, chia thành 2 phần, màu nâu nhạt khi chín.\n\nRễ: Rễ mảnh, bò lan dưới đất, giúp cây bám chắc và hấp thụ dinh dưỡng.\n\nSinh thái: Thích đất ẩm, tơi xốp, chịu bóng bán phần, phát triển tốt ở vùng nhiệt đới và cận nhiệt đới.',NULL,'Lá tươi: 20–30 g/ngày, ăn sống hoặc xay nước uống.\n\nDạng khô: 3–10 g/lần, sắc nước hoặc hãm trà 1–2 lần/ngày.\n\nDạng cao chiết hoặc viên nang: theo hướng dẫn y học, thường dùng hỗ trợ làm lành vết thương hoặc chăm sóc da.\n\nCách dùng: uống trực tiếp, hãm trà, chế biến món ăn, đắp ngoài da hoặc dùng thuốc bôi từ cao chiết.','Ánh sáng: Thích bán bóng hoặc ánh sáng vừa phải; chịu được nắng nhẹ.\n\nĐất: Đất ẩm, tơi xốp, giàu mùn, thoát nước tốt.\n\nNhiệt độ: 20–30°C, kém phát triển ở nhiệt độ thấp hoặc khô hạn.\n\nĐộ ẩm: Cây ưa môi trường ẩm, thường mọc ven suối, ao, bờ ruộng.\n\nPhân bố: Nhiều nơi ở Đông Nam Á, châu Á nhiệt đới và cận nhiệt đới, trong đó có Việt Nam.',_binary '','Làm lành vết thương, giảm sẹo:\n\nLá rau má tươi giã nát, đắp trực tiếp lên vết thương 1–2 lần/ngày.\n\nTrị mụn, viêm da:\n\nLá rau má tươi xay nhuyễn, trộn với mật ong, đắp mặt 10–15 phút.\n\nGiải nhiệt, lợi tiểu:\n\n20–30 g lá rau má tươi xay hoặc hãm nước uống 2 lần/ngày.\n\nHỗ trợ tiêu hóa:\n\nRau má nấu canh hoặc ép lấy nước uống sau bữa ăn.','Centella',NULL,'Làm lành vết thương, giảm sẹo: nhờ saponin triterpenoid (asiaticoside, madecassoside).\n\nHỗ trợ da: trị mụn, viêm da, giảm thâm nám, tăng sinh collagen.\n\nGiải nhiệt, mát gan, lợi tiểu nhẹ.\n\nHỗ trợ tuần hoàn, tăng cường trí nhớ: trong y học cổ truyền và hiện đại.\n\nHỗ trợ tiêu hóa, chống đầy bụng, chướng hơi.','Lợi tiểu, lỵ, cảm mạo phong nhiệt, thuỷ đậu, sởi, viêm họng, sưng Amygdal, viêm đường tiết niệu, viêm ruột, chảy máu cam, khí hư, bạch đới, đái dắt, đái buốt (cả cây sắc uống).','Rau má','Tích tuyết thảo, phanok ,Irachiek kranh','lá, thân','DA_XUAT_BAN','Centella asiatica','Dị ứng: phát ban, ngứa, mẩn đỏ trên da hoặc miệng.\n\nTiêu hóa: uống quá nhiều có thể gây buồn nôn, đi ngoài phân lỏng.\n\nTương tác thuốc: có thể ảnh hưởng đến thuốc lợi tiểu hoặc thuốc hạ đường huyết nếu dùng liều cao.','rau-ma',0,8,'Hoa nhỏ, màu trắng hoặc hồng nhạt, mọc thành tán kép nhỏ.\n\nThường nở vào mùa hè hoặc mùa mưa.\n\nHoa ít dùng làm thuốc, chủ yếu để sinh sản bằng hạt.','Quả nhỏ, chia thành 2 phần, màu nâu nhạt khi chín.\n\nHạt nhỏ, dùng để nhân giống hoặc gieo trồng.','Hình thận hoặc hình tròn, mép răng cưa nhỏ.\n\nPhiến lá mỏng, màu xanh lục, mặt lá nhẵn, mịn.\n\nCuống lá dài 2–10 cm, mọc so le hoặc vòng quanh thân.\n\nLá có mùi thơm nhẹ khi vò.','Rễ mảnh, bò lan dưới đất, giúp cây bám chắc và hấp thụ dinh dưỡng.\n\nRễ còn góp phần lan rộng cây, tạo thảm phủ đất.','Thân bò lan, mảnh, mềm, phân nhánh nhiều.\n\nChiều dài thân khoảng 20–60 cm, có khả năng bám đất và lan rộng.\n\nMàu xanh lục, đôi khi hơi tím nhạt ở một số giống.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764956662/zjia6oiulqmj72riqdze.jpg'),(194,'2025-12-05 17:55:01','1','2025-12-05 17:55:01','1',NULL,'Cây thân thảo, sống lâu năm, mọc bò lan trên mặt đất.\n\nChiều cao thân khoảng 20–50 cm.\n\nToàn cây có mùi hăng đặc trưng, dùng làm rau ăn, thuốc hoặc làm gia vị.\n\nPhát triển tốt ở nơi ẩm, đất giàu mùn, thường ven ao, bờ ruộng.','Tinh dầu: chứa houttuynin, decanoyl acetaldehyde, methyl nonyl ketone, tạo mùi hăng đặc trưng.\n\nFlavonoid và polyphenol: có tác dụng chống oxy hóa, kháng khuẩn.\n\nCác hợp chất khác: alkaloid, tannin, vitamin C, khoáng chất.','Người mẫn cảm với diếp cá hoặc tinh dầu của cây.\n\nNgười suy thận nặng hoặc tiêu chảy cấp cần hạn chế dùng liều cao.\n\nPhụ nữ mang thai hoặc cho con bú: dùng liều vừa phải, tránh dùng tinh dầu cô đặc.','Thân: thân thảo, mềm, bò lan trên mặt đất, cao khoảng 20–50 cm.\n\nLá:\n\nHình tim hoặc hình tròn, mép nguyên, phiến lá mỏng, mặt trên xanh lục, mặt dưới hơi tím nhạt.\n\nCuống lá dài 5–10 cm, có mùi thơm đặc trưng khi vò.\n\nHoa: nhỏ, màu trắng, mọc thành bông dạng bông dài ở nách lá.\n\nQuả / Hạt: quả nhỏ, chứa hạt nhỏ, ít dùng để nhân giống.\n\nRễ: rễ chùm, mọc lan dưới đất, giúp cây bò lan nhanh và hút dinh dưỡng.\n\nSinh thái: thích đất ẩm, nhiều mùn, mọc ven ao, ruộng, nơi bóng bán phần hoặc nắng vừa phải.',NULL,'Lá tươi hoặc toàn cây: 20–30 g/ngày, ăn sống, xay nước uống hoặc nấu canh.\n\nDạng sắc thuốc: 10–15 g lá tươi hoặc 5–10 g khô, sắc nước uống 1–2 lần/ngày.\n\nCách dùng: uống trực tiếp, hãm trà, chế biến món ăn, đắp ngoài da hoặc xông hơi.','Ánh sáng: Thích bán bóng hoặc ánh sáng vừa phải; chịu nắng nhẹ.\n\nĐất: Đất ẩm, tơi xốp, giàu mùn, thoát nước tốt.\n\nNhiệt độ: 20–30°C, kém phát triển ở nhiệt độ thấp hoặc khô hạn.\n\nĐộ ẩm: Cây ưa môi trường ẩm, ven ao, bờ suối hoặc ruộng nước.\n\nPhân bố: Nhiều nơi ở Đông Nam Á, châu Á nhiệt đới và cận nhiệt đới, trong đó có Việt Nam.',_binary '','Trị ho, cảm cúm nhẹ:\n\n20 g lá diếp cá + 1 lát gừng, sắc nước uống 2 lần/ngày.\n\nHỗ trợ tiêu hóa:\n\nRau diếp cá xay hoặc ăn sống sau bữa ăn.\n\nLợi tiểu, giải độc:\n\nLá diếp cá tươi 20–30 g hãm nước uống 1–2 lần/ngày.\n\nTrị mẩn ngứa, viêm da nhẹ:\n\nGiã nát lá diếp cá, đắp trực tiếp lên vùng da bị ngứa 10–15 phút.','Houttuynia',NULL,'Người bị viêm đường hô hấp trên, ho, cảm cúm nhẹ.\n\nNgười viêm đường tiết niệu nhẹ, tiểu ít, sưng viêm nhẹ.\n\nNgười đầy bụng, khó tiêu, chướng hơi.\n\nNgười bị mẩn ngứa hoặc viêm da nhẹ.','Kháng khuẩn, kháng viêm: nhờ tinh dầu chứa houttuynin, decanoyl acetaldehyde.\n\nGiải độc, lợi tiểu nhẹ: hỗ trợ thận và thanh lọc cơ thể.\n\nHỗ trợ tiêu hóa: giảm đầy bụng, khó tiêu.\n\nHạ sốt, giảm ho, cảm cúm nhẹ.\n\nChăm sóc da: giảm mụn, mẩn ngứa, viêm da nhẹ.','Diếp cá','Diếp cá, Lá giấp, Co vầy mèo (Thái), Ngư tinh thảo, Tập thái, Rau vẹn, Phiăc hoảy (Tày), Cù mua mín (Dao)','thân, lá','DA_XUAT_BAN','Houttuynia cordata','Dị ứng: phát ban, ngứa, mẩn đỏ ở người nhạy cảm.\n\nTiêu hóa: uống quá nhiều có thể gây buồn nôn, đi ngoài phân lỏng.\n\nTương tác thuốc: tinh dầu diếp cá có thể ảnh hưởng thuốc lợi tiểu hoặc hạ đường huyết nếu dùng liều cao.','diep-ca',0,35,'Hoa nhỏ, màu trắng, mọc thành bông dài ở nách lá.\n\nÍt dùng trong y học, chủ yếu để sinh sản bằng hạt.\n\nThường nở vào mùa xuân – mùa hè.','Quả nhỏ, hạt nhỏ, tròn, ít được dùng để nhân giống vì cây thường sinh sản bằng thân/rễ.','Hình tim hoặc hình tròn, mép nguyên, phiến mỏng.\n\nMặt trên xanh lục, mặt dưới hơi tím nhạt.\n\nCuống dài 5–10 cm, mọc so le hoặc xen kẽ.\n\nLá có mùi hăng đặc trưng khi vò.','Rễ chùm, bò lan dưới đất, giúp cây bám chắc và hút dinh dưỡng.\n\nRễ cũng góp phần lan rộng nhanh, tạo thảm phủ đất.','Thân mềm, bò lan trên mặt đất, phân nhánh nhiều.\n\nMàu xanh lục, đôi khi hơi tím nhạt ở gốc.\n\nCó khả năng bám đất và lan rộng, giúp cây phủ nhanh diện tích.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1764957295/pvwz9ohlkn5mbvpbl8a5.jpg'),(195,'2025-12-06 08:22:29','1','2025-12-06 08:22:29','1',NULL,'','Trong lá lốt có tinh dầu. Hoạt chất khác chưa rõ.','Không nên dùng lá lốt trong các trường hợp sau:\n\n1. Người bị nhiệt, bốc hỏa\n\nMiệng khô, khát nhiều, táo bón\n→ Lá lốt tính ấm, có thể làm triệu chứng nặng hơn.\n\n2. Người có viêm loét dạ dày nặng\n\nLá lốt có tinh dầu → dễ gây kích ứng nếu dùng quá nhiều.\n\n3. Phụ nữ có thai 3 tháng đầu\n\nKhông nên dùng liều cao hoặc uống sắc đặc.\n\n4. Người dị ứng họ Hồ tiêu (Piperaceae)','Lá lốt là cây thảo sống lâu năm, ưa ẩm, mọc bò lan trên mặt đất hoặc hơi leo.\n\nCó mùi thơm đặc trưng.\nThân bò ngang, dài 30–40 cm hoặc hơn.\n\nKhi già hóa gỗ nhẹ, trên thân có nhiều đốt, từ đốt mọc rễ phụ.',NULL,'1. Dùng uống (sắc nước)\n\nLá tươi: 20–30 g/ngày\n\nLá khô: 10–15 g/ngày\n\nSắc với 600 ml nước còn 200–250 ml, chia 2 lần uống.\n\n2. Dùng ngoài da\n\nMột nắm lá lốt tươi (30–50 g)\n\nĐun nước xông hoặc ngâm rửa.\n\n3. Dùng ăn\n\nCó thể sử dụng trong chế biến thực phẩm (nướng, xào, cuốn) nhưng không quá 50–70 g/lần.','Cây lá lốt mọc hoang và được trồng tại nhiều nơi ở miền Bắc nước ta, thường trồng bằng mẩu thân cắt thành từng khúc 20-25cm, giâm vào nơi ẩm ướt, dưới bóng cây mát. Thường nhân dân trồng lấy lá làm gia vị hay làm thuốc. Lá hái quanh năm, có thể dùng thân, hoa hay rễ. Hái về dùng tươi hay phơi khô để dành, nhưng thường dùng tươi. Nếu dùng rễ thường hái vào tháng 8-9.',_binary '','1. Trị đau nhức xương khớp do lạnh\n\nLá lốt 30 g\n\nRễ bưởi bung 15 g\n\nRễ cỏ xước 15 g\n\nRễ cây náng 15 g\n→ Sắc uống ngày 1 thang, uống 5–7 ngày.\n\n2. Trị đau bụng lạnh, đầy hơi\n\nLá lốt 20 g\n\nGừng tươi 5 g\n→ Sắc 300 ml còn 150 ml, uống ấm.\n\n3. Trị mẩn ngứa, nổi mề đay\n\nLá lốt tươi 40 g\n\nĐun nước, xông hơi và tắm khi còn ấm.\n\n4. Chữa ra mồ hôi tay chân\n\nLá lốt 30 g\n\nMuối hạt 1 thìa\n→ Đun sôi 2 lít nước, ngâm tay chân 10–15 phút/ngày.\n\n5. Trị viêm xoang nhẹ, chảy nước mũi\n\nLá lốt 10 g giã nát\n\nVắt lấy nước cốt, pha loãng với nước ấm theo tỷ lệ 1:10\n→ Nhỏ mũi 1–2 lần/ngày.','Piper',NULL,'1. Chữa đau nhức xương khớp\n\nĐau mỏi tay chân, phong thấp, lạnh khớp\n\nĐau lưng, thoái hóa nhẹ, đau do lạnh ẩm\n\n2. Chữa bệnh về tiêu hóa\n\nĐau bụng lạnh\n\nĐầy hơi, khó tiêu\n\nTiêu chảy do lạnh\n\n3. Chữa các bệnh ngoài da\n\nMẩn ngứa, nổi mề đay\n\nViêm da do tiếp xúc lạnh\n\n4. Hỗ trợ điều trị viêm nhiễm\n\nViêm xoang, chảy nước mũi\n\nViêm khớp\n\nViêm đường tiết niệu nhẹ\n\n5. Chữa ra nhiều mồ hôi tay chân\n\nDùng trong các trường hợp tay chân lạnh, đổ mồ hôi nhiều.',' Chữa đau xương, đau bụng, ỉa chảy, nôn mửa, đau răng, đau đầu, chảy nước mũi hôi (cả cây sắc uống).','Lá lốt','Lá lốp,  Lá lốt , Tất bát,  Giang tất bát , Nốt  ,Phát tô thảo','toàn thân','DA_XUAT_BAN','Piper lolot','Lá lốt tương đối an toàn nhưng có thể gây tác dụng phụ nếu dùng quá nhiều:\n\n1. Kích ứng dạ dày\n\nBuồn nôn\n\nĐau vùng thượng vị\n\nỢ nóng\n\n2. Nóng trong người\n\nNổi mụn\n\nKhát nước\n\nTáo bón\n\n3. Dị ứng\n\nNgứa, đỏ da, khó thở (hiếm)\n\n4. Tăng tiết mồ hôi khi dùng ngoài quá lâu\n\nDo tinh dầu kích thích da.','la-lot',0,44,'Cụm hoa mọc thành bông, bông hoa cái dài chừng 1cm, cuống dài 1cm.\n','','Lá hình trứng rộng, phía gốc hình tim, đầu lá nhọn, soi lên có những điểm trong, phiến lá dài 13cm, rộng 8,5cm, mặt trên nhẵn, mặt dưới hơi có lông ở gân, cuống lá dài chừng 2,5cm.\n','','Lá lốt là một loại cây mềm, mọc cao tới 1m, thân hơi có lông.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765009344/g2xnuzb1g2gjgseedk9h.jpg'),(196,'2025-12-06 09:21:56','1','2025-12-06 09:21:56','1',NULL,'','Toàn cây ngải cứu chứa tinh dầu với hàm lượng 0,2-0,34%. Thành phần chủ yếu tinh dầu là các monoterpen và sesquiterpen. Gồm 1,8 cineol, camphor, terpinen 4 ol, pinen.','Không dùng hoặc thận trọng trong các trường hợp:\n\nPhụ nữ có thai 3 tháng đầu (nếu dùng uống, tránh gây kích thích tử cung).\n\nNgười nóng trong, âm hư nội nhiệt, người hay bốc hỏa.\n\nNgười bị xuất huyết do nhiệt.\n\nNgười có bệnh gan nặng (tránh dùng kéo dài).\n\nDị ứng với tinh dầu ngải cứu.','Dạng cây: Cây thảo sống lâu năm, cao 0.5–1 m, mọc thành bụi.\n\nThân: Thân vuông hoặc hơi tròn, có rãnh dọc, phân nhiều cành nhánh.\n\nLá:\n\nMọc so le, xẻ lông chim, chia nhiều thuỳ.\n\nMặt trên màu xanh đậm, không lông.\n\nMặt dưới màu trắng bạc, phủ nhiều lông mịn – đặc trưng dễ nhận biết.\n\nHoa:\n\nHoa nhỏ, màu vàng nhạt, mọc thành chùm kép ở ngọn.\n\nMùa hoa thường vào tháng 9–10.\n\nQuả: Quả bế nhỏ, không có mào lông.\n\nMùi vị: Mùi thơm hắc đặc trưng, vị đắng nhẹ.',NULL,'Dùng uống\n\nLiều khô: 6–12 g/ngày.\n\nLá tươi: 20–40 g/ngày.\n\nSắc với 400–600 ml nước, còn 150–200 ml chia 2 lần.\n\nDùng ngoài\n\nĐắp lá tươi giã nát: trị bong gân, bầm tím.\n\nXông hơi – chườm nóng: trị cảm lạnh, đau nhức.\n\nNgải cứu cứu (hơ ngải): dùng điếu ngải hơ huyệt, trị đau khớp, suy nhược.','Ngải cứu là cây ưa sáng, nhưng cũng chịu bóng nhẹ.\n\nKhí hậu: Thích hợp khí hậu mát, ôn đới hoặc nhiệt đới gió mùa.\n\nNhiệt độ lý tưởng: 18–28°C.\n\nLượng mưa: Trung bình, nơi có độ ẩm tương đối cao.',_binary '','(1) Trị đau bụng kinh, kinh không đều\n\nNgải cứu 20 g, ích mẫu 12 g, hương phụ 8 g.\n\nSắc uống ngày 1 thang trước kỳ kinh 5–7 ngày.\n\n(2) An thai (thai động do lạnh)\n\n(Chỉ dùng khi có chỉ định thầy thuốc)\n\nNgải cứu 10 g + tía tô 10 g sắc uống.\n\n(3) Trị cảm lạnh, đau đầu do gió lạnh\n\nNgải cứu khô 10 g, gừng 3 lát, sả 1 nhánh.\n\nSắc uống hoặc xông hơi.\n\n(4) Trị đau xương khớp\n\nLá ngải cứu + muối hạt rang nóng.\n\nBọc khăn chườm lên khớp đau 10–15 phút.\n\n(5) Trị mụn nhọt – viêm da\n\nLá ngải cứu tươi giã nát, đắp trực tiếp 15–20 phút, ngày 1–2 lần.\n\n(6) Trị mất ngủ\n\nNgải cứu 15 g sắc nước uống trước ngủ 1 giờ.','',NULL,'Dùng trong các trường hợp:\n\nĐau bụng kinh, kinh nguyệt không đều.\n\nBăng huyết, chảy máu tử cung do hàn (dùng phối hợp).\n\nĐau bụng do lạnh, tiêu chảy lạnh.\n\nCảm lạnh, sốt nhẹ, đau đầu do phong hàn.\n\nĐau nhức xương khớp (thấp khớp).\n\nĐộng thai do lạnh (có chỉ định thầy thuốc).\n\nMẩn ngứa ngoài da, chàm, mụn nhọt.\n\nBong gân, bầm tím, trật khớp (đắp ngoài).','Ngải cứu trong Đông y có:\n\nTính ấm, vị đắng – cay, quy vào kinh Can, Tỳ, Thận.\n\nTác dụng:\n\nÔn kinh chỉ huyết: cầm máu do hàn lạnh.\n\nĐiều hòa khí huyết, giảm đau bụng kinh.\n\nAn thai, giảm động thai do hàn.\n\nKhu phong hàn, trị cảm lạnh, đau đầu do lạnh.\n\nGiảm đau, trị đau xương khớp, thoái hóa.\n\nLợi tiểu, hỗ trợ tiêu hóa.\n\nSát khuẩn, kháng viêm, dùng ngoài chữa mụn nhọt, chàm, eczema.','Ngải cứu','Ngải diệp,  Ngải cứu tía,  Nhả ngải,  Ngải cảm,  Cỏ linh li , Tần ngải','toàn thân','DA_XUAT_BAN','Artemisia vulgaris','Dùng đúng liều thường an toàn. Tuy nhiên, có thể gặp:\n\nTác dụng nhẹ:\n\nNóng trong, táo bón.\n\nBuồn nôn nhẹ.\n\nDị ứng da khi tiếp xúc lá tươi.\n\nTác dụng nặng (khi dùng quá liều hoặc kéo dài):\n\nRối loạn tiêu hóa, đau bụng.\n\nTổn thương gan (hiếm, khi dùng liều cao trong thời gian dài).\n\nChoáng váng, kích thích thần kinh (do tinh dầu thujone).','ngai-cuu',0,47,'Hoa mọc ở ngọn thân và đầu cành thành chùm kép, mang nhiều đầu nhỏ, màu vàng lục nhạt; tổng bao gồm những lá bắc nguyên giống như những vảy có lông','','Lá mọc so le, chẻ lông chim, phiến men theo cuống đến tận gốc, dính vào thân như có bẹ, các thùy hình mác hẹp, đầu nhọn, mặt trên màu lục sẫm, mặt dưới phủ đầy lông trắng.','','Cây thảo, sống lâu năm, cao 0,4-1m. Thân cành mọc sum sê, có rãnh và lông nhỏ.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765012904/q5xlsqiswzvb6itlvvcm.jpg'),(197,'2025-12-06 09:39:45','1','2025-12-06 09:39:45','1',NULL,'Cây thân thảo, cao khoảng 15cm đến 40cm và có thể phát triển tới 1 mét.\n','Cây lược vàng chứa nhiều hoạt chất sinh học quan trọng','Không dùng hoặc thận trọng với:\n\nPhụ nữ mang thai và cho con bú.\n\nTrẻ dưới 6 tuổi.\n\nNgười đang dùng thuốc chống đông (tương tác flavonoid).\n\nNgười dị ứng với lược vàng hoặc thực vật họ Thài lài (Commelinaceae).\n\nNgười có rối loạn nội tiết, u phụ thuộc hormone (chưa đủ bằng chứng an toàn).\n\nNgười có bệnh thận hoặc gan nặng.','Thân bò (thân khí sinh): dài, mềm, chứa nhiều chất nhầy.\n\nLá: bộ phận dùng phổ biến nhất, chứa flavonoid (quercetin, kaempferol) có tác dụng kháng viêm.\n\nRễ: dùng trong một số bài thuốc.\n\nCả cây có thể dùng tươi hoặc ngâm rượu, giã đắp, sắc uống tùy mục đích.',NULL,'Dùng tươi (phổ biến nhất)\n\nLá tươi 1–2 lá/ngày (lá bánh tẻ – không quá non, không quá già).\n\nNhai trực tiếp hoặc ép nước pha loãng.\n\nKhông dùng liên tục quá 30 ngày.\n\nDùng khô\n\n10–15 g/ngày sắc với 500 ml nước còn 200 ml, chia 2 lần.\n\nDùng ngoài da\n\nGiã nát đắp lên vùng viêm, mụn nhọt, sưng tấy.\n\nNgâm rượu (1:3) dùng xoa bóp trị đau khớp.\n\nNgậm nước ép loãng trị viêm họng nhẹ.','Lược vàng có nguồn gốc từ Mexico, sau một thời gian, giống cây này phát triển hơn và di thực tới các vùng đất khác như Tây Ấn Độ, Việt Nam và một số vùng ở Mỹ.\n\nỞ Việt Nam, lược vàng được tìm kiếm và xuất hiện ở những khu vực có khí hậu ẩm ướt, nhiều bóng râm như sườn đồi, vùng núi thấp ở Tây Bắc. Hiện nay, giống cây này được nuôi trồng và thu hái ở nhiều tỉnh thành trên cả nước bởi công dụng mà chúng mang lại. Ngoài ra, chúng còn được sử dụng như cây cảnh trang trí nhà cửa và khuôn viên sân vườn.',_binary '','(1) Giảm đau khớp – viêm khớp\n\n1–2 lá lược vàng nhai mỗi ngày hoặc rượu ngâm lược vàng xoa bóp 2–3 lần/ngày.\n\n(2) Trị viêm họng – ho nhẹ\n\nLấy 1 lá lược vàng rửa sạch, nghiền nát lấy nước cốt.\n\nPha với nước ấm theo tỷ lệ 1:5 rồi ngậm 5–10 phút.\n\n(3) Giảm đau dạ dày nhẹ\n\nNhai 1 lá lược vàng trước bữa ăn 30 phút, ngày 1–2 lần.\n\n(4) Trị mụn nhọt – viêm da\n\nLá tươi giã nát, đắp trực tiếp 15–20 phút, ngày 1–2 lần.\n\n(5) Giảm viêm xoang nhẹ\n\nNước ép lược vàng pha loãng (1:10), nhỏ 1–2 giọt vào mũi, ngày 1 lần.\n→ Không dùng nếu kích ứng mạnh.\n\n(6) Đau rát họng, khản tiếng\n\nLá lược vàng hấp mật ong, ngậm từng ít 2–3 lần/ngày.','',NULL,'Dùng trong các trường hợp:\n\nViêm khớp, đau nhức xương khớp.\n\nĐau rát dạ dày, trào ngược nhẹ, rối loạn tiêu hóa.\n\nHo khan, viêm họng nhẹ.\n\nMụn nhọt, viêm da, dị ứng ngoài da.\n\nSưng tấy, bầm tím, côn trùng cắn.\n\nViêm xoang nhẹ (ngậm nước ép loãng).\n\nHạ đường huyết nhẹ (hỗ trợ, không thay thế thuốc).\n\nGiảm cholesterol nhẹ.','Theo kinh nghiệm dân gian và một số nghiên cứu thực nghiệm, lược vàng có:\nTác dụng chính\n\nKháng viêm – giảm đau (nhờ flavonoid quercetin, kaempferol).\n\nKháng khuẩn – kháng nấm nhẹ.\n\nGiảm ho – tiêu đờm.\n\nTăng cường miễn dịch.\n\nGiảm sưng – tiêu u lành tính (mụn, viêm da, phì đại tuyến giáp nhẹ).\n\nHỗ trợ tiêu hóa, giảm viêm loét dạ dày nhẹ.\n\nGiải độc – thanh nhiệt.\n\nChống oxy hóa, hỗ trợ phòng ngừa tổn thương tế bào.\n\nLưu ý: Lược vàng không phải thuốc điều trị ung thư, chỉ hỗ trợ giảm viêm, giảm stress oxy hóa ở mức độ nhất định.','Cây lược vàng','Địa lan vòi, lan vũ, rai lá phất dũ, giả khóm, lan vòi, cây bạch tuộc…','Thân, lá','DA_XUAT_BAN','Callisia fragrans','Dùng sai cách hoặc liều cao có thể gây:\n\nTác dụng thường gặp\n\nRát họng, kích ứng miệng khi nhai lá tươi.\n\nĐau bụng, tiêu chảy.\n\nNổi mẩn đỏ hoặc ngứa (dị ứng).\n\nTác dụng nặng (dùng kéo dài hoặc liều cao)\n\nGây phù nề thanh quản (đã có trường hợp ghi nhận).\n\nRối loạn tiêu hóa nặng.\n\nẢnh hưởng hoạt động gan – thận.\n\nMất giọng tạm thời (do kích ứng mạnh).\n\nLưu ý an toàn\n\nKhông dùng quá 2 lá tươi/ngày.\n\nKhông dùng liên tục quá 30 ngày.\n\nDừng ngay nếu có khó thở – phù môi – nổi mề đay.','cay-luoc-vang',0,22,'Hoa có màu trắng, dạng dây, mọc thành cụm với 6 – 12 bông nhỏ. Cuống lá chỉ dài 1.5 đến 3mm. Thông thường, cây sẽ ra hoa vào mùa xuân đến mùa thu, phụ thuộc vào khí hậu từng vùng.','','Lá cây lược vàng thuộc lá sáp, lá đơn hoặc mọc so le nhau, phiên có hình ngọn giáo. Lá có kích thước khoảng 12cm đến 20cm – 25cm, chiều rộng khoảng 4cm đến 6cm. Lá có bề mặt nhẵn, thông thường những lá tiếp xúc nhiều với ánh nắng mặt trời sẽ có màu tím, lá trong bóng râm màu xanh mướt. Màu ở mặt dưới sẽ nhạt hơn mặt trên.','','Thân cây phân thành nhiều đốt và nhiều nhánh khác nhau. Mỗi đốt chỉ dài khoảng 1cm đến 2cm. Tuy nhiên có những nhánh thân dài tới 10cm',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765013709/rbco4phmh56swcwyrerl.jpg'),(198,'2025-12-06 09:48:23','1','2025-12-06 09:48:23','1',NULL,'Cây thảo, sống hàng năm hoặc lâu năm.\n\nChiều cao 30–50 cm, phân nhiều nhánh, mọc bò hoặc đứng.\n\nToàn cây có tính mát, hơi nhớt, mùi hăng nhẹ.\n\nThường mọc hoang, dễ tìm ở ven đường, bãi đất ẩm.','Coumestan: wedelolacton – hoạt chất chính chống viêm, giải độc gan.\n\nFlavonoid: luteolin, apigenin, quercetin – kháng viêm, chống oxy hóa.\n\nAlkaloid: nhỏ, hỗ trợ hoạt động sinh lý.\n\nSaponin: kháng khuẩn, lợi mật.\n\nTinh dầu, sterol, polyacetylen: tác dụng hỗ trợ miễn dịch.','Người mẫn cảm hoặc dị ứng với cây cúc (Asteraceae).\n\nNgười suy thận hoặc gan nặng khi chưa có hướng dẫn y tế.\n\nPhụ nữ mang thai và cho con bú nên thận trọng.\n\nNgười huyết áp thấp (do tác dụng lợi tiểu có thể hạ huyết áp).','Dạng cây: Cây thảo, sống hàng năm hoặc lâu năm, cao 30–50 cm.\n\nThân: Nhẵn, mọc bò hoặc đứng, phân nhiều nhánh.\n\nLá: Mọc đối, hình bầu dục hoặc mác, dài 2–5 cm, mép lá nguyên, đầu nhọn.\n\nHoa: Nhỏ, màu trắng hoặc trắng hơi tím, mọc thành đầu hoa nhỏ ở kẽ lá.\n\nQuả: Hình bầu dục, màu nâu đen khi già.\n\nRễ: Sâu, mọc chùm, mảnh.\n\nSinh thái: Cây ưa sáng, phát triển tốt trên đất ẩm, dễ mọc ở ven đường, bãi đất hoang.',NULL,'Dùng uống\n\nLá tươi: 30–60 g/ngày, sắc với 500–800 ml nước còn 200–250 ml, chia 2 lần uống.\n\nLá khô: 10–20 g/ngày, sắc uống tương tự.\n\nDùng ngoài\n\nGiã nát lá tươi, đắp lên vết mụn nhọt, viêm da, vết thương.\n\nNgâm rượu hoặc tinh chất dùng xoa bóp da đầu để hỗ trợ mọc tóc.\n\nChú ý\n\nKhông dùng quá 30 ngày liên tục.\n\nNên dùng cách ngày để cơ thể thích ứng.','Khí hậu: ưa sáng, chịu hạn vừa phải, phát triển tốt ở vùng nhiệt đới và cận nhiệt đới.\n\nĐất: tơi xốp, ẩm, giàu mùn; cũng mọc hoang trên đất nghèo dinh dưỡng.\n\nPhân bố: khắp Việt Nam, châu Á, châu Mỹ nhiệt đới.\n\nMùa sinh trưởng: quanh năm, mạnh nhất vào mùa mưa.\n\nKhả năng sinh trưởng: dễ nhân giống bằng hạt hoặc hom, tái sinh nhanh.\n\nVai trò sinh thái: che phủ đất, chống xói mòn, là cây dược liệu quen thuộc.',_binary '','(1) Giải độc gan – mát gan\n\nLá chó đẻ tươi 30–50 g, rửa sạch, sắc uống 1 thang/ngày.\n\n(2) Trị mụn nhọt – viêm da\n\nGiã nát lá tươi, đắp trực tiếp lên mụn nhọt 1–2 lần/ngày.\n\n(3) Hỗ trợ mọc tóc – giảm rụng tóc\n\nNước sắc hoặc ép lá tươi, gội đầu hoặc xoa bóp da đầu 2–3 lần/tuần.\n\n(4) Lợi tiểu, giảm phù\n\nLá tươi 20–30 g sắc uống, ngày 1–2 lần.\n\n(5) Chảy máu cam\n\nNhai trực tiếp 3–5 lá tươi hoặc sắc uống 1 thang/ngày.','Eclipta',NULL,'Viêm gan, men gan cao.\n\nGan nhiễm mỡ nhẹ, hỗ trợ chức năng gan.\n\nMụn nhọt, chảy máu cam, viêm da nhẹ.\n\nRụng tóc, hói đầu (dân gian dùng ngoài).\n\nPhù thũng nhẹ, giữ nước do nóng trong.\n\nTăng cường sức khỏe tổng thể, chống oxy hóa.','Cây chó đẻ được sử dụng trong y học cổ truyền và một số nghiên cứu hiện đại ghi nhận:\n\nBảo vệ gan, giải độc gan: hỗ trợ viêm gan, men gan cao.\n\nKháng viêm, giảm đau: nhờ flavonoid và wedelolacton.\n\nChống oxy hóa, bảo vệ tế bào gan và cơ thể.\n\nLợi tiểu, giúp thải độc cơ thể.\n\nChữa mụn nhọt, chảy máu cam, các vết thương ngoài da.\n\nHỗ trợ tóc mọc, giảm rụng tóc (dân gian thường dùng nước sắc hoặc tinh chất).\n\nGiải nhiệt, mát gan: dùng trong các trường hợp nóng trong, mụn nhọt.','Cây chó đẻ','Chó đẻ răng cưa  ,Bạch hoa xà thiệt thảo  ,Ngưu tất thảo  ,Tóc tiên thảo','Toàn cây trên mặt đất (thân, lá, hoa).  Thường dùng tươi hoặc phơi khô để làm thuốc.','DA_XUAT_BAN','Eclipta prostrata','Thường gặp (hiếm)\n\nTiêu chảy nhẹ khi uống quá liều.\n\nDị ứng da khi tiếp xúc trực tiếp với lá tươi.\n\nNặng (hiếm, dùng kéo dài liều cao)\n\nRối loạn tiêu hóa, nôn mửa.\n\nHạ huyết áp (do lợi tiểu mạnh).\n\nKích ứng da, ngứa, phát ban.','cay-cho-e',0,18,'Hoa nhỏ, màu trắng hoặc trắng hơi tím.\n\nMọc thành đầu hoa nhỏ ở kẽ lá, xếp thành cụm.\n\nThường nở quanh năm, đặc biệt vào mùa mưa.','Quả dạng achene (quả bế), hình bầu dục, dài khoảng 1–2 mm.\n\nKhi già màu nâu đen.\n\nHạt nhỏ, nhẹ, dễ phát tán nhờ gió hoặc nước.','Mọc đối, hình bầu dục hoặc mác, dài 2–5 cm, rộng 0.5–1.5 cm.\n\nMép lá nguyên, đầu nhọn, cuống ngắn.\n\nMặt trên màu xanh lục đậm, mặt dưới nhạt hơn.','Rễ chùm, mảnh, dài và phát triển mạnh để giữ cây trên đất ẩm.\n\nRễ có thể hấp thu nước tốt, giúp cây sống ở đất ẩm và bãi hoang.','Thân nhẵn, màu xanh lục, hình trụ, có thể mọc bò sát đất hoặc đứng.\n\nPhân nhiều nhánh, mềm, dễ gãy.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765014424/zfolrxs9c7hyqq2bx3hq.jpg'),(199,'2025-12-06 09:59:17','1','2025-12-06 09:59:17','1',NULL,'Cây thảo sống lâu năm, mọc thành bụi, chiều cao khoảng 10–30 cm.\n\nToàn cây có tính mát, vị nhạt, lá non dùng làm thuốc tốt nhất.\n\nThường mọc hoang, thích đất ẩm, ven đường, bãi đất hoang.','Chất nhầy (mucilage): chiếm nhiều trong lá, hỗ trợ tiêu hóa, giảm viêm.\n\nFlavonoid: apigenin, luteolin, quercetin – kháng viêm, chống oxy hóa.\n\nAlkaloid và glycosid: tác dụng lợi tiểu nhẹ.\n\nCác acid hữu cơ: malic, citric, oxalic.\n\nVitamin và khoáng chất: vitamin C, K, khoáng: Ca, Mg, Fe.','Người dị ứng với cây mã đề hoặc họ Plantaginaceae.\n\nNgười suy thận nặng hoặc đang dùng thuốc lợi tiểu mạnh cần thận trọng.\n\nPhụ nữ mang thai và cho con bú nên tham khảo ý kiến thầy thuốc trước khi dùng liều cao.','Dạng cây: Cây thảo, sống lâu năm, cao 10–30 cm.\n\nThân: Thân ngắn, thường không có nhánh rõ rệt, mọc từ gốc thành bụi.\n\nLá: Mọc từ gốc, hình trứng hoặc elip, cuống dài, gân lá rõ rệt, mép nguyên hoặc hơi lượn sóng. Lá non dùng làm thuốc tốt nhất.\n\nHoa: Hoa nhỏ, màu trắng, mọc thành bông dạng trụ ở đầu cành dài, thường nở vào mùa hè.\n\nQuả/Hạt: Quả bế nhỏ, hình trứng, chứa 1 hạt nhỏ.\n\nRễ: Rễ chùm, ngắn, phát triển từ gốc.',NULL,'Dùng uống\n\nLá tươi: 15–30 g/ngày, sắc với 500 ml nước còn 200 ml, chia 2 lần.\n\nLá khô: 10–20 g/ngày, sắc uống tương tự.\n\nDùng ngoài\n\nLá tươi giã nát, đắp trực tiếp lên vết thương, mụn nhọt, viêm da.\n\nNgâm rượu hoặc nấu cao lá dùng xoa bóp vùng sưng đau.','Khí hậu: ưa sáng, chịu hạn vừa phải, phát triển tốt ở vùng ôn đới và nhiệt đới.\n\nĐất: tơi xốp, giàu mùn, ẩm nhưng thoát nước tốt; cũng mọc hoang trên đất cát hoặc ven đường.\n\nPhân bố: khắp Việt Nam, châu Á, châu Âu, Bắc Mỹ.\n\nMùa sinh trưởng: quanh năm, mạnh nhất mùa mưa.\n\nKhả năng sinh trưởng: dễ nhân giống bằng hạt hoặc tách bụi, tái sinh nhanh.\n\nVai trò sinh thái: che phủ đất, chống xói mòn, là cây dược liệu quen thuộc.',_binary '','(1) Trị ho, viêm họng\n\nLá tươi 10–15 g, rửa sạch, sắc uống 1 thang/ngày.\n\nHoặc nhai trực tiếp lá non, ngậm nước ép.\n\n(2) Trị táo bón, lợi tiểu\n\nLá tươi hoặc khô 10–15 g, sắc uống ngày 1–2 lần.\n\n(3) Cầm máu vết thương nhỏ\n\nLá tươi giã nát, đắp trực tiếp lên vết thương.\n\n(4) Trị viêm da, mụn nhọt\n\nGiã lá tươi, đắp 15–20 phút, ngày 1–2 lần.','Plantago',NULL,'Viêm đường tiết niệu nhẹ, tiểu rắt.\n\nHo, viêm họng, đờm nhiều.\n\nTáo bón nhẹ, rối loạn tiêu hóa.\n\nViêm da, mụn nhọt, vết thương nhỏ chảy máu.\n\nPhù thũng nhẹ do nóng trong.','Cây mã đề được sử dụng trong y học cổ truyền và một số nghiên cứu hiện đại:\n\nLợi tiểu, giải độc, mát gan.\n\nChống viêm, giảm sưng, làm lành vết thương.\n\nHỗ trợ tiêu hóa, giảm táo bón (nhờ chất nhầy).\n\nKháng khuẩn nhẹ, trị viêm họng, viêm đường tiết niệu.\n\nChữa ho, long đờm.\n\nGiảm xuất huyết, dùng ngoài cầm máu vết thương nhỏ.','Cây mã đề','Mã đề lá to  ,Mã đề , Xa tiền thảo , Bạch xa tiền','Lá, hạt','DA_XUAT_BAN','Plantago asiatica','Thường gặp (hiếm)\n\nTiêu chảy nhẹ nếu uống quá liều.\n\nDị ứng da khi tiếp xúc trực tiếp với lá tươi (ngứa, mẩn đỏ).\n\nNặng (hiếm)\n\nRối loạn tiêu hóa, buồn nôn.\n\nPhản ứng dị ứng nặng (hiếm, đặc biệt ở người nhạy cảm).','cay-ma-e',0,18,'Hoa nhỏ, màu trắng hoặc hơi xanh nhạt.\n\nMọc thành bông dạng trụ ở đầu cành dài 10–30 cm.\n\nMùa hoa: từ tháng 5–9.','Quả bế nhỏ, hình trứng, chứa 1 hạt.\n\nHạt nhỏ, màu nâu vàng, nhẹ, dễ phát tán theo gió hoặc nước.','Mọc từ gốc, hình trứng hoặc elip, gân nổi rõ.\n\nCuống lá dài 5–15 cm.\n\nMép lá nguyên hoặc hơi lượn sóng.\n\nLá non mềm, dùng làm thuốc tốt nhất.','Rễ chùm, mọc từ gốc, ngắn và khỏe.\n\nGiúp cây bám đất tốt, hấp thu nước và dinh dưỡng hiệu quả.','Thân ngắn, mọc từ gốc, không phân nhánh rõ rệt.\n\nMàu xanh lục, mềm, đôi khi có gân ngang nhẹ.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765015049/iyjdpeb7acbgszyqkvlz.jpg'),(200,'2025-12-06 10:09:00','1','2025-12-06 10:09:00','1',NULL,'Cây thảo sống lâu năm, cao 30–60 cm.\n\nToàn cây có mùi nhẹ, vị rất ngọt do chứa steviol glycoside.\n\nThường trồng làm cây lấy lá để chế biến chất ngọt tự nhiên, phát triển tốt ở vùng nhiệt đới và cận nhiệt đới.','Steviol glycoside (stevioside, rebaudioside A, rebaudioside C) – vị ngọt, 200–300 lần ngọt hơn đường mía.\n\nFlavonoid, tannin – hỗ trợ chống oxy hóa.\n\nTinh dầu, polyphenol – tác dụng hỗ trợ sức khỏe nhẹ.\n\nVitamin và khoáng chất: vitamin C, K, khoáng chất Ca, Mg, Fe.','Người mẫn cảm với cỏ ngọt hoặc họ Cúc (Asteraceae).\n\nTrẻ nhỏ dưới 2 tuổi (không khuyến cáo dùng lâu dài).\n\nNgười bệnh nặng về thận, gan khi dùng liều cao chưa có hướng dẫn y tế.\n\nPhụ nữ mang thai và cho con bú: nên tham khảo ý kiến bác sĩ trước khi dùng.','Dạng cây: Cây thảo, sống lâu năm, cao 30–60 cm.\n\nThân: Nhỏ, mảnh, màu xanh nhạt, mọc thẳng hoặc hơi bò.\n\nLá: Mọc đối, hình bầu dục hoặc elip, dài 2–6 cm, rộng 1–2 cm, mép nguyên, mặt trên xanh đậm, mặt dưới nhạt hơn. Lá chứa nhiều steviol glycoside, rất ngọt.\n\nHoa: Nhỏ, màu trắng hoặc tím nhạt, mọc thành chùm ở ngọn, ra hoa vào mùa hè.\n\nQuả/Hạt: Quả bế nhỏ, hạt hình bầu dục, màu nâu, nhẹ, thường dùng để nhân giống.\n\nRễ: Rễ chùm, phát triển mạnh để hút nước và dinh dưỡng từ đất.',NULL,'Dùng uống / làm thực phẩm\n\nLá tươi hoặc phơi khô: 2–5 g lá/ngày, có thể pha nước uống hoặc dùng chiết xuất steviol glycoside.\n\nDạng bột, chiết xuất: dùng theo hướng dẫn trên bao bì thực phẩm chức năng.\n\nDùng ngoài (hiếm, dân gian)\n\nLá tươi giã nát, đắp nhẹ lên vùng da bị nóng, mẩn ngứa (dân gian).\n\nChú ý\n\nKhông dùng quá liều khuyến cáo của thực phẩm chức năng.\n\nNên thử liều nhỏ trước khi sử dụng lâu dài.','Khí hậu: ưa sáng, nhiệt độ 20–30°C, độ ẩm trung bình.\n\nĐất: tơi xốp, giàu mùn, thoát nước tốt, pH 6–7.\n\nPhân bố: Nguồn gốc Nam Mỹ (Paraguay, Brazil), hiện trồng rộng rãi ở nhiều nước nhiệt đới và cận nhiệt đới, bao gồm Việt Nam.\n\nMùa sinh trưởng: quanh năm, mạnh nhất vào mùa mưa.\n\nKhả năng sinh trưởng: dễ nhân giống bằng hạt hoặc giâm cành, thích nghi tốt với đất trồng giàu mùn.\n\nVai trò sinh thái: làm cây cảnh, lấy lá làm chất ngọt tự nhiên, dễ trồng, ít sâu bệnh.',_binary '','Ngọt tự nhiên thay đường: dùng lá tươi hoặc lá khô pha trà, nấu chè, nướng bánh.\n\nLợi tiểu nhẹ: lá tươi 3–5 lá pha nước uống hàng ngày.\n\nThanh nhiệt, giảm rối loạn tiêu hóa nhẹ: nước sắc lá tươi 5–10 g/ngày.','Stevia',NULL,'Người cần giảm đường trong khẩu phần (tiểu đường, béo phì).\n\nNgười huyết áp cao nhẹ muốn hỗ trợ điều hòa huyết áp.\n\nRối loạn tiêu hóa nhẹ, khó tiêu.\n\nDân gian: dùng lá non pha nước uống để thanh nhiệt, lợi tiểu.','Cỏ ngọt là thảo dược và thực phẩm chức năng nổi tiếng với các tác dụng:\n\nNgọt tự nhiên, thay thế đường: dùng cho người tiểu đường, giảm cân.\n\nHỗ trợ hạ huyết áp: steviol glycoside có thể giúp điều hòa huyết áp nhẹ.\n\nHỗ trợ tiêu hóa: lá non giúp giảm rối loạn tiêu hóa nhẹ.\n\nChống oxy hóa, tăng cường sức khỏe: flavonoid và polyphenol giúp bảo vệ tế bào.\n\nLợi tiểu nhẹ: giúp thải nước, hỗ trợ chức năng thận.\n\nHỗ trợ bệnh huyết áp, bệnh tiểu đường (dân gian và thực phẩm chức năng).','Cây cỏ ngọt','Cỏ ngọt,  Thiên lý tử , Lá ngọt  ,Lá Stevia','lá, toàn thân','DA_XUAT_BAN','Stevia rebaudiana','Thường gặp (hiếm)\n\nDị ứng nhẹ: ngứa, mẩn đỏ khi dùng lá tươi ngoài da.\n\nTiêu chảy nhẹ khi uống quá liều lá tươi.\n\nNặng (hiếm, dùng liều cao)\n\nRối loạn tiêu hóa nặng nếu dùng quá liều chiết xuất.\n\nHiếm ghi nhận tác dụng hạ đường huyết quá mức.\n\nLưu ý\n\nDừng ngay nếu có dấu hiệu dị ứng, đau bụng, tiêu chảy nặng.\n\nTham khảo ý kiến bác sĩ trước khi dùng cho trẻ nhỏ, phụ nữ mang thai, người bệnh nặng.','cay-co-ngot',0,5,'Hoa nhỏ, màu trắng hoặc tím nhạt.\n\nMọc thành chùm ở ngọn, dạng đầu hoa nhỏ.\n\nRa hoa vào mùa hè, ít khi dùng trong y học.','Quả dạng quả bế nhỏ, hình bầu dục, chứa 1 hạt nhỏ.\n\nHạt màu nâu, nhẹ, dùng để nhân giống.','Mọc đối, hình bầu dục hoặc elip, dài 2–6 cm, rộng 1–2 cm, mép nguyên.\n\nMặt trên xanh đậm, mặt dưới nhạt hơn, chứa nhiều steviol glycoside – hợp chất tạo vị ngọt tự nhiên.\n\nLá non dùng làm thuốc hoặc chế biến thực phẩm ngọt tự nhiên tốt nhất.','Rễ chùm, phát triển mạnh, giúp cây hút nước và dinh dưỡng tốt.','Thân nhỏ, mảnh, mọc thẳng hoặc hơi bò.\n\nMàu xanh nhạt, phân nhiều cành nhánh mềm, dễ gãy.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765015726/eyyyszvnyu3doqp44pgr.jpg'),(201,'2025-12-06 10:16:29','1','2025-12-06 10:16:29','1',NULL,'Cây mọng nước, sống lâu năm, thường mọc thành cụm từ gốc.\n\nThích nghi tốt với khí hậu khô, chịu hạn, có khả năng tích trữ nước trong lá.\n\nĐược sử dụng rộng rãi trong y học dân gian, dược mỹ phẩm và thực phẩm chức năng.','Gel lá: nước (90–95%), polysaccharide (acemannan), glycoprotein, enzym, axit amin.\n\nNhựa lô hội (aloes, phần vỏ lá): anthraquinone (aloesin, aloin) – có tác dụng nhuận tràng.\n\nVitamin: A, C, E, B1, B2, B6, B12.\n\nKhoáng chất: Ca, Mg, Zn, Fe, K.\n\nCác hợp chất khác: sterol, acid hữu cơ, flavonoid, tannin – tác dụng chống viêm, chống oxy hóa.','Dị ứng với lô hội hoặc các cây thuộc họ Liliaceae (Aloe).\n\nTrẻ sơ sinh và trẻ nhỏ dưới 2 tuổi (không dùng nhựa lô hội).\n\nNgười tiêu chảy mạn tính hoặc bệnh về đường ruột khi dùng nhựa lô hội.\n\nPhụ nữ mang thai và cho con bú: nhựa lô hội không dùng uống, gel ngoài da thì thận trọng.','Dạng cây: Cây mọng nước, sống lâu năm.\n\nThân: Ngắn, gần như không có thân, mọc thành cụm từ gốc.\n\nLá: Dày, mọng nước, hình mác, nhọn đầu, mép có răng cưa nhỏ. Mặt trên xanh lục, mặt dưới nhạt hơn.\n\nHoa: Cụm hoa hình chuông, màu vàng, cam hoặc đỏ, mọc trên cành hoa dài từ trung tâm.\n\nQuả/Hạt: Quả nang, hình trụ, chứa nhiều hạt nhỏ.\n\nRễ: Rễ chùm, ngắn, ăn sâu, giúp cây hút nước và dinh dưỡng.',NULL,'Dùng ngoài da\n\nGel lô hội tươi: bôi trực tiếp lên vết thương, bỏng, da khô hoặc mụn 2–3 lần/ngày.\n\nDùng uống (dân gian, nhuận tràng)\n\nNhựa lô hội: 10–15 ml/lần, ngày 1–2 lần, không dùng kéo dài quá 1 tuần.\n\nGel tươi pha nước uống hoặc làm sinh tố: 50–100 ml/ngày','Khí hậu: ưa sáng, chịu hạn, phát triển tốt ở vùng khô, bán khô hạn.\n\nĐất: tơi xốp, thoát nước tốt; đất cát, đất pha cát, đất giàu mùn đều phù hợp.\n\nPhân bố: Nguồn gốc Nam Phi, hiện trồng rộng rãi khắp thế giới, đặc biệt ở vùng nhiệt đới và cận nhiệt đới.\n\nMùa sinh trưởng: quanh năm, ra hoa chủ yếu mùa hè.\n\nKhả năng sinh trưởng: dễ trồng bằng lá hoặc hạt, cây ưa nắng, chịu hạn tốt.',_binary '','Trị bỏng nhẹ, vết thương ngoài da: bôi gel tươi trực tiếp lên vết bỏng, vết cắt, vết xước.\n\nDưỡng da và mụn nhọt: gel bôi 15–20 phút, 1–2 lần/ngày.\n\nTáo bón, rối loạn tiêu hóa: nhựa lô hội pha nước uống 1–2 lần/ngày (dân gian, thận trọng).\n\nMặt nạ dưỡng da, chống lão hóa: gel lô hội trộn mật ong hoặc nha đam làm mặt nạ.','',NULL,'Bỏng nhẹ, vết thương, trầy xước ngoài da.\n\nViêm da, mụn nhọt, da khô, nứt nẻ.\n\nTáo bón nhẹ, rối loạn tiêu hóa.\n\nNgười cần bổ sung vitamin, khoáng chất và tăng cường sức đề kháng.','Cây lô hội được sử dụng rộng rãi trong y học cổ truyền và hiện đại:\n\nChữa lành vết thương, bỏng, vết cắt, trầy xước nhờ gel lá có tác dụng làm dịu, kháng viêm.\n\nDưỡng ẩm, làm mềm da, chống lão hóa trong dược mỹ phẩm.\n\nLợi tiêu hóa, nhuận tràng: nhựa lô hội chứa anthraquinone (aloesin, aloin).\n\nKháng khuẩn, kháng viêm: hỗ trợ điều trị mụn, viêm da nhẹ.\n\nHỗ trợ miễn dịch, chống oxy hóa nhờ polysaccharide và vitamin trong gel','Lô hội','Lô hội, Hổ thiệt, Lưỡi hổ, Long tu, Tượng đởm, Lủ hội, Nha đam','thân, bẹ lá, vỏ lá, rễ, hạt','DA_XUAT_BAN','Aloe vera','Thường gặp (hiếm)\n\nKích ứng da: ngứa, đỏ da khi dùng gel ngoài da.\n\nTiêu chảy nhẹ khi uống nhựa lô hội.\n\nNặng (hiếm)\n\nRối loạn điện giải nếu dùng nhựa lô hội kéo dài.\n\nCo thắt bụng, đau bụng nặng.\n\nDị ứng nghiêm trọng (hiếm).','lo-hoi',0,42,'Cụm hoa hình chuông, mọc trên cành hoa dài 50–80 cm từ trung tâm cây.\n\nMàu hoa vàng, cam hoặc đỏ, ra hoa mùa hè.\n\nHoa không phải bộ phận dùng chính trong y học.','Quả nang, hình trụ, chứa nhiều hạt nhỏ.\n\nHạt nhỏ, màu nâu nhạt, dùng để nhân giống khi cần.','Lá mọng nước, hình mác, dài 30–60 cm, rộng 5–10 cm.\n\nMép lá có răng cưa nhỏ, đầu nhọn.\n\nMặt trên xanh lục, mặt dưới nhạt hơn.\n\nPhần thịt lá chứa gel lô hội, trong suốt, giàu nước và hoạt chất sinh học.','Rễ chùm, ngắn, ăn sâu, giúp cây hút nước và chất dinh dưỡng hiệu quả.\n\nKhả năng phát triển tốt trên đất cát, đất tơi xốp, thoát nước tốt.','Thân ngắn, gần như không có thân đứng cao, phần lớn là lá mọc trực tiếp từ gốc.\n\nKhi trưởng thành, cây tạo thành bụi, các lá xếp hình quạt.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765016160/eyoqccfwnnfwrfphjg0n.jpg'),(202,'2025-12-06 10:25:35','1','2025-12-06 10:25:35','1',NULL,'Cây thảo sống lâu năm, thân hành.\n\nThường mọc thành bụi, lá xếp vòng từ gốc.\n\nDùng trong y học cổ truyền và nghiên cứu dược liệu nhờ hoạt chất alcaloid.\n\nThích hợp khí hậu nhiệt đới, ưa sáng và đất tơi xốp.','Alkaloid: crinamin, lycorin, crinasiatin – tác dụng chống u, chống viêm.\n\nSaponin steroid: hỗ trợ chống viêm, tăng cường miễn dịch.\n\nFlavonoid và polyphenol: chống oxy hóa, bảo vệ tế bào.\n\nTinh dầu: lượng nhỏ, hỗ trợ dược tính.','Người mẫn cảm với cây trinh nữ hoàng cung hoặc họ Amaryllidaceae.\n\nPhụ nữ mang thai và cho con bú không dùng liều cao.\n\nNgười bệnh nặng về gan, thận chưa được hướng dẫn y tế.\n\nKhông dùng thay thế phác đồ điều trị ung thư chuẩn.','Dạng cây: Cây thảo sống lâu năm, thân hành.\n\nThân: Hành củ to, màu trắng hoặc trắng hơi hồng.\n\nLá: Mọc vòng từ gốc, hình dải, dài 30–60 cm, rộng 3–6 cm, đầu nhọn, mép nguyên, màu xanh lục bóng.\n\nHoa: Cụm hoa tán, màu trắng, thơm, mọc trên cuống dài từ trung tâm cây.\n\nQuả / Hạt: Quả nang, hình trứng, chứa hạt nhỏ, màu nâu.\n\nRễ: Rễ chùm, ăn sâu, từ củ ra, giúp hút nước và chất dinh dưỡng.\n\nSinh thái: Ưa sáng, đất tơi xốp, giàu mùn; thường mọc hoang hoặc trồng làm cây dược liệu.',NULL,'Dùng uống\n\nLá tươi hoặc phơi khô: 15–30 g/ngày, sắc nước uống 1–2 lần/ngày.\n\nCao lỏng hoặc bột từ lá và củ: theo hướng dẫn trên bao bì hoặc y tế.\n\nDùng ngoài (ít gặp)\n\nLá giã nát, đắp ngoài da để giảm sưng, viêm nhẹ (dân gian).\n\nChú ý\n\nKhông dùng quá 30 ngày liên tục.\n\nDùng dưới sự hướng dẫn của thầy thuốc khi dùng cho bệnh nhân u xơ hoặc ung thư.','Khí hậu: Ưa sáng, nhiệt đới, chịu hạn vừa phải.\n\nĐất: Tơi xốp, giàu mùn, thoát nước tốt.\n\nPhân bố: Chủ yếu ở Việt Nam, Thái Lan, Campuchia; được trồng rộng rãi để làm cây dược liệu.\n\nMùa sinh trưởng: quanh năm, ra hoa mạnh mùa hè.\n\nKhả năng sinh trưởng: dễ trồng bằng củ hoặc hạt; cây ưa nắng và đất giàu mùn.',_binary '','U xơ tử cung, u nang buồng trứng: lá tươi 20–30 g, sắc uống 1 thang/ngày, chia 2 lần.\n\nHỗ trợ sức khỏe tổng quát: lá phơi khô 10–15 g, pha nước uống hàng ngày.\n\nViêm phụ khoa: lá tươi giã nát, rửa nhẹ vùng kín (theo dân gian).','Crinum',NULL,'Hỗ trợ điều trị u xơ tử cung, u nang buồng trứng.\n\nHỗ trợ người bị ung thư (dùng theo hướng dẫn y học cổ truyền hoặc nghiên cứu).\n\nViêm phụ khoa, viêm niêm mạc tử cung.\n\nNgười cần tăng cường sức khỏe, chống oxy hóa.','Cây trinh nữ hoàng cung được sử dụng rộng rãi trong y học cổ truyền và hiện đại:\n\nHỗ trợ điều trị ung thư: nhờ các alkaloid steroid, đặc biệt là crinamin, lycorin.\n\nKháng viêm, chống oxy hóa, bảo vệ tế bào.\n\nTăng cường miễn dịch.\n\nGiảm đau, chống sưng tấy.\n\nHỗ trợ bệnh phụ nữ: viêm phụ khoa, u xơ tử cung (dân gian và y học cổ truyền).','Trinh nữ hoàng cung',' Hoàng cung trinh nữ, Náng lá rộng, Tỏi lơi lá rộng','toàn bộ thân trên mặt đất','DA_XUAT_BAN','Crinum latifolium','Thường gặp (hiếm)\n\nTiêu chảy nhẹ khi dùng quá liều nước sắc từ lá.\n\nBuồn nôn, chóng mặt nhẹ.\n\nNặng (hiếm)\n\nPhản ứng dị ứng: ngứa, phát ban.\n\nKhông dùng liều cao kéo dài có thể ảnh hưởng đến gan, thận.','trinh-nu-hoang-cung',0,40,'Hoa trắng, thơm, mọc thành cụm tán trên cuống dài từ trung tâm cây.\n\nRa hoa vào mùa hè, thường thu hút côn trùng để thụ phấn.','Quả nang, hình trứng, chứa hạt nhỏ màu nâu.\n\nHạt dùng để nhân giống trong nghiên cứu, ít dùng làm thuốc.','Mọc vòng từ gốc, hình dải, dài 30–60 cm, rộng 3–6 cm.\n\nMép nguyên, đầu nhọn, màu xanh lục bóng.\n\nLá dày, cứng, chứa nhiều hợp chất hoạt tính sinh học.','Rễ chùm, phát triển từ củ, ăn sâu để hút nước và chất dinh dưỡng.\n\nRễ khỏe, giúp cây sống được ở đất tơi xốp, thoát nước tốt.','Thân hành to, củ màu trắng hoặc trắng hồng nhạt.\n\nCây phát triển từ hành, thân ngắn, lá mọc trực tiếp từ gốc.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765016675/sc1zbky2eigf9p3duark.jpg'),(204,'2025-12-06 10:47:53','1','2025-12-06 10:47:53','1',NULL,'Cây gỗ nhỏ hoặc cây bụi cao 2–5 m, sống lâu năm.\n\nThường mọc ven suối, bờ rừng, hoặc trồng làm cây thuốc.\n\nDân gian sử dụng chủ yếu vỏ thân và cành để sắc nước uống hỗ trợ bệnh gan.','Flavonoid: hỗ trợ chống oxy hóa, bảo vệ tế bào gan.\n\nSaponin: tác dụng chống viêm, tăng cường miễn dịch.\n\nAlkaloid: có tác dụng hỗ trợ bảo vệ gan, điều hòa enzyme gan.\n\nTinh dầu và polyphenol: hỗ trợ tác dụng dược lý nhẹ.','Người mẫn cảm với cây an xoa hoặc họ Acanthaceae.\n\nTrẻ em nhỏ và phụ nữ mang thai nên thận trọng, dùng dưới sự hướng dẫn y học.\n\nNgười bệnh nặng về thận hoặc đường tiêu hóa khi dùng liều cao chưa được y tế hướng dẫn.\n\nKhông dùng thay thế các phác đồ điều trị gan chuẩn nếu bệnh nặng.','Dạng cây: Cây gỗ nhỏ hoặc cây bụi cao 2–5 m.\n\nThân: Mảnh, phân nhánh, vỏ màu xám hoặc nâu nhạt, dễ bong tróc.\n\nLá: Lá kép 3 lá chét, hình trứng, mép nguyên, màu xanh lục, mặt dưới nhạt hơn.\n\nHoa: Hoa màu đỏ hoặc cam, mọc thành chùm, hình dạng đặc trưng giống hoa đậu.\n\nQuả / Hạt: Quả đậu dài, dẹt, chứa 1–2 hạt, màu nâu.\n\nRễ: Rễ chùm, ăn nông, dễ lấy vỏ thân và cành để làm thuốc.',NULL,'Vỏ thân và cành khô: 20–30 g/ngày, sắc nước uống 1–2 lần/ngày.\n\nDùng tươi: 30–50 g vỏ thân và cành, sắc lấy nước uống hàng ngày.','Khí hậu: ưa sáng, phát triển tốt ở vùng nhiệt đới, chịu hạn vừa phải.\n\nĐất: ưa đất tơi xốp, giàu mùn, thoát nước tốt; thường mọc hoang ven suối, bờ rừng hoặc trồng làm cây thuốc.\n\nPhân bố: Việt Nam, Campuchia, Lào, Thái Lan; được trồng phổ biến để làm thuốc.\n\nMùa sinh trưởng: quanh năm, ra hoa mạnh từ mùa xuân đến hè.\n\nKhả năng sinh trưởng: dễ nhân giống bằng hạt hoặc giâm cành, cây ưa nắng và đất giàu mùn.',_binary '','Hỗ trợ men gan cao, gan nhiễm mỡ: sắc 20–30 g vỏ thân và cành khô với 500 ml nước, còn 200–250 ml, uống 1–2 lần/ngày.\n\nGiải độc gan: sắc nước uống hằng ngày 20–30 g vỏ thân và cành.\n\nHỗ trợ rối loạn tiêu hóa nhẹ: nước sắc từ vỏ thân, uống 1 lần/ngày.','Erythrina',NULL,'Người men gan cao, viêm gan, gan nhiễm mỡ.\n\nNgười muốn bảo vệ gan, hỗ trợ giải độc gan.\n\nRối loạn tiêu hóa nhẹ, khó tiêu (dân gian).\n\nHỗ trợ tăng cường miễn dịch và sức khỏe tổng quát.','Cây an xoa được sử dụng phổ biến trong y học cổ truyền Việt Nam, đặc biệt liên quan đến bệnh gan:\n\nHỗ trợ điều trị men gan cao, viêm gan, gan nhiễm mỡ.\n\nGiải độc gan, tăng cường chức năng gan.\n\nLợi tiểu nhẹ, thông tiểu tiện và thông mật.\n\nChống viêm, kháng oxy hóa giúp bảo vệ tế bào gan.\n\nHỗ trợ cầm máu nhẹ theo dân gian.','cây an xoa','An xoa lá nhỏ,  Cây xoa gan , Cây cười  ,Mã tiền thảo','vỏ cây, cành, lá và rễ','DA_XUAT_BAN','Erythrina variegata','Thường gặp (hiếm)\n\nTiêu chảy nhẹ khi uống nước sắc quá liều.\n\nBuồn nôn, chóng mặt nhẹ.\n\nNặng (hiếm)\n\nPhản ứng dị ứng: nổi mẩn đỏ, ngứa.\n\nSử dụng quá liều trong thời gian dài có thể gây rối loạn tiêu hóa hoặc ảnh hưởng chức năng thận.','cay-an-xoa',0,18,'Hoa màu đỏ hoặc cam, mọc thành chùm, dạng giống hoa đậu.\n\nRa hoa từ mùa xuân đến mùa hè, thu hút ong và bướm để thụ phấn.','Quả dạng đậu dài, dẹt, chứa 1–2 hạt, màu nâu.\n\nHạt dùng để nhân giống, ít khi dùng làm thuốc.','Lá kép 3 lá chét, hình trứng, đầu nhọn, mép nguyên.\n\nMặt trên xanh đậm, mặt dưới nhạt hơn.\n\nLá mọc so le, cuống dài 2–5 cm.','Rễ chùm, ăn nông, từ gốc và thân phát triển, giúp cây hút nước và dinh dưỡng.','Thân mảnh, phân nhánh nhiều, cao 2–5 m.\n\nVỏ màu nâu nhạt hoặc xám, dễ bong tróc.\n\nCành dễ bẻ, dùng để làm thuốc.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765018059/yhvp5dondyppklrnsuul.jpg'),(205,'2025-12-06 10:56:19','1','2025-12-06 10:56:19','1',NULL,'','Saponin triterpenoid: giúp tăng cường sức khỏe, hỗ trợ miễn dịch, chống viêm.\n\nFlavonoid: tác dụng chống oxy hóa, bảo vệ tế bào.\n\nAlkaloid và polysaccharide: giúp tăng sức đề kháng và hỗ trợ chức năng tiêu hóa.\n\nTinh dầu, acid amin, khoáng chất: vitamin và khoáng chất hỗ trợ bồi bổ cơ thể.','Người mẫn cảm với đinh lăng hoặc các cây thuộc họ Araliaceae.\n\nTrẻ nhỏ và phụ nữ mang thai nên thận trọng, dùng dưới sự hướng dẫn y học.\n\nNgười bị bệnh thận nặng hoặc huyết áp thấp khi dùng liều cao.','Dạng cây: Cây gỗ nhỏ hoặc cây bụi cao 1–3 m, sống lâu năm.\n\nThân: Thân nhẵn, phân nhánh nhiều, màu nâu nhạt.\n\nLá: Lá kép lông chim, 2–3 lần chẻ, gồm nhiều lá chét nhỏ hình bầu dục hoặc elip, đầu nhọn, mép nguyên, xanh đậm, mặt dưới nhạt hơn.\n\nHoa: Hoa nhỏ, màu trắng hoặc hơi vàng, mọc thành chùm tán ở ngọn cành.\n\nQuả / Hạt: Quả bế, nhỏ, màu nâu, ít khi dùng làm thuốc.\n\nRễ: Rễ chùm phát triển mạnh, thường được thu hái làm thuốc.',NULL,'Dùng uống\n\nRễ tươi hoặc khô: 15–30 g/ngày, sắc nước uống 1–2 lần/ngày.\n\nRễ giã nát hoặc xay nhuyễn: pha với nước ấm, uống hằng ngày để bồi bổ cơ thể.\n\nDùng ngoài\n\nLá tươi giã đắp lên vết thương nhẹ hoặc mẩn ngứa theo dân gian.\n\nChú ý\n\nUống liên tục 1–2 tháng, sau đó nghỉ 1–2 tuần trước khi tiếp tục nếu cần.\n\nNgười tiêu hóa kém nên giảm liều ban đầu.','Khí hậu: ưa sáng, phát triển tốt ở vùng nhiệt đới ẩm, chịu hạn nhẹ.\n\nĐất: ưa đất tơi xốp, giàu mùn, thoát nước tốt; cây dễ sống ở vườn, bờ rào hoặc trồng làm cảnh.\n\nPhân bố: phổ biến ở Việt Nam, Campuchia, Lào, Thái Lan; được trồng làm cây thuốc và cảnh quan.\n\nMùa sinh trưởng: quanh năm, lá và rễ đều có thể thu hái quanh năm.\n\nKhả năng sinh trưởng: dễ trồng bằng rễ hoặc giâm cành; cây ưa nắng, phát triển nhanh ở đất giàu mùn và thoát nước tốt.',_binary '','Bồi bổ cơ thể sau ốm, sinh đẻ: rễ tươi 20–30 g, sắc uống 1–2 lần/ngày.\n\nHỗ trợ huyết áp, mệt mỏi: rễ phơi khô 15–20 g, sắc nước uống hàng ngày.\n\nLàm nước uống hàng ngày: rễ tươi hoặc khô pha nước uống để nâng cao sức khỏe tổng thể.\n\nĐắp vết thương nhẹ: lá tươi giã nát, đắp lên vùng bị trầy xước hoặc mẩn ngứa.','Polyscias',NULL,'Cây đinh lăng được dùng phổ biến trong y học cổ truyền với các mục đích:\n\nTăng cường sức khỏe, bổ khí huyết, bồi bổ cơ thể sau ốm, sinh đẻ.\n\nHỗ trợ huyết áp nhẹ, giảm mệt mỏi, suy nhược cơ thể.\n\nHỗ trợ tiêu hóa, lợi tiểu nhẹ.\n\nGiảm sưng, cầm máu nhẹ theo dân gian.',' Thuốc bổ, tăng lực, lợi tiểu, bổ thận, lợi sữa, điều kinh, làm co rút tử cung; còn dùng chữa ho, ho ra máu, kiết lỵ (Rễ sắc uống). Lá thương giã đắp chữa vết thương.\n\n ','Đinh Lăng','Đinh lăng lá nhỏ, cây gỏi cá, nam dương lâm.','toàn thân','DA_XUAT_BAN','Tieghemopanax fruticosus','Thường gặp (hiếm)\n\nTiêu chảy nhẹ khi dùng quá liều rễ.\n\nBuồn nôn hoặc chóng mặt nhẹ.\n\nNặng (hiếm)\n\nDị ứng da: ngứa, nổi mẩn đỏ khi tiếp xúc trực tiếp với lá hoặc rễ.','inh-lang',0,18,'Cụm hoa mọc ở ngọn thành hình chùy ngắn mang nhiều tán; lá bắc rộng, sớm rụng; hoa nhỏ, màu lục nhạt hoặc trắng xám; đài 5 răng hầu liền, mép uốn lượn; tràng 5 cánh hình trái xoan; nhị 5, chỉ nhỏ ngắn; bầu hạ, 2 ô.\n','Quả đẹp, hình trứng rộng, màu trắng bạc.\n','Lá to, mọc so le, kép lông chim 2 – 3 tầng, dài 20 – 40cm; lá chét có răng cưa nhọn, đôi khi chia thuỳ, gốc và đầu thuôn nhọn, có mùi thơm khi vò nát; cuống lá dài, phát triển thành bẹ to ở phần cuối.','Rễ chùm, ăn sâu, khỏe, phát triển mạnh từ gốc.\n\nRễ thường được thu hái để làm thuốc, có thể dùng tươi hoặc phơi khô.\n\nRễ chứa nhiều hoạt chất sinh học có tác dụng bổ dưỡng, tăng sức đề kháng, hỗ trợ tiêu hóa và huyết áp.','Cây nhỏ, xanh tốt quanh năm, có thể cao đến 2m. Thân nhẵn, không gai, ít phân nhánh, mang nhiều vết sẹo to, màu xạm.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765018569/fc76egdavjztvrnpnd1l.jpg'),(206,'2025-12-06 11:03:42','1','2025-12-06 11:03:42','1',NULL,'Cây thảo dây sống lâu năm, thân mềm, leo hoặc bám vào cây khác.\n\nDân gian dùng rễ làm thuốc bồi bổ cơ thể, tăng cường sức khỏe.\n\nThích hợp khí hậu nhiệt đới, sinh trưởng tốt ở đất tơi xốp và ẩm.','Saponin triterpenoid: hỗ trợ bồi bổ, tăng sức đề kháng.\n\nAlkaloid, tinh dầu, đường khử: tác dụng hỗ trợ tiêu hóa, tăng cường thể lực.\n\nPolyphenol, flavonoid: chống oxy hóa, bảo vệ tế bào.','Người mẫn cảm với cây sâm bố chính hoặc họ Campanulaceae.\n\nKhông dùng cho trẻ sơ sinh hoặc trẻ nhỏ dưới 2 tuổi.\n\nNgười bệnh nặng về gan, thận hoặc huyết áp cao cần tham khảo ý kiến bác sĩ trước khi dùng.','Sâm bố chính là một loại cây thuộc thảo sống dai, mọc đứng một cách yếu ớt, có khi dựa vào các cây xung quanh, cao chừng 1m hay hơn. Rễ mầm màu trắng nhạt hay vàng nhạt, có đường kính 1,5-2cm, nhiều rễ có hình người trông rất giống nhân sâm, có lẽ vì thế người xưa bắt đầu dùng nhầm rồi thấy tốt mà dùng mãi và lưu truyền về sau chăng?\nLá ở phía gốc cây hình trái xoan, phần cuối phiến lá hình tim hay hình mũi tên, đầu phiến lá không nhọn. Các lá ở phía ngọn càng lên trên càng hẹp, có khi phiến lá chia thuỳ với thuỳ giữa dài hơn, có khi phiến lá chia thuỳ trông như mũi tên. Lá dài 6-7cm, rộng 30mm. Mặt lá có lông đơn hay hình sao, lá kèn hình sợi chỉ dài 7mm có ít lông dài.\nHoa màu hồng hay đỏ, phớt vàng, mọc đơn độc ở kẽ lá, đường kính tới 8cm. Cuống hoa dài 5-8cm, có lông cứng, hơi phồng đầu. Tiểu đài cấu tạo bởi 7-10 bộ phận, dài 12-14mm, có lông tua tủa, đài hoa hình túi, ở ngọn có vài răng nhỏ, đài rách ra và rụng sớm, 5 cánh hoa dài 5-6cm, rộng 3-4cm ở ngọn. Nhiều nhị hàn liền với nhau thành một cột. Bao phấn phủ cột đỏ đến tận gốc. Bầu có lông, 5 vòi, có tuyến.\nQuả hình trứng nhọn, dài gấp 3 lần tiểu đài, ngoài mặt có lông, khi chín, quả nứt thành 5 mảnh vỏ, mặt trong và mặt ngoài đều có lông. Hạt hình thận, màu nâu, ngoài mặt có những đường vân rất sít nhau thành những gợn hay ụ màu vàng .',NULL,'Dùng uống\n\nRễ tươi hoặc khô: 10–30 g/ngày, sắc nước uống 1–2 lần/ngày.\n\nRễ xay nhuyễn: pha với nước ấm uống hàng ngày để bồi bổ cơ thể.\n\nDùng phối hợp\n\nCó thể kết hợp với các cây bổ dưỡng khác như đinh lăng, sâm tố nữ, để tăng hiệu quả bồi bổ.','Khí hậu: ưa sáng, sinh trưởng tốt ở vùng nhiệt đới ẩm, chịu bóng vừa phải.\n\nĐất: đất tơi xốp, giàu mùn, thoát nước tốt; thích hợp trồng trên giàn hoặc leo cây khác.\n\nPhân bố: Việt Nam, Lào, Campuchia, Indonesia; được trồng làm cây thuốc và cây dược liệu quý.\n\nMùa sinh trưởng: quanh năm, ra hoa mạnh vào mùa hè-thu.\n\nKhả năng sinh trưởng: dễ trồng bằng rễ hoặc hạt; cần giàn leo hoặc cây làm giá thể.',_binary '','Bồi bổ cơ thể sau ốm, mệt mỏi: rễ khô 15–30 g, sắc nước uống 1–2 lần/ngày.\n\nPhục hồi sức khỏe sau sinh: rễ sâm bố chính 20 g, phối hợp với đinh lăng, sắc uống hàng ngày.\n\nHỗ trợ tiêu hóa, ăn uống kém: rễ tươi 15–20 g, sắc uống hằng ngày.','',NULL,'Người suy nhược cơ thể, mệt mỏi, ăn uống kém.\n\nNgười cần bồi bổ sức khỏe, tăng sức đề kháng.\n\nHỗ trợ huyết áp nhẹ, tuần hoàn kém.\n\nNgười sau ốm hoặc phụ nữ sau sinh cần hồi phục sức khỏe.','Cây sâm bố chính được sử dụng phổ biến trong y học cổ truyền và dân gian:\n\nBồi bổ cơ thể, tăng cường sức khỏe, chống mệt mỏi.\n\nHỗ trợ tiêu hóa, cải thiện ăn uống kém.\n\nTăng cường hệ miễn dịch, phòng chống suy nhược cơ thể.\n\nHỗ trợ tuần hoàn, điều hòa huyết áp nhẹ.\n\nHỗ trợ người sau ốm, phụ nữ sau sinh phục hồi sức khỏe.','Cây Sâm bố chính','Sâm thổ hào, Sâm báo, Nhân sâm Phú Yên','thân, rễm lá, hoa','DA_XUAT_BAN','Abelmoschus sagittifolius','Thường gặp (hiếm)\n\nTiêu chảy nhẹ khi uống nước sắc quá liều.\n\nBuồn nôn hoặc chóng mặt nhẹ khi dùng liều cao.\n\nNặng (hiếm)\n\nDị ứng: nổi mẩn đỏ, ngứa khi tiếp xúc trực tiếp với rễ hoặc lá.','cay-sam-bo-chinh',0,28,'Hoa nhỏ, hình chuông, màu trắng hoặc hơi vàng nhạt.\n\nMọc đơn lẻ hoặc thành chùm ngắn, mọc ở nách lá.\n\nRa hoa từ mùa hè đến mùa thu.','Quả nang, nhỏ, hình bầu dục.\n\nHạt nhỏ, màu nâu hoặc đen, dùng để nhân giống.','Lá đơn, mọc cách hoặc đối, hình trứng hoặc elip, mép nguyên.\n\nLá màu xanh lục, mặt dưới nhạt hơn, cuống lá ngắn.\n\nLá non mềm, lá già dai hơn, có lông mịn ở gân lá.','Rễ củ chùm, dày, màu nâu nhạt bên ngoài, bên trong trắng, chứa nhiều hoạt chất sinh học.\n\nRễ là bộ phận dùng chính trong y học cổ truyền.','Thân dây mảnh, leo hoặc bám, dài vài mét.\n\nMềm, xanh lục, phân nhánh nhiều.\n\nThường quấn quanh các cây khác hoặc giàn leo.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765018935/jvm1lqdvig36k8pw1hhr.jpg'),(207,'2025-12-06 11:11:45','1','2025-12-06 11:11:45','1',NULL,'','Rễ của Cảm thảo – G. uralensis chứa glucid 4,7-10,97%, tinh bột 4,17-5,92%. Hoạt chất thuộc nhóm sapanosid là glycyrrhizin; thuộc nhóm flavonoid là liquiritin, liquiritigenin, isoliquiritin, isoliquiritigenin, neo-liquiritin, neoisoliquiritin, licurazid. Rễ Cam thảo nhẵn – G. glabra chứa 20-25% tinh bột, 3-10% glucose và saccharose, các cumarin, triterpen và các sterol. Dược liệu chứa các hoạt chất saponosid và flavonoid. Thuộc nhóm saponosid, có hoạt chất ngọt là glycyrrhizin, acid liquiritic..; thuộc nhóm các flavonoid có liquiritin, isoliquiritin, liquiritingenin, isoliquiritigenin, licurasid và các hợp chất oestrogen có nhân sterol.','Người mẫn cảm với cam thảo hoặc họ Fabaceae.\n\nNgười tăng huyết áp, bệnh tim, phù nề, suy tim không nên dùng nhiều.\n\nNgười bệnh thận nặng hoặc đang dùng thuốc lợi tiểu, corticoid cần tham khảo bác sĩ.\n\nTrẻ em dưới 2 tuổi và phụ nữ mang thai nên thận trọng.','Cây thảo sống lâu năm, cao 30-100cm. Rễ dài có màu vàng nhạt. Thân có lông mềm, ngắn.\nLá mọc so le, kép lông chim lẻ, gồm 9-17 lá chét hình trứng có mép nguyên.\nCụm hoa chùm ở nách lá; hoa tương đối nhỏ, màu tím nhạt.\nQuả đậu cong hình lưỡi liềm, dài 3-4cm, rộng 6-8mm, màu nâu đen, có lông dày, chứa 2-8 hạt nhỏ dẹt, màu nâu bóng.\nLoài Cam thảo nhẵn – Glycyrrhiza glabra L. cũng thường được sử dụng.\n\nCây cao 1-1,5m, cũng có rễ dài màu vàng nhạt.\nLá kép lông chim lẻ có lá chét nguyên, hình trái xoan tù.\nHoa nhỏ màu lơ tím sáng, hợp thành chùm dài mọc đứng.\nQuả đậu thuôn, dẹp, thẳng hoặc hơi cong, không lông, nhỏ hơn loài trên và chỉ chứa 2-4 hạt tròn.',NULL,'Dùng uống\n\nRễ khô: 3–9 g/ngày, sắc nước uống 1–2 lần/ngày.\n\nRễ tươi: 15–30 g/ngày, sắc hoặc pha nước uống.','Cây của miền Âu á ôn đới, phân bố chủ yếu ở Nga, Trung Quốc, Mông Cổ, Apganistan, Iran… Ta nhập giống từ Trung Quốc và Nga, đem về trồng thử nghiệm ở Vĩnh Phú (Tam Đảo), Hà Nội, Hải Hưng nhưng chưa phát triển được rộng rãi. Ở nước ta, Cam thảo trồng được 3 năm thì ra hoa, nhưng tỷ lệ kết quả thấp. Đến 5 năm tuổi, cây ra hoa nhiều và kết quả cao hơn. Thường thì mùa hoa tháng 6-7, mùa quả tháng 8-9. Người ta thu hoạch Cam thảo vào khoảng năm thứ năm; thường thu vào mùa đông khi cây tàn lụi. Lúc này rễ chắc, nặng, nhiều bột, có chất lượng tốt. Chải sạch đất bằng bàn chải. Phân loại to, nhỏ và phơi khô. Khi khô được 50%, bó thành bó và sau đó chỉ phơi đầu cắt, không phơi cả rễ, để cho vỏ vẫn giữ được màu nâu đỏ đẹp. Thường dùng dưới dạng Sinh thảo, Chích thảo, bột Cam thảo:',_binary '','Hỗ trợ gan: sắc rễ 5–10 g uống hàng ngày.\n\nGiảm viêm loét dạ dày: phối hợp rễ cam thảo 5 g với cam thảo bắc, bạch truật, sắc uống.\n\nBồi bổ cơ thể: rễ 10–15 g sắc uống hàng ngày.\n\nĐắp vết thương, giảm mụn nhọt: rễ giã nhuyễn hoặc lá tươi đắp trực tiếp.','Glycyrrhiza',NULL,'Hỗ trợ điều trị bệnh gan: men gan cao, viêm gan nhẹ, gan nhiễm mỡ.\n\nHỗ trợ tiêu hóa: viêm loét dạ dày, đau bụng, đi lỏng nhẹ.\n\nBồi bổ cơ thể: suy nhược, mệt mỏi, sau ốm hoặc sau sinh.\n\nTăng cường miễn dịch, chống viêm nhẹ.\n\nHỗ trợ tuần hoàn, huyết áp nhẹ (dân gian, thận trọng).\n\nHỗ trợ cầm máu nhẹ, giảm mụn nhọt, mẩn ngứa theo dân gian.','Chữa ho, ho mất tiếng, viêm họng. Cảm, ỉa chảy, viêm loét dạ dày (Thân rễ sắc uống). Còn dùng trong sản xuất mỹ phẩm, chế nước giải khát, làm mứt kẹo, tẩm thuốc lá.','Cam thảo','Cốt toái bổ, Cam thảo','Rễ và thân','DA_XUAT_BAN','Glycyrrhiza uralensis','Thường gặp (hiếm)\n\nTiêu chảy nhẹ hoặc đầy hơi khi dùng liều cao.\n\nBuồn nôn, chóng mặt nhẹ.\n\nNặng (hiếm)\n\nGiữ nước, phù, tăng huyết áp nếu dùng kéo dài liều cao.\n\nDị ứng da: ngứa, phát ban khi tiếp xúc trực tiếp.','cam-thao',0,1,'Cụm hoa chùm ở nách lá; hoa tương đối nhỏ, màu tím nhạt.\n','Quả đậu cong hình lưỡi liềm, dài 3-4cm, rộng 6-8mm, màu nâu đen, có lông dày, chứa 2-8 hạt nhỏ dẹt, màu nâu bóng.\n','Lá mọc so le, kép lông chim lẻ, gồm 9-17 lá chét hình trứng có mép nguyên.\n','Rễ dài có màu vàng nhạt. Thân có lông mềm, ngắn.\n','Cây thảo sống lâu năm, cao 30-100cm. ',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765019483/jmk9p7liirtaiothaivz.jpg'),(208,'2025-12-07 15:32:01','1','2025-12-07 15:32:01','1',NULL,'Dâm dương hoắc: Tên Latin là Epimedium macranthum Morr. & Decne.\nTên tiếng Hoa: yin yang huo) là cây thân thảo, cao khoảng 0.5 – 0.8m có hoa, cuống dài.\nCây này có nhiều loài khác nhau như Dâm dương hoắc lá to, Dâm dương hoắc lá hình tim, Dâm dương hoắc tá mác, tất cả các loại trên đều được sử dụng trong y học cổ truyền với tác dụng bổ thận tráng dương dành cho nam giới.\nTương truyền rằng khi Dâm dương hoắc được người dân cho dê đực ăn, thì sau đó dê đực có khả năng giao phối với dê cái rất nhiều lần trong ngày, từ đó cây được đặt tên là Dâm dương hoắc.','','Không nên dùng cho:\n\nPhụ nữ đang mang thai hoặc cho con bú.\n\nNgười bị sốt cao, viêm cấp tính.\n\nNgười bị âm hư hỏa vượng (nóng trong, dễ bốc hỏa).\n\nTrẻ em dưới 12 tuổi.\n\nNgười cao huyết áp nặng.','Là cây thân thảo sống lâu năm, cao khoảng 20–40 cm.\n\nThân mảnh, mọc thẳng từ thân rễ ngầm dưới đất.\n\nLá: mọc so le, hình tim hoặc bầu dục, mép có răng cưa nhỏ, mặt trên xanh sẫm, mặt dưới nhạt hơn.\n\nHoa: mọc thành chùm nhỏ ở đầu cành, màu vàng nhạt, trắng ngà hoặc tím hồng, cánh mỏng, mềm.\n\nRễ: là thân rễ bò ngang, màu nâu vàng.\n\nCây thường mọc ở vùng núi cao, khí hậu mát, ưa ẩm và bóng râm.',NULL,'Dạng sắc uống: 6–12g lá khô/ngày, đun với 500ml nước, còn 200ml, chia 2 lần uống.\n\nDạng ngâm rượu: 100g dược liệu khô ngâm với 1 lít rượu 35–40 độ trong 20–30 ngày, uống 1–2 chén nhỏ/ngày.\n\nDạng viên hoàn hoặc trà túi lọc: dùng theo hướng dẫn sản phẩm.','Dâm dương hoắc phân bố chủ yếu ở miền rừng núi và có rất nhiều ở Trung Quốc, đây là cây thích hợp mọc ở vùng có khí hậu ôn đới. Ở Việt Nam, cây này xuất hiện tại các vùng núi cao vùng Tây Bắc, đặc biệt là ở Hòa Bình, Sapa.',_binary '','1. Trị yếu sinh lý\n\nDâm dương hoắc 10g\n\nBa kích 10g\n\nNhục thung dung 10g\n→ Sắc uống mỗi ngày 1 thang.\n\n2. Trị đau lưng mỏi gối\n\nDâm dương hoắc 12g\n\nĐỗ trọng 10g\n\nNgưu tất 10g\n→ Sắc uống 1 lần/ngày.\n\n3. Tăng thể lực, giảm mệt mỏi\n\nDâm dương hoắc 10g\n\nNhân sâm 5g\n→ Hãm như trà uống trong ngày.','Epimedium',NULL,'Dùng trong các trường hợp:\n\nYếu sinh lý nam giới.\n\nĐau lưng, mỏi gối, tay chân lạnh.\n\nSuy nhược cơ thể, mệt mỏi kéo dài.\n\nNgười cao tuổi yếu gân cốt.\n\nPhụ nữ lạnh tử cung, kinh nguyệt không đều (theo YHCT).','Bổ thận, tráng dương, mạnh gân cốt.\n\nHỗ trợ điều trị sinh lý nam yếu, di tinh, mộng tinh.\n\nTăng tuần hoàn máu, giảm đau nhức xương khớp.\n\nTăng sức đề kháng, chống mệt mỏi.\n\nHỗ trợ cải thiện huyết áp thấp.','Dâm dương hoắc','Tiên linh tỳ , Cỏ dê ăn lá  ,Dê ngậm cỏ , Dâm dương hoắc','Lá, thân non.','DA_XUAT_BAN','Epimedium macranthum','Khi dùng quá liều hoặc không đúng cách có thể gây:\n\nChóng mặt, đau đầu.\n\nKhô miệng, háo nước.\n\nTim đập nhanh.\n\nMất ngủ.\n\nNóng trong người, táo bón.','dam-duong-hoac',0,27,'','','Cây này có nhiều loài khác nhau như Dâm dương hoắc lá to, Dâm dương hoắc lá hình tim, Dâm dương hoắc tá mác, tất cả các loại trên đều được sử dụng trong y học cổ truyền với tác dụng bổ thận tráng dương dành cho nam giới.','','Tên tiếng Hoa: yin yang huo) là cây thân thảo, cao khoảng 0.5 – 0.8m có hoa, cuống dài.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765121507/tjfcv5cjut7dj98ncqzt.jpg'),(209,'2025-12-07 15:38:09','1','2025-12-07 15:38:09','1',NULL,'Ba kích có tên khoa học: Morinda officinalis How; tên khác ba kích, Ruột gà, Thao tày cáy (Mán), Ba kích thiên, Sáy cáy (Thái), Chầu phóng sì (Tày), Chổi hoàng kim, Chày kiằng đòi (Dao). Đây là cây thảo, sống lâu năm, leo bằng thân quấn, thân non mầu tím, có lông, phía sau nhẵn, cành non, có cạnh, lá mọc đối, hình mác hoặc bầu dục, thuôn nhọn, cứng.','','Kiêng kị: đối với bệnh nhân âm hư hỏa vượng, đại tiện táo kết không nên dùng.\n\n','Là dây leo thân gỗ nhỏ, sống nhiều năm, thường mọc dựa vào cây khác hoặc giàn leo.\n\nThân: tròn, màu nâu xám, có nhiều đốt.\n\nLá: mọc đối, hình bầu dục hoặc hình mác, đầu nhọn, mặt trên xanh đậm, mặt dưới nhạt hơn.\n\nHoa: nhỏ, mọc thành cụm, màu trắng ngà hoặc vàng nhạt.\n\nQuả: hình cầu nhỏ, khi chín có màu đỏ.\n\nRễ: phát triển thành củ dài, cong queo, vỏ ngoài màu nâu tím, ruột màu tím nhạt hoặc vàng nhạt (tùy loại ba kích tím hay trắng).\n\nCây thường mọc ở vùng núi, trung du, ưa đất ẩm, tơi xốp, thường được trồng nhiều ở Quảng Ninh, Quảng Nam, Nghệ An.',NULL,'Ngày 8-16g dưới dạng thuốc sắc hay rượu thuốc. Phối hợp trong các phương thuốc bổ thận.\n\n','Chi Morinda L. có vài chục loài trên thế giới gồm phân lớn là là những cây bụi, gỗ nhỏ hoặc dây leo, phân bố chủ yếu ở vùng nhiệt đới. Ở Việt Nam hiện đã biết khoảng gần chục loài. Trong số 3 -4 loài dây leo, ba kích là một cây thuốc quan trọng. Ba kích mới chỉ thấy phân bố ở một số tỉnh trung du và miền núi Hòa Bình và Hà Tây. Một vài địa phương khác cũng đã phát hiện thấy cây Ba kích nhưng không đáng kể. Cây còn phân bố ở tỉnh Quảng Tây, Vân Nam…của Trung Quốc.\nBa kích là cây ưa ẩm, ưa sáng và hơi chịu bóng khi còn non. Trong tự nhiên thường thấy Ba kích trong các kiểu rừng thứ sinh hoặc rừng xen tre nứa (ít). Độ cao phân bố phổ biến thường dưới 300m, trên các loại đất feralit đỏ vàng hay đỏ và hơi chua. Đó cũng là một trong các lí do giải thích tại sao trồng Ba kích ở vùng đồng bằng thấy khó khăn. Cây sinh trưởng mạnh vào mùa hè, ra hoa quả trong vụ hè thu, đến mùa đông nếu gặp sương muối nhiều, cây bị rụng lá. Trong điều kiện trồng trọt, cây có giá thể leo và được chiếu sáng đầy đủ sẽ ra hoa nhiều nhưng lượng kết quả thấp. Cây Ba kích tự nhiên thường có ít hoa quả hơn cây trồng. Ba kích có khả năng tái sinh cây chồi tốt, sau khi bị chặt phá quá nhiều lần. Ngoài ra bằng cách giâm cành và thân rễ cũng tạo được những cây con.\nBa kích là một cây thuốc quý, vừa có giá trị sử dụng trong nước, vừa được xuất khẩu. Trước năm 1975, mỗi năm có thể thu mua được vài chục tấn. Việc khai thác quá mức và rừng thường xuyên bị tàn phá đã làm cho cây thuốc này trở nên hiếm. Tuy nhiên, Ba kích bước đầu đã được đưa vào trồng xen trong các mô hình vườn – trang trại ở trung du có kết qủa.',_binary '','1. Trị liệt dương, ngũ lao, thất thương, ăn nhiều, hạ khí:\n\nBa kích thiên, Ngưu tất (sống)  đều 3 cân ngâm với 5 đấu rượu, uống (Thiên Kim Phương).\n\n2. Trị phụ nữ tử cung bị lạnh, kinh nguyệt không đều, xích bạch đới hạ:\n\nBa kích 120g, Lương khương 20g, Tử kim đằng 640g, Thanh diêm 80g, Nhục quế (bỏ vỏ)160g, Ngô thù du 160g. Tán bột. Dùng rượu hồ làm hoàn. Ngày uống 20 hoàn với rượu pha muối nhạt (Ba Kích Hoàn – Cục Phương).\n\n3. Trị lưng đau do phong hàn, đi đứng khó khăn:\n\nBa kích 60g, Ngưu tất 120g, Khương hoạt 60g, Quế tâm 60g, Ngũ gia bì 60g, Đỗ trọng (bỏ vỏ, sao hơi vàng) 80g, Can khương (bào) 60g. Tán bột, trộn mật làm hoàn, uống với rượu ấm (Ba Kích Hoàn – Thánh Huệ Phương).\n\n4. Trị tiểu nhiều:\n\nÍch trí nhân, Ba kích thiên (bỏ lõi), 2 vị chưng với rượu và muối, Tang phiêu tiêu, Thỏ ty tử (chưng  với rượu). Lượng bằng nhau. Tán bột. Dùng rượu chưng hồ làm hoàn to bằng hạt ngô đồng lớn, mỗi lần uống 12 viên với rượu pha muối hoặc sắc thành thang uống với muối ( Kỳ Hiệu Lương Phương)','Morinda',NULL,'Kiêng kị: đối với bệnh nhân âm hư hỏa vượng, đại tiện táo kết không nên dùng.\n\n','Trong nhân dân, ba kích được dùng phổ biến làm thuốc bổ tăng lực. Qua điều trị thử nghiệm đạt kết quả:\n\nĐối với những bệnh nhân nam có hoạt động sinh dục không bình thường, Ba Kích có tác dụng làm tăng khả năng giao hợp, đặc biệt đối với những trường hợp giao hợp yếu và thưa. Ba Kích có tác dụng tăng cường sức dẻo dai, mặc dầu nó không làm tăng đòi hỏi tình dục, không thấy có tác dụng kiểu Androgen. Tuy không làm thay đổi tinh dịch đồ nhưng trên thực tế có tác dụng hỗ trợ và cải thiện hoạt động sinh dục cũng như điều trị vô sinh cho những nam giới có trạng thái vô sinh tương đối và suy nhược thể lực. Còn các trường hợp tinh dịch ít, tinh trùng chết nhiều, không có tinh trùng, không xuất tinh khi giao hợp thì xử dụng Ba Kích chưa thấy kết quả (Tài Nguyên Cây Thuốc Việt Nam).\nĐối với cơ thể những người tuổi già, những bệnh nhân không biểu hiện mệt mỏi, ăn kém, ngủ ít, gầy yếu mà không thấy có những yếu tố bệnh lý gây nên và 1 số trường hợp có đau mỏi các khớp, Ba Kích có tác dụng tăng lực rõ rệt, thể hiện qua những cảmgiác chủ quan như đỡ mệt mỏi, ăn ngon, ngủ ngon và những dấu hiệu khách quan như tăng cân nặng, tăng cơ lực. Còn đối với bệnh nhân đau mỏi các khớp thì sau khi dùng Ba Kích dài ngày, các triệu chứng đau mỏi giảm rõ rệt (Tài Nguyên Cây Thuốc Việt Nam).\nTheo tài liệu cổ, ba kích chữa dương ủy di tinh, phong thấp cước khí, gân cốt yếu mềm, lưng gối mỏi đau. Là một vị thuốc bổ trí não và tinh khí, di mộng tinh, phụ nữ kinh nguyệt không đều, bệnh phong thấp.','Ba kích','Ba kích, Ruột gà, Thao tày cáy (Mán), Ba kích thiên, Sáy cáy (Thái), Chầu phóng sì (Tày), Chổi hoàng kim, Chày kiằng đòi (Dao)','Rễ','DA_XUAT_BAN','Morinda officinalis','hầu như không','ba-kich',0,18,'Cụm hoa mọc thành tán ở đầu, hoa nhỏ, lúc non mầu trắng, sau hơi vàng, tập trung thành tán ở đầu cành, dài 0,3-1,5cm, đài hoa hình chén hoặc hình ống gồm những lá đài nhỏ phát triển không đều. Tràng hoa dính liền ở phía dưới thành ống ngắn.','Quả hình cầu, khi chín mầu đỏ, mang đài còn lại ở đỉnh.','Lá mọc đối, hình mác hoặc bầu dục, thuôn nhọn, cứng, dài 6-14cm, rộng 2,5-6cm, lúc non mầu xanh lục, khi già mầu trắng mốc. Lá kèm mỏng ôm sát thân.','','Cây thảo, sống lâu năm, leo bằng thân quấn. Thân non mầu tím, có lông, phía sau nhẵn. Cành non, có cạnh',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765121880/yvtqysuqxhuqbgdmnniq.jpg'),(210,'2025-12-07 15:54:23','1','2025-12-07 15:54:23','1',NULL,'Là cây thân thảo sống nhiều năm, phát triển chậm.\n\nTuổi thọ có thể từ 5–7 năm hoặc lâu hơn mới thu hoạch rễ.\n\nƯa khí hậu mát lạnh, ẩm mát, ánh sáng tán xạ.','Các hoạt chất chính gồm:\n\nSaponin triterpen (Ginsenosides) – thành phần quan trọng nhất.\n\nPolyacetylen.\n\nPolysaccharide.\n\nAcid amin.\n\nTinh dầu.\n\nVitamin nhóm B.','Người sốt cao, viêm nhiễm cấp tính.\n\nNgười bị tăng huyết áp nặng, tim đập nhanh, mất ngủ nghiêm trọng.\n\nPhụ nữ có thai hoặc đang cho con bú (cần hỏi ý kiến bác sĩ).\n\nTrẻ em dưới 12 tuổi không tự ý sử dụng.','Cây nhân sâm là một cây sống lâu năm, cao chừng 0,6m. Rễ mọc thành củ to.\n\nLá mọc vòng, có cuống dài, lá kép gồm nhiều lá chét mọc thành hình chân vịt. Nếu cây mới được một năm (nghĩa là sau khi gieo được 2 năm) thì cây chỉ có 1 lá với 3 lá chét, nếu cây nhân sâm được 2 năm cũng chỉ có 1 lá với 5 lá chét. Cây nhân sâm 3 năm có 2 lá kép, cây nhân sâm 4 năm có 3 lá kép, cây nhân sâm 5 năm trở lên có 4 đến 5 lá kép, tất cả đều có 5 lá chét (đặc biệt có thể có 6 lá chét) hình trứng, mép lá chét có răng cưa sâu. Bắt đầu từ năm thứ ba trở đi, cây nhân sâm mới cho hoa, kết quả.\n\nHoa xuất hiện vào mùa hạ. Cụm hoa hình tán mọc ở đầu cành, hoa màu xanh nhạt, 5 cánh hoa, 5 nhị, bầu hạ 2 núm.\n\nQuả mọng hơi dẹt to bằng hạt đậu xanh, khi chín có màu đỏ, trong chứa 2 hạt. Hạt cây sâm năm thứ 3 chưa tốt. Thường người ta bấm bỏ đi đợi cây được 4-5 năm mới để ra quả và lấy hạt làm giống.\n\nMùa hoa: tháng 3-5; mùa quả tháng 6-8',NULL,'Sắc nước uống: 2–6g rễ/ngày, đun với 300–500ml nước, uống trong ngày.\n\nHãm trà: 1–3g thái lát, hãm với nước nóng 10–15 phút.\n\nNgâm rượu: 1–2 củ nhân sâm với 1–2 lít rượu 35–40 độ, uống 10–20ml/lần.\n\nViên, cao sâm: theo hướng dẫn nhà sản xuất.','Mọc hoặc được trồng ở vùng núi cao, khí hậu ôn đới, mát mẻ.\n\nƯa đất tơi xốp, giàu mùn, thoát nước tốt, hơi chua.\n\nThích hợp với môi trường bóng râm, ánh sáng tán xạ, không chịu nắng gắt.\n\nNhân sâm thường phân bố ở Hàn Quốc, Trung Quốc, Triều Tiên và vùng núi Đông Bắc Á.',_binary '','Bồi bổ cơ thể và tăng sức đề kháng\n\nNhân sâm 5g + táo đỏ 3–5 quả → hãm trà uống hằng ngày.\n\n2. Trị suy nhược thần kinh, mất ngủ\n\nNhân sâm 3g + long nhãn 10g → sắc uống 1 lần/ngày.\n\n3. Hỗ trợ hồi phục sau ốm hoặc phẫu thuật\n\nNhân sâm 5g + gà ác 1 con → hầm canh ăn 2–3 lần/tuần.','Panax',NULL,'Suy nhược cơ thể, mệt mỏi kéo dài.\n\nMất ngủ, căng thẳng thần kinh, giảm trí nhớ.\n\nNgười già, người mới ốm dậy, hồi phục sau phẫu thuật.\n\nNgười cần bồi bổ sinh lực và tăng cường sức đề kháng.','Bồi bổ cơ thể: tăng cường sức khỏe, giảm mệt mỏi.\n\nTăng sức đề kháng: cải thiện hệ miễn dịch.\n\nCải thiện tuần hoàn máu: giảm căng thẳng, hỗ trợ tim mạch nhẹ.\n\nTăng trí lực, hỗ trợ thần kinh: giảm stress, cải thiện trí nhớ.\n\nỔn định đường huyết và huyết áp ở mức nhẹ.','Nhân sâm',' Nhân sâm, Viên sâm, Dã nhân sâm, Sâm cao ly, Sâm triều tiên','rễ','DA_XUAT_BAN','Panax ginseng','Mất ngủ, khó ngủ nếu dùng quá liều.\n\nChóng mặt, đau đầu, tim đập nhanh.\n\nTăng huyết áp nhẹ hoặc khô miệng.\n\nTiêu chảy nhẹ nếu dùng liên tục quá liều.','nhan-sam',0,18,'Hoa nhỏ, màu trắng ngà hoặc xanh nhạt.\n\nMọc thành tán đơn (hình cầu) ở đỉnh thân.\n\nHoa nở vào khoảng tháng 5 – 7.','Quả mọng, hình cầu dẹt, khi chín có màu đỏ tươi.\n\nMỗi quả chứa 1–2 hạt cứng, hình thận.\n\nQuả chín vào khoảng tháng 7 – 9.','Lá kép hình chân vịt, mỗi lá thường gồm 3–5 lá chét.\n\nLá chét hình bầu dục, đầu nhọn, mép có răng cưa nhỏ.\n\nMặt trên xanh sẫm, mặt dưới nhạt hơn.','Rễ phình to thành củ chính, phân nhánh giống hình người.\n\nVỏ ngoài màu vàng nhạt, có nhiều nếp nhăn ngang.\n\nBên trong màu trắng ngà, mùi thơm nhẹ, vị hơi đắng – ngọt.','Thân mảnh, mềm, mọc thẳng từ thân rễ.\n\nMàu xanh lục, nhẵn, cao khoảng 30–60 cm.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765122842/cq57ecadsavarhmcnunk.jpg'),(211,'2025-12-07 16:02:35','1','2025-12-07 16:02:35','1',NULL,'Bột củ Tam thất có màu vàng nhạt, mùi đặc trưng, vị đắng sau ngọt.','Các chất chính có trong Tam thất gồm:\n\nSaponin triterpenoid (notoginsenosides / ginsenosides R1, Rb1, Rg1…) – thành phần dược lý quan trọng.\n\nPolysaccharides.\n\nAcid amin và vitamin nhóm B.\n\nTinh dầu và các hợp chất hữu cơ khác.\n\nCác thành phần này góp phần cầm máu, chống viêm, chống oxy hóa, bảo vệ tim mạch.','Người sốt cao, viêm cấp tính.\n\nNgười mẫn cảm với Tam thất hoặc các sản phẩm nhân sâm.\n\nPhụ nữ mang thai hoặc đang cho con bú nên hỏi ý kiến bác sĩ trước khi dùng.\n\nTrẻ em dưới 12 tuổi dùng cần thận trọng.','Tam Thất có tên khoa học: Panax pseudo-ginseng Wall, thuộc họ ngũ gia bì (Araliaceae)\n\nTam thất là cây thuốc quý có rất nhiều tầm quan trọng như là một chất bổ. Tam thất là loại cây thảo, sống nhiều năm.\nThân mọc thẳng, cao 30 – 50cm, màu tím tía.\nLá kép chân vịt, 3 – 4 cái mọc vòng gồm 5-7 lá chét hình mác, gốc thuôn, đầu có mũi nhọn, mép khía răng, hai mặt có lông cứng ở gân, mặt trên thẫm, mặt dưới nhạt.\nCụm hoa mọc thành tán đơn ở ngọn thân; hoa màu lục vàng nhạt, đài 5 răng ngắn; tràng 5 cánh rộng ở phía dưới, nhị 5; bầu 2 ô.\nQuả mọng, hình cầu dẹt, khi chín màu đỏ; hạt màu trắng.\nMùa hoa: tháng 5-7, mùa quả: tháng 8 – 10. Rễ củ hình con quay',NULL,'Sắc nước uống: 3–9g rễ/ngày, đun với 200–500ml nước, chia 2–3 lần uống.\n\nDạng bột: 1–3g/ngày, pha nước uống.\n\nNgâm rượu: 50–100g rễ khô/ngâm với 1 lít rượu 35–40 độ, uống 10–20ml/lần.\n\nViên hoàn hoặc cao: theo hướng dẫn sản phẩm.','Tam thất là cây ưa khí hậu mát, ẩm, thường mọc hoặc được trồng ở vùng núi cao, đất tơi xốp, giàu mùn.\n\nKhông chịu nắng gắt trực tiếp, thường trồng dưới bóng cây rừng hoặc lưới che.\n\nCây sống lâu năm, 4–7 năm mới đạt kích thước thu hoạch rễ tối ưu.\n\nPhân bố chủ yếu ở tây nam Trung Quốc, đặc biệt là Vân Nam, Quý Châu, Tứ Xuyên.',_binary '','Cầm máu, giảm đau vết thương\n\nTam thất bột 3g + mật ong 5ml → uống trực tiếp hoặc hòa nước ấm.\n\n2. Hỗ trợ tuần hoàn máu\n\nTam thất 5g + táo đỏ 3–5 quả → hãm trà uống ngày 1 lần.\n\n3. Bồi bổ sức khỏe, giảm mệt mỏi\n\nTam thất 3–5g + nhân sâm 2–3g → sắc uống 1 lần/ngày.','Panax',NULL,'Dùng trong các trường hợp:\n\nChảy máu nhẹ, vết thương nhỏ, chảy máu cam, rong kinh.\n\nNgười suy nhược cơ thể, mệt mỏi kéo dài.\n\nNgười tuần hoàn kém, đau đầu, chóng mặt do thiếu máu.\n\nNgười cao tuổi cần bồi bổ sức khỏe và phòng bệnh tim mạch.','Cầm máu: hiệu quả với chảy máu nhẹ, vết thương, rong kinh.\n\nBồi bổ cơ thể: tăng cường sức khỏe, giảm mệt mỏi.\n\nHỗ trợ tim mạch: cải thiện tuần hoàn máu, giảm nguy cơ xơ vữa động mạch.\n\nChống viêm và giảm đau: giảm sưng, đau nhức nhẹ.\n\nỔn định huyết áp: hỗ trợ huyết áp cao và thấp ở mức nhẹ.\n\nChống oxy hóa: bảo vệ cơ thể khỏi các gốc tự do, lão hóa.','Cây Tam thất','Sâm tam thất,  Tam thất bắc  ,Nhân sâm tam thất','rễ','DA_XUAT_BAN','Panax pseudo-ginseng','Khi dùng quá liều có thể gây:\n\nBuồn nôn, khó tiêu, tiêu chảy nhẹ.\n\nChóng mặt, nhức đầu.\n\nTim đập nhanh hoặc huyết áp thay đổi nhẹ.\n\nSử dụng đúng liều và theo hướng dẫn thường an toàn, ít tác dụng phụ.','cay-tam-that',0,30,'Cụm hoa mọc thành tán đơn ở ngọn thân; hoa màu lục vàng nhạt, đài 5 răng ngắn; tràng 5 cánh rộng ở phía dưới, nhị 5; bầu 2 ô.','Quả mọng, hình cầu dẹt, khi chín màu đỏ; hạt màu trắng.','Lá kép chân vịt, 3 – 4 cái mọc vòng gồm 5-7 lá chét hình mác, gốc thuôn, đầu có mũi nhọn, mép khía răng, hai mặt có lông cứng ở gân, mặt trên thẫm, mặt dưới nhạt.','Rễ củ là bộ phận chính dùng làm dược liệu.\n\nHình thẳng, củ hơi cong, nhỏ dài, có màu vàng nhạt hoặc vàng nâu, bề mặt nhẵn hoặc có vết sẹo.\n\nRễ chứa nhiều dược chất quan trọng, dùng trong Đông y để bồi bổ, cầm máu, giảm đau.','Thân mọc thẳng, cao 30 – 50cm, màu tím tía.',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765123336/o6rr8dw8gaav0bixhurp.jpg'),(212,'2025-12-07 16:07:41','1','2025-12-07 16:07:41','1',NULL,'','Mặc dầu mới được đưa vào sử dụng rộng rãi ở Trung Quốc vào 20 năm gần đây, nhưng nhiều viện nghiên cứu thuộc các tỉnh khác nhau ở Trung Quốc đã nghiên cứu nhưng cũng chưa tìm được hoạt chất. Chúng tôi kê sau đây kết quả nghiên cứu của một số cơ sở:\nViện nghiên cứu tỉnh Quảng Đông nghiên cứu thành phần hoá học của nấm linh chi mọc hoang dại thấy: Nước 12-13%, lignin 13-14%, hợp chất có N 1,6-2,1 %, hợp chất phenol 0,08-0,1%, tro 0,022%, xelluloza 54-56%, chất béo 1,9-2%, chất khử 4-5%, hợp chất steroit 0,14-0,16%. Có tài liệu cho biết trong nấm linh chi có 0,3-0,4 % ergosterol (C28H44O).\nViện nghiên cứu kháng sinh Tứ Xuyên tìm thấy axit amin, protein, saponin, steroit.\nHọc viện y học Bắc Kinh phát hiện đường khử và đường kép axit amin, dầu béo.\nTheo những công trình nghiên cứu mới nhất của Viện nghiên cứu linh chi hoang dại của toàn Trung Quốc thì trong hỗn hợp 6 loại linh chi có hàm lượng germanium cao hơn lượng germanium có trong nhân sâm từ 5 đến 8 lần. Germanium giúp khí huyết lưu thông, các tế bào hấp thu oxy tốt hơn. Lượng polysacarit cao có trong linh chi tăng cường sự miễn dịch của cơ thể, làm mạnh gan, cô lập và diệt các tế bào ung thư. Axit ganoderic có tác dụng chống dị ứng và chống viêm.','','Nấm linh chi không phải một loại cỏ, mà là một loại nấm hoá gỗ có cuống dài hoặc ngắn, mũ nấm có dạng hình thận, có dạng hình tròn hay hình quạt. Cuống thường cắm không ở giữa mũ nấm mà cắm lệch sang một phía mũ. Hình trụ tròn hay dẹt có thể phân nhánh cuống và cuống có màu khác nhau tuỳ theo loài, loài đỏ thay đổi từ nâu đến đỏ vàng, đỏ cam, mặt trên bóng loáng như đánh vécni, trên mặt mũ có những vân đồng tâm.\nThụ tầng màu trắng ngà, khi già ngả màu nâu vàng, mang nhiều lỗ nhỏ li ti là các ống thụ tầng mang bào tử. Bào tử loài xích chi hình trứng, được bao bọc bởi 2 lớp màng, màng ngoài nhẵn, không màu, màng trong màu gỉ sắt, lỗ nẩy mầm có hình gai nhọn.\nToàn nấm gồm những sợi nấm không mầu, trong sáng, đường kính 1-3mm, có phân nhánh.',NULL,'6~12g\n\n','Linh chi thường thấy mọc hoang dại ở các vùng núi cao lạnh ở một số tỉnh của Trung Quốc (Tứ xuyên, Quảng Đông, Quảng Tây…)\n\nGần đây, trên cơ sở những giống cây hoang dại người ta đã tổ chức trồng theo qui mô công nghiệp để đáp ứng nhu cầu dùng trong nước và xuất khẩu. Ngoài Trung Quốc, Nhật Bản cũng đã tiến hành trồng nhưng khí hậu không thuận tiện như Trung Quốc.\n\nỞ nước ta, một số cơ sở đã bắt đầu trồng nấm linh chi để dùng trong nước và xuất khẩu.\nNgười ta thu hoạch nấm, phơi sấy khô rồi sử dụng bào chế các dạng bột, thuốc nước ngọt hay đông khô…',_binary '','Bài thuốc có vị Nấm linh chi\n\nTrị mất ngủ hay quên: Linh chi tán bột mịn, ngày uống 2 lần, mỗi lần uống 3g chiêu với nước ấm.\nTrị phế hư hen suyễn: Linh chi và nhân sâm lượng hai thứ bằng nhau, tán bột mịn trộn đều, ngày uống 2 lần, mỗi lần uống 3g, chiêu với nước còn ấm.\nViêm gan đã hồi phục: Linh chi 10g, vịt 1 con. Thịt vịt, lòng tạng, rửa sạch, cho chung với linh chi hầm nhừ bằng lửa nhỏ, chia ra ăn thịt vịt, uống nước hết trong ngày.','',NULL,'','Tác dụng của nấm linh chi đối với hệ tuần hoàn:\n\nỔn định huyết áp\nLọc sạch máu, tăng cường tuần hoàn máu, giảm mệt mỏi, hỗ trợ thần kinh.\nChống đau đầu và tứ chi.\nĐiều hòa kinh nguyệt.\nLàm da dẻ hồng hào, chống các bệnh ngoài da như dị ứng, trứng cá.','Linh chi','Vạn niên nhung,Xích chi ,Hồng chi','toàn thân','DA_XUAT_BAN','Ganoderma lucidum','','linh-chi',0,34,'','','','','',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765123641/muh3j3ddfoxyifcdttcm.jpg'),(213,'2025-12-07 16:12:38','1','2025-12-07 16:12:38','1',NULL,'Loài nấm nhỏ, có thân hình trụ, mảnh, dài 3 – 6 cm, có thể đến 10 – 11 cm, đặc khi còn non sau trở nên rỗng giữa. Phần dưới thân nấm to, thuôn dần về phía ngọn, kết thúc bằng một phần rộng loe thành hình thoi, đầu nhọn, đường kính 2,5 – 6 mm, phần này có vẻ ngoài sần sùi, lấm tấm những hạt nhỏ mà khi soi kính hiển vi đó là tử nang xác (bộ phận sinh sản).\n\nTử nang xác hình trứng hay hơi tròn, trong chứa các nang hình sợi, có cuống ngắn. Trong nang có nhiều bào tử ngăn vách riêng biệt.','Trong đông trùng hạ thảo nhập ở Trung Quốc người ta đã lấy được chừng 1% một loại axit đặc biệt gọi là axit cocdixepic 3-4-5 tetraoxyhexahydrobenzoic, có cấu tạo tương tự như axit quinic. Nhưng các chất khác và hoạt chất chưa được biết.\nĐông trùng hạ thảo chứa 25-32% protit. Khi thủy phân cho axit glutamic, prolin, histidin, valin và oxyvalin, acginin và alanin.\nNgoài ra còn có 8,4% chất béo trong đó axit béo no chiếm 13%, axit không no chiếm 82,2% (axit linolic 31,69%, axit linilenic 68,31%) (theo Lưu Thọ Sơn và cộng sự-Trung dược nghiên cứu đề yếu, 1963, 126).','','Vị thuốc bổ, chữa thần kinh suy nhược, chữa ho, ho lao. Bổ tinh khí chữa đau lưng, bổ thận',NULL,'','Vị thuốc (dược liệu) đông trùng hạ thảo tự nhiên được tìm thấy chủ yếu trên vùng cao nguyên Vân Nam, Tây Tạng của Trung Quốc.\n\n“Đông trùng hạ thảo” là kết quả của sự ký sinh nấm thuộc chi Cordyceps trên sâu non của các loài bướm thuộc chi (giống) Hepialus, Allomyrina hoặc Brihaspa.',_binary '','','',NULL,'','Đông trùng hạ thảo được dùng chữa hư lao, sinh ho, ho ra máu, ra nhiều mồ hôi, liệt dương, đau lưng mỏi gối, di tinh. Ngày dùng 6-12g. Người ta cho rằng đông trùng hạ thảo ngâm rượu uống chữa chứng đau lưng, mỏi gối, tác dụng ngang với nhân sâm.\n\nTheo tài liệu cổ: Có tác dụng ích phế, thận, bổ tinh tủy, cầm máu, hóa đờm, dùng chữa hư lao sinh ho, ho ra máu, liệt dương, lưng gối đau mỏi, di tinh.','Đông trùng hạ thảo','Trùng thảo, Hạ thảo đông trùng, Đông Trùng Hạ Thảo','','DA_XUAT_BAN','Cordyceps sinensis','','ong-trung-ha-thao',0,18,'','','','','',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765123947/aannjfg0fitxuz1uovri.jpg'),(214,'2025-12-07 16:18:19','1','2025-12-07 16:18:19','1',NULL,'','','','Cây nhỏ leo, sống nhiều năm, dài khoảng 1m hay hơn. Thân hóa gỗ ở gốc, nhẵn, phân cành nhiều; cành non tỏa rộng, phủ lông hình sao và rất nhiều gai cong màu vàng.\nLá mọc so le, hình bầu dục hay thuôn, gốc tròn hoặc hình nêm, đầu tù; phiến lá to có thùy nông không đều, mặt trên sẫm, mặt dưới nhạt phủ đầy lông tơ màu trắng; hai mặt đều có gai ở gân chính nhất là mặt trên; cuống lá cũng có gai.\nHoa màu trắng hoặc hơi phớt tím mọc thành xim 2 – 5 hoa ở kẽ lá, ít khi 7 – 9; đài có lông, xẻ thành 4 thùy hình trái xoan nhọn; nhị màu vàng, chỉ nhị phình ở gốc.\nQuả mọng, hình cầu nhẵn, có cuống dài, màu vàng, khi chín màu đỏ, đường kính 5 – 7 mm; hạt hình thận màu vàng.\nMùa hoa: tháng 4 -6; mùa quả: tháng 7 -9.',NULL,'Trị cảm cúm, dị ứng, hen suyễn, đau nhức xương khớp:\n\nDùng 16 – 20g rễ hoặc thân lá cà gai leo dưới dạng thuốc sắc, uống trong ngày.\n\nPhòng ung thư:\n\nCà gai leo 30g, diệp hạ châu 10g, dừa cạn 10g, mỗi ngày sắc uống 1 thang, liên tục từ 10-30 ngày.\n\nGiải rượu:\n\nSắc 100g cà gai leo khô với 400ml nước đến khi cạn còn 150ml. Dùng uống trong ngày khi còn ấm\nHãm 50g cà gai leo khô với nước sôi như trà, xong lấy cho người say rượu uống đến khi tỉnh.','Cà gai leo là cây ưa ẩm, ưa sáng và có thể hơi chịu bóng, thường mọc tập trung nhiều cá thể, lẫn trong các lùm bụi thưa quanh làng, bãi hoang, kể cả các bụi tre gai. Cây mọc ở chỗ nhiều ánh sáng, sinh trưởng phát triển tốt, ra nhiều hoa quả. Cà gai leo có khả năng tái sinh từ hạt hoặc từ các phần thân và gốc còn lại sau khi chặt. Ngoài ra, từ các đoạn thân và cành trồng vào mùa xuân cũng có thể mọc thành cây mới.',_binary '','Chữa viêm gan B, xơ gan, giải độc gan:\n\nDùng 35g rễ hoặc thân lá cà gai leo sắc với 1 lít nước, đến khi lượng nước còn 1/3 thì chia làm 3 phần uống trong ngày\n\nChữa rắn cắn:\n\nTheo kinh nghiệm dân gian Lào, khi bị rắn cắn mà vết thương sưng tấy, nhức nhối, để cấp cứu kịp thời, có thê lấy 30 – 50 g rễ cà gai leo tươi, rửa sạch, giã nhỏ, hòa với khoảng 200 ml nước đun sôi để nguội, chắt nước cho người bị nạn uống tức thì. Ngày uống 2 lần. Người bị nạn sẽ cảm thấy dễ chịu ngay, bớt đau nhức, ngủ được. Sang ngày sau, tiếp tục cho uống nước sắc rễ cà gai leo phơi khô (10 – 30 g rễ khô, chặt nhỏ, sao vàng, nấu với 600 ml nước còn khoảng 200 ml). Mỗi ngày uống 2 lần. Dùng 3 – 5 ngày là khỏi hẳn.\n\nVới bài thuốc trên, bệnh viện Hưng Nguyên ở Nghệ An đã chữa khỏi hoàn toàn 14 trường hợp bị rắn cắn, trong đó có một vài trường hợp bị nặng.\n\nChữa tê thấp:\n\nRễ cà gai leo, rễ thổ phục linh, rễ xích đồng nam, dây chiều, dây gắm, dây mặt quỷ, dây tơ xanh, vỏ thân ngũ gia bì (mỗi thứ 1kg), dây đau xương, cành hoặc lá vông nem (mỗi thứ ½ kg). Tất cả chặt nhỏ, nấu với nước nhiều lần để được 1 lít cao. Thêm 500g đường, cô còn 700 ml . Để nguội. Đổ rượu 30⁰ vào cao cho đủ thành 1 lít. Ngày uống 2 lần, mỗi lần 30 ml. (Kinh nghiệm của hợp tác xã Hợp Châu).\n\nChữa ho, ho gà:\n\nRễ cà gai leo (10g), lá chanh (30g). Sắc uống làm 2 lần trong ngày\n\nChữa phong thấp:\n\nRễ cà gai leo, rễ xấu hổ, thổ phục linh, rễ cỏ xước, kê  huyết đằng, rễ cỏ tranh, mỗi vị 16 g. Sắc uống.\nRễ cà gai leo, vỏ chân chim, rễ cỏ xước, dây đau xương, kê huyết đằng, rễ tầm xuân, mỗi vị 20 g. Sắc uống.\nChữa tê thấp, bàn chân tê buốt, sợ nước, sợ lạnh, khớp xương đau buốt:\nRễ cà gai leo, rễ lá lốt, quýt rừng, rễ gấc, rễ xuyên tiêu, cốt khí củ, mỗi vị 20 – 30g. Sắc uống.\nChữa sưng mộng răng:\n\nHạt cà gai leo 4g tán nhỏ, cho vào nồi đồng với một ít sáp ong, đốt lá lấy khói xông vào chân răng (Bách gia trân tàng).','',NULL,'','Phản ứng viêm:\n\nTrong mô hình gây phù thực nghiệm chân chuột bằng kaolin tạo nên giai đoạn cấp tính của phản ứng viêm tương ứng với những biến đổi về mạch máu gây thoát huyết tương ở khoảng ngoài tế bào, rễ và thân lá cà gai leo có tác dụng ức chế phù rõ rệt (rễ với liều 13.5/ kg và thân lá với liều 22.5 kg trở lên).\n\nĐối với giai đoạn bán cấp của phản ứng viêm tương ứng với sự tạo thành tổ chức hạt, trong mô hình gây u hạt thực nghiệm với amian, rễ và thân lá cà gai leo có tác dụng ức chế rõ rệt (rễ với liều từ 5g/kg và thân lá từ 10g/kg chuột trở lên).','Cà gai leo','Cà gai leo, Chẽ nam (Tày), Cà gai dây, Cà quýnh, Cà quạnh, Brong goon (Bana), Gai cườm','Rễ và cành lá cà gai leo, thu hái quanh năm, rửa sạch, thái nhỏ, phơi hay sấy khô. Có khi dùng tươi.','DA_XUAT_BAN','Solanum hainanense','','ca-gai-leo',0,18,'Hoa màu trắng hoặc hơi phớt tím mọc thành xim 2 – 5 hoa ở kẽ lá, ít khi 7 – 9; đài có lông, xẻ thành 4 thùy hình trái xoan nhọn; nhị màu vàng, chỉ nhị phình ở gốc.','Quả mọng, hình cầu nhẵn, có cuống dài, màu vàng, khi chín màu đỏ, đường kính 5 – 7 mm; hạt hình thận màu vàng.','Lá mọc so le, hình bầu dục hay thuôn, gốc tròn hoặc hình nêm, đầu tù; phiến lá to có thùy nông không đều, mặt trên sẫm, mặt dưới nhạt phủ đầy lông tơ màu trắng; hai mặt đều có gai ở gân chính nhất là mặt trên; cuống lá cũng có gai.','','Cây nhỏ leo, sống nhiều năm, dài khoảng 1m hay hơn. Thân hóa gỗ ở gốc, nhẵn, phân cành nhiều; cành non tỏa rộng, phủ lông hình sao và rất nhiều gai cong màu vàng.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765124294/o0itrb0f6dz0eukruj06.jpg'),(215,'2025-12-07 16:22:18','1','2025-12-07 16:22:18','1',NULL,'','Chưa thấy có tài liệu nghiên cứu\n\n','',' Trị ung nhọt, kiết lỵ, viêm loét dạ dày hành tá tràng, chốc đầu.',NULL,'','',_binary '','Chữa đau bụng không rõ nguyên nhân:\n\nHái mấy lá Khổ sâm, nhai với mấy hạt muối; nếu có nôn hay sôi bụng thì nhai với một miếng gừng sống.\n\nChữa đau bụng lâm râm, hay sau khi ăn đau bụng, khó tiêu:\n\nLá Khổ sâm, dây Ngấy hương, đều phơi khô, mỗi thứ một nắm (30-40g), thêm 3 lát gừng, sắc uống. Hoặc thường dùng sắc 2 thứ lá trên uống thay trà.\n\nChữa kiết lỵ hay đau bụng đi ngoài:\n\nDùng lá Khổ sâm và lá Phèn đen mỗi thứ một nắm sắc uống, hoặc lá Khổ sâm, Rau sam, Cỏ sữa, Nhọ nồi, Lá mơ lông, mỗi vị 10g sắc uống, ngày 1 thang.\n\nChữa khắp mình nổi mẩn ngứa, muốn gãi luôn:\n\nDùng lá Khổ sâm, Kinh giới, lá Đắng cay, lá Trầu không, nấu nước xông và tắm rửa.','',NULL,'','Cây khổ sâm trị ung nhọt, kiết lỵ, viêm loét dạ dày hành tá tràng, chốc đầu.\nLiều dùng khổ sâm cho lá:\nMỗi lần uống 12 – 20g dưới dạng thuốc sắc.\n\nCây này mới được nhiều người chú ý mấy năm gần đây do được dùng trong đơn thuốc chữa đau dạ dày, có lá khôi sau đây:\n\nLá khôi Ardisia sylvestris 50g\nLá bồ công anh Lactuca indica 20g\nLá khổ sâm Croton tonkinensis 12g\nNước 600ml\nSắc đặc và cô còn chừng 200ml chia làm 2 hay 3 lần uống trong ngày.\nUống liên tục trong 10 ngày, lại nghỉ 3 ngày. Cứ như vậy cho đến khi khỏi đau, uống thêm một tuần nữa. Có người thêm vào đơn thuốc trên 3 lát gừng sống đối với người hay đi ỉa lỏng.\nNếu dùng riêng thường dùng với liều 24-40g (lá khô sao vàng), thêm 600ml nước (3 bát), sắc còn 1 bát (200ml), chia 2 hay 3 lần uống trong ngày, 15 phút đến nửa giờ trước khi ăn cơm.\nĐể ăn ngon cơm, giúp sự tiêu hoá.','Khổ Sâm cho lá','Khổ sâm lá nhỏ , Khổ sâm lá nhọn','lá','DA_XUAT_BAN','Croton tonkinensis','','kho-sam-cho-la',0,18,'Cụm hoa mọc ở kẽ lá hay đầu cành, lưỡng tính hay đơn tính. Hoa đực có 5 lá đài, 12 nhị, hoa cái có 5 lá đài, 3 vòi nhị.\n','Quả gồm 3 mảnh vỏ, màu hung hung đỏ.\n','Lá mọc cách hay gần như mọc đối, có khi mọc thành vòng giả gồm 3-6 lá. Lá hình mũi mác, mép nguyên dài 5-10cm, rộng 3cm. Cả hai mặt lá đều có nhiều lông hình khiên óng ánh (kiểu lông ở lá cây nhót) nhưng mặt dưới nhiều hơn ở mặt trên.\nKhi phơi khô, mặt lá dưới có màu trắng bạc, mặt trên có màu nâu đen.','','Cây nhỏ cao độ 0,7-1m.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765124519/qtk6z2c48zmuahikp2ib.jpg'),(216,'2025-12-07 16:25:55','1','2025-12-07 16:25:55','1',NULL,'Cây ích mẫu có tên như vậy vì có ích cho người mẹ (ích là có ích, mẫu là mẹ). Tên Leonurus do chữ Hy lạp leon là sư tử, oura là đuôi, heterophyllus là lá có hình dạng biến đổi, vì cây ích mẫu giống đuôi con sư tử có lá hình dạng thay đổi. Ích mẫu là một loại cỏ sống 1-2 năm, cao 0,6m đến 1m.\nThân hình vuông, ít phân nhánh, toàn thân có phủ lông nhỏ ngắn.\nLá mọc đối, tùy theo lá mọc ở gốc, giữa thân hay đầu cành mà có hình dạng khác nhau. Lá ở gốc, có cuống dài, phiến lá hình tim, mép có răng cưa thô và sâu; lá ở thân có cuống ngắn hơn, phiến lá thường xẻ sâu thành 3 thùy, trên mỗi thùy lại có răng cưa thưa; lá trên cùng phần lớn không chia thùy và hầu như không cuống.\nHoa mọc vòng ở kẽ lá. Tràng hoa màu hồng hay tím hồng, xẻ thành hai môi gần đều nhau.\nQủa nhỏ, 3 cạnh, vỏ màu xám nâu\nNgoài cây ích mẫu mô tả trên, cần chú ý phát hiện và phân biệt cây ích mẫu Leonurus sibiricus L (tạm gọi là cây ích mẫu hoa to) vì cây này khác cây ích mẫu mói trên ở hoa to hơn, dài hơn, lá phía trên vẫn chia 3 thùy. Ta có thể tóm tắt sự khác nhau giữa hai cây như sau:\n\nLá trên cùng không chia thùy, tràng hoa dài 9-12mm, môi trên, môi dưới gần bằng nhau Leonurus heterophyllus.\nTheo các tài liệu mới hiện nay họ Hoa môi có tên khoa học là Lamiaceace.\nLá trên cùng xẻ 3 thùy, tràng hoa hài 15-20mm, môi dưới ngắn hơn môi trên Leonurus','Cây ích mẫu Leonurus heterophyllus chưa thấy tài liệu nghiên cứu. Sơ bộ chúng tôi thấy phản ứng ancaloit và tanin (7-8%), flavonozit.\nTừ cây ích mẫu Leonurus sibiricus, các nhà nghiên cứu Nhật Bản ( Nhật bản dược vật học tạp chí 1930, tr.153-158) đã chiết được 0,05% ancaloit gọi là leonirin C13H19O4N4 có độ chảy 238oC.\nNăm 1958, một số tác giả khác (Bắc Kinh y học viện học báo kỳ I) đã chiết từ ích mẫu Leonurus sibiricus 5 chất có tinh thể: 2 chất đầu là ancaloit và gọi là leonurin A: C20H32O10N6 có độ chảy 229-230oC, leorunin B: C14H24O7N4 chảy 77-78oC, 86-87oC và 141-142oC.\nNăm 1940, Thang Đằng Hán (1940 J.Chem. Soc.vol.7, N02) chiết từ phần tan trong nước một chất gọi là leonuridin công thức C6H12O3N2 có độ chảy 221,5-222oC. Trong cây và quả ích mẫu, Hứa thực Phương (J.Chem.Soc.vol 2, N03) còn báo cáo chiết được một ancaloit khác còn gọi là leonurinin có độ chảy 262-263oC với công thức C10H14O3N2.\nTỷ lệ ancaloit cao nhất vào tháng 5, sau đó giảm xuống. Ngoài ra trong cây ích mẫu còn có tanin, chất đắng, saponin và 0,03% tinh dầu.\nHoạt chất của ích mẫu như thế cũng chưa được xác định chắc chắn, nhưng trên cơ sở dược lý người ta thấy trong ích mẫu có 2 loại hoạt chất. Một loại hoạt chất tan trong ête có tác dụng ức chế tử cung, một loại hoạt chất không tan trong ête có tác dụng kích thích tử cung.\nGần đây người ta thấy trong ích mẫu có 3 flavonozit, một trong số flavonozit được xác định là rutin, một glucozit có cấu tạo steroit, một ít tanin, trong toàn cây có leocacdin cùng cấu trúc với stachydrin, một ít tinh dầu. Ancaloit không có tác dụng chữa bệnh.','','Thuốc điều kinh, chữa đau bụng kinh, phù thũng, bạch đới (cả cây). Phối hợp với Chàm mèo làm thuốc gây sảy thai. Còn dùng chữa cao huyết áp, tiêu độc, viêm thận, phù.',NULL,'Từ lâu vị ích mẫu được nhân dân ta dùng, chữa bệnh từ phụ nữ, nhất là đối với phụ nữ sau khi sinh nở, do đó có câu ca dao: Nhân trần, ích mẫu đi đâu Để cho gái đẻ đớn đau thế này?\nThường ích mẫu dùng trong trường hợp đẻ xong bị rong huyết (cầm máu tử cung), chữa viêm niêm mạc dạ con, kinh nguyệt quá nhiều.\nCòn dùng chữa huyết áp cao, thuốc bổ huyết, các bệnh về tuần hoàn cơ tim, thàn kinh của tim, chứng tim hẹp nhẹ (stenocardie), chữa lỵ.\nQuả ích mẫu dùng với tên sung úy tử làm thuốc thông tiểu, chữa phù thủng, thiên đầu thống (glôcôm)\nDùng ngoài thân và quả ích mẫu giã đắp hay sắc lấy nước rửa chữa một số bệnh như sưng vú, chốc đầu, lở ngứa.\nTheo sách cổ, ích mẫu có tính chất: vị cay, đắng, tính hơi hàn, có khả năng trục ứ huyết, sinh huyết mới, hoạt huyết điều kinh, những người có đồng tử mở rộng không dùng được.\nLiều dùng hằng ngày từ 6-12g dưới dạng thuốc sắc hay nấu thành cao. Quả ích mẫu dùng với liều 6-12g dưới dạng thuốc sắc.','',_binary '','','',NULL,'','1. Tác dụng trên tử cung\nNước sắc ích mẫu Leonurus sibiricus 1/5.000 hay 1/1.000 có tác dụng kích thích đối với tử cung cô lập của thỏ cái (dù có thai hay không có thai cũng vậy)\nThỏ cái gây mê bằng ure6tan rồi cho uống nước sắc ích mẫu cũng thấy có tác dụng kích thích trên tử cung tại chỗ của thỏ.\nDung dịch nước 10% ích mẫu khô tác dụng trên tử cung mạnh hơn là dung dịch rượu 20%.\nTác dụng của ích mẫu trên tử cung cũng giống như tác dụng của cựa lõa mạch (Claviceps purpurrea).\nĐiều đáng chú ý là dung dịch rượu hay dung dịch nước ích mẫu tác dụng lên tử cung thì bắt đầu có một giai đoạn hưng phấn.\nNếu trước khi sắc ích mẫu, dùng ête để loại phần tan trong ête đi thì hiện tượng ức chế tử cung không thấy nữa.\n2. Tác dụng trên huyết áp\nNước sắc ích mẫu tuy không tác dụng trực tiếp trên huyết áp nhưng làm giảm tác dụng của adrenalin trên mạch máu. Cao ích mẫu làm giảm huyết áp, nhất là đối với thời kỳ đầu của bệnh cao huyết áp.\n\n3. Tác dụng trên tim mạch\nLoài ích mẫu Leonurus quinquelobatus là Leonurus cardia có tác dụng tốt trên tim mạch và đối với cơ tim có bệnh.\n\n4. Tác dụng đối với hệ thần kinh\nTác dụng đối với hệ thần kinh của ích mẫu Leonurus sibiricus mạnh hơn tác dụng của Valerian và Muyghe (Convallaria maialis).\n\n5. Tác dụng kháng sinh đối với một số vi trùng ngoài da\nTheo Trung hoa bì phụ khoa tạp chí (số 4-1957, tr.286-292) một số tác giả nghiện cứu thấy nước chiết ích mẫu 1:4 có tác dụng ức chế với trình độ khác nhau đối với một số vi trùng gây bệnh ngoài da.\n\n6. Tác dụng trên viêm thận và phù cấp tính\nTrên lâm sàng, ích mẫu chữa khỏi một số trường hợp viêm thận và phù (Trung y tạp chí số 6, 1959 và Trung y dược 1966 kỳ 4, 26).','Ích mẫu',' Ích mẫu, Sung uý, Chói đèn, Làm ngài, Xác diến (Tày), Chạ linh lo (Thái)','lá, thân','BAN_NHAP','Leonurus japonicus','','ich-mau',0,6,'Hoa mọc vòng ở kẽ lá. Tràng hoa màu hồng hay tím hồng, xẻ thành hai môi gần đều nhau.\n','Qủa nhỏ, 3 cạnh, vỏ màu xám nâu\n','Lá mọc đối, tùy theo lá mọc ở gốc, giữa thân hay đầu cành mà có hình dạng khác nhau. Lá ở gốc, có cuống dài, phiến lá hình tim, mép có răng cưa thô và sâu; lá ở thân có cuống ngắn hơn, phiến lá thường xẻ sâu thành 3 thùy, trên mỗi thùy lại có răng cưa thưa; lá trên cùng phần lớn không chia thùy và hầu như không cuống.\n','','Thân hình vuông, ít phân nhánh, toàn thân có phủ lông nhỏ ngắn.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765124732/ejwrmtinl0zakh1j0mao.jpg'),(217,'2025-12-07 16:28:47','1','2025-12-07 16:28:47','1',NULL,'','Theo các nhà nghiên cứu trước, trong nhọ nồi có một ít tinh dầu, tannin, chất đắng, carotene và chất ancaloit gọi là ecliptin. Có sách nói chất ancaloit là nicotin.\nNăm 1959 Govindachari T.R và đồng sự đã chiết được từ cỏ nhọ nồi một chất wedelolacton là một cumarin lacton. Sau đó tác giả cũng thấy chất này trong cây sài đất (công thức wedelolacton, xem ở cây sài đất).\nNgoài wedelolacton, năm 1972 K.K Bharagava (Ind.J.Chem 8,72:810) còn tách được demetyl wedelolacton và một flavonozit chưa xác định.','','Cỏ nhọ nồi là một loài cỏ mọc thẳng đứng có thể cao tới 80cm, thân có lông cứng, lá mọc đối có lông ở hai mặt, dài 2-8cm, rộng 5-15mm.\nCụm hoa hình đầu màu trắng ở kẽ lá hoặc đầu cành, lá bắc thon dài 5-6mm, cũng có lông.\nQuả bế 3 cạnh, hoặc dẹt, có cánh. Dài 3mm, rộng 1,5mm, đầu cụt, mọc hoang khắp nơi ở nước ta.',NULL,'','',_binary '','','',NULL,'','Tác dụng bổ thận âm, chỉ huyết lỵ. Dùng chữa can thận âm kém, lỵ và ỉa ra máu, làm đen râu tóc.\n\nNhân dân vẫn dùng cây nhọ nồi giã vắt lấy nước uống để cầm máu trong rong kinh, trĩ ra máu, bị thương chảy máu. Còn dùng chữa ho hen, ho lao, viêm cổ họng, ngày dùng 6-12g dưới dạng sắc uống hay làm thành viên mà uống. những người thợ nề dùng cỏ nhọ nồi để xoa tay chữa bệnh bỏng rát do vôi. Có người dùng chữa bệnh nấm ở ngoài da, làm thuốc mọc tóc (sắc uống hoặc ngâm vào dầu dừa mà bôi), nhuộm tóc, bôi lên những chỗ chóc ở da thịt để có màu tím đen.','Cỏ nhọ nồi','Cỏ nhọ nồi, Cỏ mực','lá , thân','DA_XUAT_BAN','Eclipta prostrata ','','co-nho-noi',0,5,'','','','','',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765124920/yn5xtwgfprufa33arnik.jpg'),(218,'2025-12-07 16:36:48','1','2025-12-07 16:36:48','1',NULL,'','Phân tích bột thân rễ được các thành phần sau: cao ether 1,28%; cao cồn 4,14%; cao nước 19,92%; tinh bột 43,48%; sợi 14,18%; tro 8,60%; tanin 4,15%. (The Wealth of India, vol V. 1950, p. 400)\n\nThân rễ sâm cau chứa các chất thuộc nhóm cycloartan triterpenic:\n\nMisra Triguna N, Singh Ram S đã phân lập và xác định chất 24-methylcycloart-7-en-3-β-20-diol.\nXu junping, Xu Rensheng đã tách được các cycloartan glycosid là curculigo saponin A → F.G.H.I.J với cấu trúc của genin chung là curculigenin A được xác định là 3β, 10α, 16β-trihydroxycycloartan-24-on.\nCác triterpen penta cyclic cũng được chiết xuất từ thân rễ sâm cau như acid 31-methyl-30-zo-20-ursen-28 oic.\nCác phenyl glucosid và chlorophenyl glucosid curculigosid B, curculigin B và C có cấu trúc là:\n\n2-β-D-glucopyranosyloxy-5-hydroxybenzyl-2-methoxy-6hydroxybenzoat.\n24-dichloro-3-methyl-5-methoxyphenol-O-β-D-apiofuranosyl(1→6)-D-glucopyranosid; và 2,4,6-trichloro-3-methyl-5-methoxyphenol-O-C-D-xylopyranoyl (1 → 6)-β-O–glucopyranosid.\nCurculigin A là một ví dụ về chlorophenyl glucosid và corchiosid A thuộc loại phelyl glucosid đều có ở thân rễ sâm cau.\nMột số chất aliphatic như 25-hydroxy-33-methylpentatricontan-6-on, hentricontanol, và các hợp chất chứa nitơ như N-acetyl-N-hydroxy-2-carbomethoxy-2H-3,4,5,6-tetrahydro-1,2,3,5,6-oxatetrazin và N-N,N’.N’-tetramethylsuccinamid cũng đã được phát hiện trong thân rễ sâm cau.\nNgoài ra còn sucrose, sitosterol, stigmasterol và các hợp chất flavonoid như 5,7-dimethoxydihydromyricetin-3-O-α-L-xylopyranosyl-4-O-β-D-glucopyranosid, yuccagemin và lycorin.\n\nYamasaki Kazuya đã định lượng một số mẫu sâm cau của Trung Quốc thấy hàm lượng curculosid khoảng 2%.\nCác chất curculigenin A, curculigol đã được nghiên cứu thấy có tác dụng chống độc gan.','','Cây thảo, sống lâu năm, cao 20 – 30 cm, có khi hơn.\nThân rễ, hình trụ dài, mọc thẳng, thót lại ở hai đầu, mang nhiều rễ phụ có dạng giống thân rễ.\nLá mọc tụ họp thành túm từ thân rễ, xếp nếp như lá cau, hình mũi mác hẹp, dài 20 – 30 cm, rộng 2,5 – 3 cm, gốc thuôn, đầu nhọn, hai mặt nhẵn gần như cùng màu, gân song song rất rõ; bẹ lá to và dài; cuống lá dài khoảng 10 cm.\nCụm hoa mọc trên một cán ngắn ở kẽ lá, mang 3 – 5 hoa màu vàng; lá bắc hình trái xoan, đài 3 răng có lông; tràng 3 cánh nhẵn; nhị 6, xếp thành hai dãy, chỉ nhị ngắn; bầu hình thoi, có lông rậm.Quả nang, thuôn, dài 1,2 – 1,5 cm; hạt 1 – 4, phình ở đầu.\nMùa hoa quả: Tháng 5 – 7',NULL,'','Trên thế giới, Sâm cau phân bố ở một số tỉnh phía nam Trung Quốc, Lào, Việt Nam và một vài nước khác ở Đông Nam Á. Ở Việt Nam, cây phân bố rải rác ở các tỉnh vùng núi, từ Lai Châu, Tuyên Quang, Cao Bằng. Trước năm 1980, các tỉnh Sơn La, Hòa Bình thường khai thác được nhiều cây thuốc này và hiện nay trở nên hiếm dần. Trước thực trạng này, công ty TNHH Tuệ Linh đã tiên phong phát triển một vùng trồng Sâm cau rộng 3 ha ở vùng núi Tây Bắc nhằm bảo vệ loại thảo dược quý này thoát khỏi nguy cơ tuyệt chủng đang cận kề áp sát.\n\nSâm cau là loại cây ưa ẩm, ưu sáng và có thể hơi chịu bóng, thường mọc trên những nơi đất còn tương đối màu mỡ trong thung lũng, chân núi đá vôi hoặc ven nương rẫy. Cây sinh trưởng tốt trong mùa mưa ẩm, phần thân rễ chính dạng củ, cắm sâu xuống đất, hoa quả hàng năm, khi già tự mở để hạt phát tán ra xung quanh.',_binary '','','Curculigo orchioides',NULL,'','Sâm cau được dùng chữa nam giới tinh lạnh, liệt dương, người già đái són, lạnh dạ, kém ăn, tê thấp, lưng gối vận động khó khăn. Liều dùng mỗi ngày 12 – 20g dưới dạng thuốc sắc hay ngâm rượu uống. Dùng riêng hoặc phối hợp với các vị khác. Còn dùng chữa hen và tiêu chảy. Nhân dân ở một số vùng dân tộc thiểu số dùng rễ củ sâm cau làm thuốc bổ. Dùng ngoài, rễ giã nát đắp chữa lở loét.','Sâm cau','Sâm cau, Ngải cau, Tiên mao, Cồ nốc lan, Sâm đỏ, Thài lèng, Soọng cà (Tày), Nam sáng ton (Dao)','Sâm cau, Ngải cau, Tiên mao, Cồ nốc lan, Sâm đỏ, Thài lèng, Soọng cà (Tày), Nam sáng ton (Dao)','DA_XUAT_BAN','Curculigo orchioides','','sam-cau',0,2,'','','','','',NULL,NULL),(219,'2025-12-07 16:45:21','1','2025-12-07 16:45:21','1',NULL,'','Hà thủ ô đỏ chứa 1,7% antraglucosid trong đó có crysophanol, emodin, rhein, 1,1% protid, 42,2% tinh bột, 3,1% lipid, 4,5% chất vô cơ, 26,4% chất tan trong nước…\n\nThành phần hoá học của hà thủ ô đỏ thay đổi trong quá trình chế biến. Theo y học cổ truyền, hà thủ ô đỏ sống chứa 7,68% tanin, 0,259% dẫn chất antraquinon tự do, 0,805% dẫn chất antaquinon toàn phần.\n\nSau khi chế biến, dược liệu chứa 3,82% tanin, 0,113% dẫn chất antraquinon tự do, 0,25% antaquinon toàn phần. Chất phospholipid có 3,49% trong dược liệu thô và 1,82% trong dược liệu đã chế biến. Ngoài ra còn có các chất vô cơ K, Ca, Mn, Ni, Cr.','','Dây leo bằng thân quấn, sống lâu năm. Thân mềm, nhẵn, mọc xoắn vào nhau. Rễ phình thành củ, màu nâu đỏ, củ nguyên có hình giống củ khoai lang.\nLá mọc so le, hình mũi tên, gốc hình tim, đầu thuôn nhọn, dài 5 – 8cm, rộng 3 – 4cm, 3 – 5 gân xuất phát từ gốc lá, hai mặt nhẵn, mặt trên sẫm bóng; cuống dài khoảng 2 cm, phủ lông tơ, bẹ chìa mỏng, ngắn, có lông dài.\nCụm hoa mọc ở kẽ lá hoặc đầu cành thành chùy phân nhánh, dài hơn lá; lá bắc ngắn; hoa nhỏ nhiều, màu trắng; nhị 8, thường dính vào gốc của bao hoa.\nQuả hình 3 cạnh, nhẵn bóng, nằm trong bao hoa, 3 mảnh ngoài phát triển thành những cánh rộng.\nMùa hoa: tháng 9 -11; mùa quả: tháng 12 – 2.',NULL,'','Hà thủ ô phân bố rộng rãi ở nhiều nước cận nhiệt đới và nhiệt đới. Ở Việt Nam, có 1 loài là cây hà thủ ô đỏ. Trên thế giới, hà thủ ô đỏ có ở Trung Quốc, Bắc Lào, Nhật Bản và Ấn Độ. Ở Việt Nam, hà thủ ô đỏ chỉ có ở một số tỉnh vùng núi cao phía bắc. Cây mọc nhiều ở Hà Giang, Lai Châu, Lào Cai, Sơn La….\n\nHà thủ ô là cây ưa khí hậu ẩm mát của vùng cận nhiệt đới và nhiệt đới núi cao. Cây ưa sáng và có thể hơi chịu bóng. Nơi mọc tự nhiên thích hợp nhất là các quần thể rừng núi đá vôi.\n\nHà thủ ô đỏ ra hoa quả nhiều hàng năm. Sau khi quả già, phần thân leo trên mặt đất tàn lụi, hạt giống phát tán xung quanh và sẽ nảy mần vào mùa xuân hè năm sau. Hà thủ ô đỏ có khả năng tái sinh vô tính khỏe. Từ một đoạn thân hay đoạn củ là có thể tái sinh thành cây mới.\nNguồn hà thủ ô ở nước ta trước đây khá dồi dào. Qua hàng chục năm khai thác và nạn phá rừng làm nương rẫy vùng phân bố tự nhiên của cây bị thu hẹp rất nhiều.',_binary '','','',NULL,'','Hà thủ ô đỏ có tác dụng dược lý như sau: làm tăng đường máu ở thỏ; do chứa lecithin, nên có thể dùng trong suy nhược thần kinh và bệnh về thần kinh, giúp sinh huyết dịch, bổ tim, giúp cải thiện chuyển hoá chung; do chứa antraglucosid nên kích thích co bóp ruột, kích thích tiêu hoá, cải thiện dinh dưỡng.\nHà thủ ô đỏ có tác dụng nội tiết kiểu oestrogen, tác dụng kiểu progesteron nhẹ trên nội mạc tử cung, làm tăng trương lực cơ tử cung trong những thí nghiệm tử cung cô lập và ở nguyên vị trí, tăng tiết sữa và chống viêm.\nHà thủ ô đỏ có tác dụng nâng cao tỷ lệ sống hoặc kéo dài thời gian cầm cự đối với động vật đã tiêm liều độc nọc rắn hổ mang và tác dụng ức chế sự co thắt cơ trơn ruột cô lập gây bởi histamin và acetylcholin.\nHà thủ ô đỏ có tác dụng chống co thắt phế quản, kéo dài thời an toàn trong mô hình khí dung histamin.\nHà thủ ô đỏ có tác dụng chống viêm trên mô hình thực nghiệm, gây phù cấp tính và viêm mạn tính, gây rỉ dịch màng phổi bằng tinh dầu thông, gây viêm dị ứng và viêm khớp bằng BGC.','Hà thủ ô đỏ',' Hà thủ ô đỏ, Dạ giao đằng, Má ỏn, Mằn năng ón (Tày), Khua lình (Thái), Xạ ú sí (Dao)','','DA_XUAT_BAN','Reynoutria multiflora','','ha-thu-o-o',0,2,'Cụm hoa mọc ở kẽ lá hoặc đầu cành thành chùy phân nhánh, dài hơn lá; lá bắc ngắn; hoa nhỏ nhiều, màu trắng; nhị 8, thường dính vào gốc của bao hoa.Mùa hoa: tháng 9 -11; mùa quả: tháng 12 – 2.\n','Quả hình 3 cạnh, nhẵn bóng, nằm trong bao hoa, 3 mảnh ngoài phát triển thành những cánh rộng.\n','Lá mọc so le, hình mũi tên, gốc hình tim, đầu thuôn nhọn, dài 5 – 8cm, rộng 3 – 4cm, 3 – 5 gân xuất phát từ gốc lá, hai mặt nhẵn, mặt trên sẫm bóng; cuống dài khoảng 2 cm, phủ lông tơ, bẹ chìa mỏng, ngắn, có lông dài.\n','','Dây leo bằng thân quấn, sống lâu năm. Thân mềm, nhẵn, mọc xoắn vào nhau. Rễ phình thành củ, màu nâu đỏ, củ nguyên có hình giống củ khoai lang.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765125901/f7nxqeevp0ueoevtfq96.jpg'),(220,'2025-12-07 16:58:46','1','2025-12-07 16:58:46','1',NULL,'','Trong bạch chỉ có các hoạt chất sau đây: Oxypeucedanin, imperatorin, isoimperatorin, phellopterin, byak-angelixin, izobyakangelicol hay anhydrobyakangelixin có độ chảy 108- 109°C, angelicol, xanthotoxin, neobyakangelicol, marmesin có độ chảy 189,50C, năng suất quay cực αD+26°8 (trong clorofoc), nodakenetin tả tuyền αD -22°4, scopoletin.\nCác chất này có cấu trúc cơ bản. Ngoài ra người ta còn chiết được chất alloizoimperatorin có độ chảy 228-230°C (thăng hoa) và 5 metoxy-8-andehytpsoralen có độ chảy 215-217°C, những chất đó vốn không có trong bạch chỉ nhưng có thể xuất hiện trong quá trình chiết xuất từ những chất izoimpertorin hoặc chất neobyakangelicol mà sinh ra.\nTrong xuyên bạch chỉ ngoài chất bergapten, umbelliferon còn có anomalin (độ chảy 105-106°C ).\nMột tác giả khác đã lấy từ xuyên bạch chỉ được chừng 0,43% một chất gọi là angelicotoxin, một chất nhựa màu vàng, vị đắng có tính chất kích thích; ngoài ra còn có 0,2% chất byakangelixin C17H1g07, 0,2% chất byakangelicola C17H16O6 axit angelic C4H7COOH và tinh dầu.','','Cây bạch chỉ (Angelica dahurica) còn gọi là hàng châu bạch chỉ là một cây sống lâu năm, cao 1-1,5m, đường kính thân có thể tới 2-3cm, thân rồng, mặt ngoài màu tím hồng, phía dưới thân nhẵn, không có lông, nhưng phía trên, gần cụm hoa thì có lông ngắn.\nLá phía dưới to, có cuống dài, phiến lá 2-3 lần xẻ lông chim, thuỳ hình trứng hay hình trứng dài, dài 2-6cm, rộng 1-3cm, mép có răng cưa, lá phía trên nhỏ hơn, toàn bộ cuống lá phát triển thành bẹ bao ôm lấy thân, hai mặt đều không có lông, nhưng trên đường gân của mặt trên có lông ngắn.\nCụm hoa hình tán kép mọc ở kẽ lá hay đầu cành, cuống tán dài 48cm, cuống tán nhỏ dài 1cm, hoa màu trắng, quả dài chìmg 6mm, rộng 5-6mm.',NULL,'Đơn thuốc có bạch chỉ dùng trong nhân dân\n\nTrẻ con nóng sốt: Nấu nước bạch chỉ, tắm thật nhanh ở nơi kín gió.\nChữa chứng hôi miệng: Bạch chỉ 30g, xuyên khung 30g. Hai vị tán nhỏ, dùng mật viên bằng hạt ngô. Hằng ngày ngậm thuốc này, mỗi ngày ngậm chừng 2-3 viên.\nChữa cảm cúm, sốt gai rét, nhức đầu ê ẩm, thân thể đau mỏi: Bạch chỉ, xuyên khung: mỗi thứ một lượng bằng nhau. Tán thành bột, uống mỗi lần 2-3g. Ngày uống 3-4 lần với nước hoặc rượu cho ra mồ hôi.\nChữa mụn nhọt mưng mủ: Bạch chỉ, đương quy, tạo giác. Mỗi thứ 7g, sắc nước uống.\nChú thích:\n\nTrong nhân dân Việt Nam còn dùng một vị thuốc với tên nam bạch chỉ, thực ra đó là rễ của cây mát rừng-Millettia pulchra Kurz, thuộc họ Cánh bướm (Papilionaceae). Cây nhỏ, cao 1,5- l,8m, hoa mọc thành chùm màu tím nhạt, quả đậu hình đao, nhẵn, cứng, mọc hoang ở nhiều tỉnh như Bắc Giang, Bắc Ninh, Vĩnh Phúc, Phú Thọ. Rễ có màu hơi vàng, thường hái ở những cây nhỏ. Dùng sắc cùng một số vị thuốc khác chữa đau bụng, đi ỉa.\nTrong một số sách thuốc cũ của Trung Quốc người ta giới thiệu bạch chỉ là rể Angelica glabra Makino hay Angelica formosana Boiss. họ Hoa tán; nhưng những tài liệu mới nhất thường thống nhất những tên đã giới thiệu ở trên.','Bạch chỉ đã được di thực vào nước ta có kết quả, cây mọc tốt, cả ở đồng bằng và những vùng núi cao mát. Nhưng giống thì chỉ mới để được ở miền núi cao, lạnh. Tại Tam Đảo trồng vào tháng 1-2, tháng 4-5 năm sau ra hoa, nhưng có những cây trồng vào tháng 7-8 năm trước thì tháng 4-5 năm sau cùng ra hoa một lúc với cây trồng tháng 1-2. Vào mùa thu, khi lá úa vàng, đào lấy rễ, cắt bỏ thân và rễ con, rửa sạch đất, sau đó có nơi cho vào vại có vôi, đậy kín một tuần rồi mói lấy ra phơi khô, có nơi đem phơi ngay, nếu trời mưa thì sấy trong lò, sau đó cạo bỏ vỏ mỏng ngoài.',_binary '','','',NULL,'','Với liều nhỏ, angelicotoxin có tác dụng hưng phấn đối với trung khu vận động huyết quản, trung khu hô hấp và dây thần kinh phế vị (nerf vague), làm cho huyết áp tăng cao, nhịp mạch chậm lại, hơi thở kéo dài, chảy dãi và nôn mửa.\nVới liều lớn, có thể dẫn tới co giật và toàn thân tê liệt. Độc tính của ngelicotoxin có thể sánh giống như chất xicutoxin (cicutoxin), nhung không mạnh bằng. Hoạt chất khác trong bạch chỉ chưa rõ.\nNăm 1950, Lưu Quốc Thanh và Trương Duy Tân nghiên cứu tác dụng kháng sinh của bạch chỉ đối với một số vi trùng thì thấy bạch chỉ có khả năng ức chế sự sinh trưởng của trực khuẩn côli, trùng lỵ Sonner, trùng trực khuẩn mủ xanh (pyocyanus) và vi trùng thổ tả.','Bạch chỉ','Bạch chỉ, Hương bạch chỉ, Hoàng châu bạch chỉ','rễ','DA_XUAT_BAN','Angelica dahurica ','','bach-chi',0,8,'Cụm hoa hình tán kép mọc ở kẽ lá hay đầu cành, cuống tán dài 48cm, cuống tán nhỏ dài 1cm, hoa màu trắng, quả dài chìmg 6mm, rộng 5-6mm.\n','','Lá phía dưới to, có cuống dài, phiến lá 2-3 lần xẻ lông chim, thuỳ hình trứng hay hình trứng dài, dài 2-6cm, rộng 1-3cm, mép có răng cưa, lá phía trên nhỏ hơn, toàn bộ cuống lá phát triển thành bẹ bao ôm lấy thân, hai mặt đều không có lông, nhưng trên đường gân của mặt trên có lông ngắn.\n','','Cây bạch chỉ (Angelica dahurica) còn gọi là hàng châu bạch chỉ là một cây sống lâu năm, cao 1-1,5m, đường kính thân có thể tới 2-3cm, thân rồng, mặt ngoài màu tím hồng, phía dưới thân nhẵn, không có lông, nhưng phía trên, gần cụm hoa thì có lông ngắn.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765126717/owrkvtjih9oz9juwjzep.jpg'),(221,'2025-12-07 17:07:35','1','2025-12-07 17:07:35','1',NULL,'Tên thiên niên kiện vì nguời ta cho rằng uống vị thuốc này thì nghìn năm khoẻ mạnh (thiên là nghìn, niên là năm, kiện là khoẻ mạnh).\n\n','','','Tê thấp, kích thích tiêu hoá, bổ gân cốt và chữa đau bụng kinh (Thân rễ sắc uống). Mụn nhọt (Thân rễ giã đắp)',NULL,'','Chi Homalomena Schott gồm một số loài thân cỏ, phân bố chủ yếu ở vùng nhiệt đới châu Á và châu Mỹ. Ở khu vực Đông Nam Á có 7 loài, đều được dùng làm thuốc. Việt Nam có 6 loài, 4 loài được dùng làm thuốc:\n\nH. occulta (Lour.) Schott phân bố khá phổ biến ở các tỉnh vùng núi, cả ở miền Nam lẫn miền Bắc. Độ cao phân bố từ 300 đến 700 m hoặc hơn.\n\nH. gigantea Engl. có tên khác là thiên niên kiện lá to, được phát hiện ở xã Đinh Trang Hòa, Đinh Trang Thượng, huyện Di Linh, tỉnh Lâm Đồng; vùng rừng Suối Lạnh thuộc xã Hòa Thịnh, huyện Tuy Hòa, tỉnh Phú Yên và vùng rừng Khe Lết, Hương Sơn tỉnh Hà Tĩnh. Độ cao phân bố từ 100-600m, riêng ở Khe Lét đã trên 700m.',_binary '','','',NULL,'','Thân rễ thiên niên kiện có tác dụng ức chế yếu phù bàn chân chuột cống trắng gây bằng kaolin, không ảnh hưởng trên u bạch huyết nghiệm gây bằng amian, và gây thu teo tuyến ức chuột cống dục non mức độ yếu. Ngoài ra, dược liệu còn có các tác dụng như ức chế sự co thắt cơ trơn ruột chuột lang cô lập gây nên bởi histamin và acetylcholin, gây giãn mạch ngoại biên, và có tác dụng yếu ổn định màng hồng cầu in vitro. Liều chết LD₅₀ của thiên niên kiện cho chuột nhắt trắng nóng là 2,45 g/kg.\n\n','Thiên niên kiện','Thiên niên kiện, Bao kim, Vắt vẻo, Sơn thục, Trao yêng (Kho), Duyên (Bana), Ráy hương, Vạt hương (Tày), Hia hẩu ton (Dao)','thân rễ','DA_XUAT_BAN','Homalomena occulta','','thien-nien-kien',0,20,'Cụm hoa là một bông mo màu lục nhạt, không bao giờ mở rộng, dài 4–5 cm, rộng 10–15 mm; mỗi khóm thường có 3–4 bông mo, cuống bông mo dài 5–15 cm; bông ngắn hơn mo, chỉ dài 3–4 cm; phần mang hoa cái hình hậu dục chỉ dài bằng một nửa phần mang hoa đực, không có bao hoa; hoa đực có 4 nhị rời, chỉ nhị rất ngắn, bao phấn song song; hoa cái có nhị lép hình khối, dài bằng đầu nhuỵ, bầu hình trứng, điểm những chấm mờ, noãn nhiều.\n','Quả mọng, thuôn, chứa nhiều hạt có vân.\n','Lá mọc tập trung ở đầu thân rễ, có thể dài đến 30 cm, rộng 18 cm, thuỳ bên 6 cm, gốc hình tim sâu, toàn bộ lá nom giống hình tam giác, đầu nhọn, mép nguyên, gần ở gốc có 3 cái ở mỗi bên, toả rộng, hướng lên, gần bên múp ở mặt trên, mỗi bên 7–9 cái; cuống lá dài 27–30 cm, gốc cuống phình và xoè ra chiếm 1/3 cuống tính từ dưới lên.\n','','Cây thào to, thân rễ dài, mọc bò ngang, thẳng hay cong quẹo, có nhiều đốt, bề ra có vỏ cứng, mùi thơm.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765127250/xjxzgbf8gqmx00zmrwf6.jpg'),(231,'2025-12-07 17:15:40','1','2025-12-07 17:15:40','1',NULL,'','Tuỳ theo nguồn gốc, lô hội có thành phần hoá học khác nhau, nhưng căn bản có những chất sau đây:\n\nTinh dầu màu vàng, độ sôi 2660-271 cho lô hội mùi đặc biệt. Ít quan trọng về mặt tác dụng dược lý.\nNhựa 12-13%: Có tác giả cho rằng nhựa này không có tác dụng tẩy, nhưng cũng có tác giả cho rằng có tác dụng tẩy.\nHoạt chất chủ yếu là chất aloin. Aloin không phải là một chất thuần nhất mà là gồm những antraglucozit có tinh thể, vị đắng có tác dụng tẩy. Tỷ lệ aloin thay đổi tuỳ theo nguồn gốc lô hội.\nThông thường tỷ lệ đó là 16-20%. Perrier có định lượng aloin trong lô hội Việt Nam thì thấy tỷ lệ này lên tới 26%. Tuy nhiên cũng có tác giả không cho aloin là hoạt chất tẩy mạnh nhất, vì nhiều loại lô hội có cùng một lượng aloin mà lại có tác dụng tẩy khác nhau. Bên cạnh aloin có tinh thể, còn có những chất không có tinh thể và alocemođin tự do.\nTuỳ theo nguồn gốc lô hội, aloin mang tên khác nhau và có cấu tạo hơi khác nhau. Vídụ trong lô hội vùng nam châu Phi (Aloe des barbades) thì aloin gọi là bacbaloin. Bacbaloin thuỷ phân sẽ cho d.arabinoza và aloe.emodin-anthrano. Ngoài ra còn có iso.bacbaloin và pbacbaloin','','Lương can, nhuận tràng, lợi mật, nhuận gan, sát khuẩn, thông tiểu, thanh nhiệt, trẻ em cam tích, kinh giản, táo bón, ăn uống khó tiêu, tẩy (Nhựa nấu cao uống).',NULL,'','Lô hội dùng ở nước ta (cả đông y và tây y) chủ yếu là nhập của nước ngoài. Mặc dù nhập qua Pháp hay Trung Quốc cũng do một số nước sau đây:\n\nLoài Aloe vulgaris Lamk, ở bắc châu Phi, cực nam châu Á, Ấn Độ, cho lô hội ẤnĐộ. Tên trên thị trường quốc tế là Aloe des barbades. Aloe Curacao (Aloe des Inas.)\nLoài Aloe ferox L. và những loại lai của nó với các loài Aloe africana Mill., Aloespicata Thunb., Aloe perfoliata L. cho vị lô hội với tên Aloe du Cap.\nLoài Aloe perry I Bak. cho vi Aloe socotrin hay succotrin. Trong đông y rất chú ýphân biệt.\nTóm lại địa lý chủ yếu của lô hội là đông châu Phi (từ nam chí bắc đều có), Ấn Độ, Châu Mỹ.\nTại nước ta, cây lô hội mọc hoang ở bờ biển những tỉnh Ninh Thuận (Phan Rang,Phan Ri) và Bình Thuận, ở miền Bắc được trồng làm cảnh nhưng ít hơn.',_binary '','Đơn thuốc có lô hội\n\nViên nhuận tràng (xí nghiệp dược phẩm): 1 lô hội 0.08g, cao mật bò tinh chế 0,01, phenoltalein 0,05g, bột cam thảo 0,05g, tá dược vừa đủ một viên. Dùng chữa táo bón,khó tiêu thiếu nước mật, vàng da, yếu gan, yếu ruột. Ngày uống 1-2 viên vào bữa cơm chiều. Có thể dùng liều cao hơn.\n\nLưu ý : Trẻ em dưới 15 tuổi không dùng được.','',NULL,'','Lô hội là một vị thuốc được dùng cả trong đông y và tây y.\nTheo tài liệu cổ lô hội vị đắng tính hàn, vào 4 kinh can, tỳ, vị và đại tràng. Có tác dụng sát trùng, thông tiện, thanh nhiệt, lương can. Dùng chữa trẻ con cam tích, kinh giản, táo bón. Người tỳ vị hư nhược, sinh tả và phụ nữ có thai không dùng được.\nHiện nay với liều nhỏ dùng giúp sự tiêu hoá, ăn uống không tiêu.\nVới liều lớn dùng làm thuốc chữa những bệnh nhức đầu khó chữa, sung huyết phổi,sung huyết các phủ tạng.\nCòn dùng làm thuốc tẩy hay nhuận tràng. Nên dùng sau bữa ăn tác dụng sẽ dịu và mau hơn.Không dùng được cho trẻ con, phụ nữ có thai lòi dom.','Cây lô hội ','Lô hội, Hổ thiệt, Lưỡi hổ, Long tu, Tượng đởm, Lủ hội, Nha đảm','','DA_XUAT_BAN','Aloe vera','','cay-lo-hoi-',0,3,'Cụm hoa dài chừng 1m, mọc thành chùm dài mang hoa màu vàng xanh lục nhạt lúc đầu mọc đứng, sau rũ xuống, dài 3-4cm. Quả nang, hình trứng thuôn, lúc đầu xanh sau nâu và dai.','Quả nang, hình trứng thuôn, lúc đầu xanh sau nâu và dai.','Lá không cuống, mọc thành vành rất sít nhau, dày mẫm, hình 3 cạnh, mép dầy, mép có răng cưa thô cứng và thưa dài 30-50cm, rộng 5- 10cm, dày 1-2cm, ở phía cuống.','','',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765127667/lrnilmhxb7mnb9glphud.jpg'),(232,'2025-12-07 17:19:18','1','2025-12-07 17:19:18','1',NULL,'','','','Chữa cao huyết áp, phòng ngừa chứng đứt mạch máu não, ho ra máu, đái ra máu, đau mắt; còn chữa chảy máu cam, băng huyết, trĩ chảy máu, xích bạch lỵ (Nụ hoa hoặc quả).',NULL,'','',_binary '','','',NULL,'','','Hoa hòe','Hòe, Lài luồng (Tày), Hòe hoa, Hòe mễ','','DA_XUAT_BAN','Styphnolobium japonicum','','hoa-hoe',0,18,'Cụm hoa mọc ở đầu cành thành chum dài 20cm, phân nhánh nhiều; hoa nhỏ màu trắng hoặc vàng nhạt; đài hình chuông, gần như nhẵn; cánh hoa có móng ngắn, cánh cờ rộng, hình tim cụt ở gốc, mép cong lên; nhị 10 rời nhau; bao phấn hình bầu dục.\n','Quả đậu, hình tràng hạt, thắt lại không đều giữa các hạt, nhẵn, không mở, đều có mũi nhọn ngắn; hạt 2-5, hình bầu dục, hơi dẹt, màu đen bóng.\n','Lá kép lông chim lẻ, mọc so le, 11-17 lá chét mọc đối, hình bầu dục – thuôn, gốc tròn, đầu hơi nhọn, dài 3-4cm, rộng 1,2-2cm, màu lục nhạt, nhất là ở mặt dưới, hơi có lông.\n','','Cây nhỡ thường xanh cao 5-7m, có khi đến 10m. Thân có vỏ hơi nứt nẻ và cành nằm ngang. Cành hình trụ, nhẵn, màu xanh lục nhạt, có những chấm trắng.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765127954/mgrszlgoap8qzpvexi3w.jpg'),(233,'2025-12-07 17:22:44','1','2025-12-07 17:22:44','1',NULL,'','','','Chữa đau đầu, đau mắt, tê thấp, lợi tiểu, hoa lâu ngày (Hoa sắc hoặc ngâm rượu uống). vết thương sưng tấy (Lá, Hoa)',NULL,'','Cúc hoa vàng có nguồn gốc ở vùng Đông Á: Trung Quốc và Nhật Bản, được trồng làm thuốc và làm cảnh ở Trung Quốc, Triều Tiên, Nhật Bản, Việt Nam, Lào, Thái Lan và Ấn Độ.\n\nỞ Việt Nam, cúc hoa vàng được trồng từ lâu đời. Hiện nay cây có nhiều ở Hưng Yên, Hải Dương, Bắc Ninh, Hà Nội và một số tỉnh khác ở phía bắc. Cây ưa sáng và ưa ẩm, thường được trồng ở vườn, công viên hoặc trên cánh đồng với mục đích sản xuất dược liệu. Cây ra hoa nhiều hàng năm, hiếm có hạt. Mùa đông có hiện tương rụng lá hoặc hơi tàn lụi. Chính lúc này người ta thường cắt bỏ phần thân cành, giữ lại gốc để tái sinh hoặc làm giống trồng vào mùa xuân năm sau.',_binary '','','',NULL,'','Cúc hoa vàng hiện được trồng ở nhiều nơi, nhất là ở các làng hoa gần các thành phố lớn như Hà Nội, Hải Phòng, Nam Định.\n\nCây chủ yếu được nhân giống bằng phương pháp vô tính. Trước đây người ta thường tách khóm, vít cành. Hiện nay, phổ biến dùng phương pháp giâm cành. Vào tháng 4-5, chọn những cành khỏe, dùng dao sắc cắt lấy đoạn trên dài 10-15 cm, bỏ bớt lá ở phần dưới rồi giâm vào bản hoặc vườn ươm đặt dưới bóng râm và giữ ẩm. Sau khi cành giâm ra rễ, có thể đánh đi trồng. Có thể xử lý bằng các loại thuốc kích thích ra rễ có bán trên thị trường.\n\nĐất trồng tốt là đất phù sa, đất thịt nhẹ, tơi xốp, màu mỡ, thoát nước. Sau khi cày bừa kỹ, vơ sạch cỏ, để ải, lên thành luống cao 25-30 cm, rộng 0,8-1m. Dùng phân chuồng để bón lót theo hốc với lượng từ 15 – 30 tấn cho một hecta. Cây con được trồng với khoảng cách 35×35 hoặc 40×40 cm. Trồng xong cần tưới ngay và giữ ẩm thường xuyên cho tới khi bén rễ.\n\nKhi cây đã lớn, chỉ cần giữ độ ẩm vừa phải. Đất quá ẩm ướt để làm cho cây bị bệnh. Thường xuyên làm cỏ, xới xáo giữ cho đất tơi xốp. Trong thời kỳ cây phân cành, dùng nước phân chuồng, tốt nhất là phân bắc, hay nước giải ngâm kỹ để tưới thúc, mỗi tháng tưới một lần. Nén hạn chế dùng đạm vì đạm dễ làm thân lá sinh trưởng quá mạnh, ảnh hưởng xấu tới việc ra hoa và độ bền của hoa. Cần thường xuyên tỉa bỏ cành già, bấm ngọn để kích thích cây ra nhiều chồi..\n\nCúc hoa vàng thường bị sâu xám, rệp, muội phá hoại. Chú ý phát hiện kịp thời để trừ diệt. Sau khi trồng 4- 5 tháng, cúc hoa vàng bắt đầu cho thu hoạch hoa, tập trung vào các tháng cuối năm. Hiện nay, có những giống hoa vàng nhập nội ra hoa vào các thời điểm khác nhau. Tùy theo mức độ chăm sóc, có thể thu hoạch hoa được nhiều đợt hay ít đợt.','Cúc hoa vàng','Cúc hoa vàng, Kim cúc, Dã cúc, Cam cúc, Khổ ý, Hoàng cúc, Bióoc kim (Tày)','hoa','DA_XUAT_BAN','Chrysanthemum indicum','','cuc-hoa-vang',0,5,'Cụm hoa mọc thành đầu trên một cuống dài ở ngọn thân hoặc kẽ lá, đường kính 1-1,5cm, tổng bao lá bắc là những vảy thuôn dài, mép khô, hoa ở ngoài hình lưỡi nhỏ màu vàng, hoa ở giữa hình ống, không có mào lông, tràng hoa hình ống ngắn hơn tràng hình lưỡi, có thùy tam giác nhọn và cũng có màu vàng.\n','Quả bế.\n','Lá mọc so le, hình bầu dục, chia nhiều thùy sâu, mép có răng cưa nhọn không đều, mặt trên màu lục đen sẫm, mặt dưới nhạt, cuống lá ngắn, có tai ở gốc.\n','','Cây thảo, sống hàng năm hay sống dai, cao 20 – 50cm. Thân mọc thẳng, nhẵn, có khía dọc.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765128159/prwtbqkwrttodzup2wrf.jpg'),(234,'2025-12-07 17:28:27','1','2025-12-07 17:28:27','1',NULL,'','','','',NULL,'','Chi Acanthopanax (Decne. et Planch.) Miq. có khoảng hơn 10 loài, phân bố chủ yếu ở vùng Đông Á, bao gồm Viễn Đông Nga, Triều Tiên, Trung Quốc, Nhật Bản và Việt Nam. Một số loài có ở vùng Nam và Đông – Nam Á.\n\nỞ Việt Nam, chi này có 3 – 4 loài kể cả loài A. baviensis Vig. hiện chưa thu lại được mẫu vật. Trong số những loài đã biết, đáng chú ý có loài ngũ gia bì gai phân bố tương đối tập trung ở các tỉnh dọc theo biên giới phía bắc, như Lạng Sơn, (huyện Bắc sơn, Tràng Định, Cao Lộc, Văn Lãng, Văn Quan….); Cao Bằng (Quảng Hòa, Trùng Khánh, Hạ Lang, Hà Quàng, Trà Lĩnh…); Lai Châu (Phong Thổ, Sìn Hồ, Tủa Chùa….); Lào Cai (Sapa, Bắc Hà, Bát xát….); Hà Giang (Quảng Bạ); Sơn La. Ở những tỉnh khác, ngũ gia bì gai chỉ mới thấy có ở 1 – 2 điểm thuộc vùng núi Cao (trên 1000m), với số lượng quần thể không nhiều.\n\nNguồn ngũ bì gai ở Việt Nam tương đối phong phú theo kết quả điều tra trữ lượng vào các năm 1973 – 1987 ở Lạng Sơn, Cao Bằng và Lai Châu, đã xác định đến vài trăm tấn được liệu. Tuy nhiên, việc khai thác thường xuyên, với khối lượng không hạn chế suốt gần 40 năm qua, đã làm cho trữ lượng của cây giảm sút nghiêm trọng. Phạm vi phân bố của cây cũng bị thu hẹp do nạn phá rừng, mở mang canh tác nương rẫy và làm nơi định cư mới. Cây đã được đưa vào Sách Đỏ Quốc gia để lưu ý bảo vệ.',_binary '','','',NULL,'','Ngũ gia bì gai có tác dụng kích thích tâm thần. Trong thử nghiệm gây trạng thái trầm uất trên chuột nhắt trắng theo phương pháp Porsolt, ngũ gia bì gai cũng như tam thất và đinh lăng, có tác dụng làm giảm thời gian bất dộng của chuột. Nước sắc và dịch chiết cồn từ vỏ cây có các tác dụng làm tăng hoạt động tự nhiên của súc vật thí nghiệm, tăng khả năng bám trụ quay của chuột, rút ngắn thời gian gây ngủ của hexobarbital, tăng khả năng thiết lập phản xạ có điều kiện và tăng khả năng duy trì phản xạ có điều kiện. Ngoài ra, ngũ gia bì gai còn có khả năng tăng cường tác dụng gây co giật của Strychnin và pentetrazol.','Ngũ gia bì gai','Ngũ gia bì gai, Tam gia bì, Poót sinh, Poót tầng, Poót thông, Tùm sươu, Co nam slư (Thái), Mạy tảng nam, Póp tưn, Pót dinh (Tày)','vỏ, rễ','BAN_NHAP','Acanthopanax trifoliatus','','ngu-gia-bi-gai',0,30,'','Quả mọng, hình cầu dẹt, mang vòi tồn tại, đường kính khoảng 2,5 mm. Khi chín màu đen, có 2 hạt.\n','Cụm hoa mọc ở đầu cành, gồm 3 – 10 tán, có cuống dài 3 – 4 cm; hoa nhỏ, màu 5, màu trắng lục. Lá đài không rõ; cánh hoa hình tam giác; nhị 5, chỉ nhị mảnh; bầu hoa 2 ô.\n','','Cây bụi nhỏ, cao 1 – 7 m, mọc dựa. Cành vươn dài có gai. Lá kép chân vịt, mọc so le, gồm 3 – 5 lá chét, thường là 3, hình bầu dục hoặc thuôn, gốc tròn, đầu nhọn, dài 5 – 8 cm, rộng 2 – 4 cm. Lá chét giữa lớn hơn, mép khía răng to, gần lá có gai. Hai mặt nhẵn, mặt trên sẫm bóng; cuống lá kép dài 4 – 7 cm, có gai.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765128501/z1bzqbp7pj1mj6dowapp.jpg'),(235,'2025-12-07 17:34:10','1','2025-12-07 17:34:10','1',NULL,'','Lá Dâu chứa inokosteron, ecdysteron, morocetin, umbelliferon, scopoletin, scopolin, a-, b- hexenal, trigonellin và nhiều acid amin. Còn có chất cao su, tanin, caroten, vitamin C, pentozan, đường.\nVỏ rễ Dâu chứa các acid hữu cơ, tanin, pectin và những hợp chất flavonoid bao gồm morin, mulberrin, mulberronchromen, cyclomulberrin, cyclomulberrochromen.\nQuả Dâu chứa đường (glucose và fructose), acid malic và acid succinic, protein, tanin, vitamin C, caroten, sắc tố màu đỏ anthocyanidin.\nTổ bọ ngựa trên cây Dâu chứa protid, chất béo, muối sắt, calcium.','','Chữa phù thũng, dị ứng, ho, tê thấp (Vỏ rễ, cành). Thuốc an thần (Lá).',NULL,'','Nguyên sản của Trung Quốc, được trồng rộng rãi ở các nước châu Á. Đã được trồng ở nước ta từ lâu đời khi người ta biết nuôi tằm. Nhiều bộ phận của cây Dâu được thu hái làm thuốc. Có những bộ phận có thể thu hái quanh năm. Tầm gửi chỉ gặp ở những cây gỗ lớn. Dùng tổ bọ ngựa chưa nở, phải đồ chín rồi sấy khô.',_binary '','','',NULL,'','','Dâu tằm','Dâu tằm, Tang, Dâu tàu, Mạy mọn, Mạy bơ (Tày), Co mọn (Thái), Nằn phong (Dao), cây tang điệp','lá, vỏ, cành, quả','DA_XUAT_BAN','Morus alba','','dau-tam',0,11,'Hoa cùng gốc hay khác gốc, các hoa cái thành bông đuôi sóc hơi dài hơn rộng, nhưng không quá 2cm.\n','Quả trắng hay hồng, thuộc dạng quả phức gồm nhiều quả bế bao trong các lá đài đồng trưởng và trở thành mọng nước.\n','Lá mọc so le, phiến xoan dài 5-10 (20)cm rộng 4-8cm, gốc hình tim hay gần như cụt, chóp tù hay hơi nhọn, có thuỳ trên các nhánh tược còn non, có răng, với răng hình tam giác, tù, khía rộng; gân gốc 3, các gân bên đạt tới chiều dài của phiến.\n','','Cây gỗ lớn cao tới 15m, màu nâu hay vàng vàng.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765128843/twnrzbxmcuhimpoevjvw.jpg'),(236,'2025-12-07 17:39:10','1','2025-12-07 17:39:10','1',NULL,'Cây bạc hà Mentha arvensis L. còn có tên là bạc hà nam là một loại cỏ sống lâu năm,\nNgoài loài bạc hà mọc hoang dại ở nước ta, gần đây đã nhập một số chủng cùng loài có năng suất tinh dầu cao như BH 974 (đưa vào nước ta từ tháng 9-1974), BH 975 (đưa vào nước ta từ tháng 9-1975) và BH976 (xuất xứ từ Triều Tiên, đưa vào nước ta từ tháng 9-1976). Hai loại 974 và 975 được xác định thuộc loài Mentha haplocalyx Briq. (nhóm Mentha arvensis).\n','Hoạt chất chủ yếu trong bạc hà là tinh dầu bạc hà. Tỷ lệ tinh dầu trong bạc hà thường từ0,5 đến 1%, có khi có thể lên tới 1,3-1,5%. Bằng phương pháp lựa chọn giống, Liên Xô cũ đã có những loại bạc hà đạt tới 5,2 đến 5,6% tinh dầu (tính trên cây, đã trừ độ ẩm). Ngoài tinh dầu, trong cây bạc hà còn có các flavonozit.\nThành phần chủ yếu trong tinh dầu bao gồm những chất sau đây:\nMentola C10H19OH có trong tinh dầu với tỷ lệ 40-50%, loài của Trung Quốc và Nhật Bản có thể lên tới 70-90%. Mentola ở trong tinh dầu chủ yếu ở trạng thái tự do nhưng một phần ở dạng kết hợp với axit axetic.\nMentol C10H18O chừng 10 đến 20% trong tinh dầu bạc hà Trung Quốc.','','Thuốc làm nóng, sát trùng, dễ tiêu, chữa cảm cúm, nhức đầu sổ mũi, đau bụng (Lá).',NULL,'','Cây bạc hà mọc hoang và đuợc trồng tại nhiều vùng ở nước ta, mọc hoang cả ở miền đồng bằng và ở miền núi. Chúng tôi đã phát hiện mọc hoang nhiều ở Sapa (Lào Cai), Tam Đảo (Vĩnh Phúc), Ba Vì (Hà Tây), Bắc Cạn, Sơn La.\nSau 25 năm nghiên cứu của chúng tôi (1955- 1980) cây bạc hà trước đây chỉ mới được trồng trên quy mô tương đối lớn ở các làng Nghĩa Trai (Hưng Yên), Đại Yên (Hà Nội) và rải rác ở nhiều tình khác để lấy lá và cây làm thuốc. Đã bắt đầu được trồng để cất tinh dầu. Năm 1958 tại huyện Gia Lâm-Hà Nội, vườn trồng bạc hà thí điểm của trườmg Đại học Dược khoa Hà Nội đã được trang bị nồi cất tinh dầu. Năm 1972, cả nước ta lần đầu tiên đã tự sản xuất được 60 tấn tinh dầu bạc hà và sản xuất được một tấn menthol tinh thể.\nTại các nước khác, loài bạc hà này còn được thấy khai thác ở Trung Quốc (Hắc Long Giang, Cát Lâm, Quảng Đông, Quảng Tây, Phúc Kiến, Vân Nam v.v…), Nhật Bản (nổi tiếng vì tinh dầu chứa nhiều mentol nhất, 80-90%). Từ năm 1974, ở nước ta đã có chủng loại bạc hà Nhật Bản này.\nMuốn trồng bạc hà tốt nhất cần chọn nơi đất sét có nhiều mùn, sau đến loại đất cát. Đất cần làm cỏ bón phân kỹ trước, làm luống rộng, trên mỗi luống trồng 2-3 hàng. Có hai mùa trồng bạc hà vào mùa xuân và thu. Mùa xuân vào các tháng 2-3, mùa thu vào tháng 8-9. Tốt nhất là trồng vào mùa xuân cho năng suất cao nhất. Trồng bằng hạt hay bằng mẩu thân, hoặc thân ngầm. Có thể trồng bằng hạt nhưng rất ít áp dụng. Sau 3-4 tháng có thể thu hoạch đợt đầu, thường một năm có thể cắt cây 3 hay 4 lần, lần thứ nhất vào tháng 6-7, sau đó cần xới và bón phân, sau 2 tháng (vào cuối tháng 8 hay tháng 9) lại hái lần nữa vào lúc cây đang ra hoa nhiều. Nếu hái 4 lần thì có thể hái lứa đầu vào tháng 6-7, lứa thứ hai vào tháng 8-9, lứa thú ba vào tháng 10-11, lứa thứ 4: 2-3. Hái về, cần bó lại từng bó, phơi chỗ mát cho khô hoặc nếu cất tinh dầu thì cần cất ngay hay để hơi héo mà cất.',_binary '','','',NULL,'','Bạc hà là một vị thuốc thơm, dùng làm cho thuốc thơm dễ uống, làm ra mồ hôi, hạ sốt dùng chữa cảm sốt, cảm mạo, mũi ngạt, đầu nhức, còn giúp cho sự tiêu hoá, chữa kém ăn, ăn uống không tiêu, đau bụng đi ngoài.\nTinh dầu bạc hà và mentola dùng làm thuốc sát trùng, xoa bóp nơi sưng đau, như khớp xương, thái dương khi đầu nhức. Theo Lesieur và J. Meyer bạc hà là một vị thuốc chữa loét dạ dày, làm giảm bài tiết dịch vị và giảm đau.\nTính chất của bạc hà theo các tài liệu cổ ghi như sau: Vị cay, mát không độc, vào 2 kinh phế và can, có tác dụng tán phong nhiệt, ra mồ hôi, giảm uất, làm thuốc thanh lương dùng chữa cảm nắng (trúng thử), đau bụng, bụng đầy, chứng ăn không tiêu. Liều dùng lá và toàn cây: Ngày uống từ 4 đến 8g dưới dạng thuốc pha. Tinh dầu và mentola: Một liều 0,02 đến 0,2ml, một ngày 0,06 đến 0,6ml.\nCòn dùng dưới hình thức cồn bạc hà (lá bạc hà 50g, tinh dầu bạc hà 50g, cồn vừa đủ 1 lít), ngày dùng nhiều lần, mỗi lần từ 5 đến 10 hay 15 giọt, cho vào nước nóng mà uống.','Bạc hà','Bạc hà, Nạt nặm, Bạc hà nam, Chạ phiăc chom (Tày)','','DA_XUAT_BAN','Mentha arvensis','','bac-ha',0,6,'Hoa mọc vòng ở kẽ lá, cánh hoa hình môi màu tím hay hồng nhạt có khi màu trắng.\n','Ít khi thấy có quả và hạt.\n','Lá mọc đối, cuống dài từ 2 đến 10mm, phiến lá hình trứng hay thon dài, rộng 2-3cm, dài 3-7cm, mép có răng cưa, mặt trên và mặt dưới đều có lông che chở và lông bài tiết.\n','','Thân cây cao từ 10 đến 60-70cm, có thể cao tới 1m, thân vuông mọc đứng hay hơi bò, có khi phân nhánh, trên thân có nhiều lông.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765129147/iogqdwzawrghyqtgfjef.jpg'),(237,'2025-12-07 17:42:45','1','2025-12-07 17:42:45','1',NULL,'','Từ dừa cạn người ta chiết được các chất sau đây: axit pyrocatechic, sắc tố flavonic (glucozit của quercetol và campferol) và anthocyanic từ thân và lá dừa cạn hoa đỏ (theo Forsyth và Simmonds, 1957). Ngoài ra từ lá người ta còn chiết được axit ursolic và rễ chiết được cholin.\n\nNăm 1969, Battersby và cộng sự còn được chiết được chất vicosid, một glucoalcaloir tiền thân để sinh tổng hợp các ancaloit. Hiện nay người ta đã xác định hoạt chất của dừa cạn là những ancaloit có nhân indol có trong tất cả các bộ phận của cây, nhiều nhất trong rễ và lá Tùy theo nơi thu hái, hàm lượng các ancaloit này thay đổi từ 0,2-1%. Và có thể có những giống có hàm lượng cao hơn.','','Chữa đái đường, đái ra máu (Thân). Sốt rét (Rễ). Thuốc hạ huyết áp, điều kinh, lọc máu (cả cây sắc uống).',NULL,'','Mọc hoang dại và được trồng ở nhiều nước nhiệt đới như Việt Nam, Ấn Độ, Indonexia, Philipin, Châu Phi, châu Úc, Braxin..tại châu Âu và châu Mỹ ở những vùng nóng cũng trồng quanh năm, nhưng ở những vùng lạnh cây được trồng hàng năm vì không chịu được lạnh.\nỞ Việt Nam gặp nhiều nhất tại các tỉnh gần biền, nhưng khắp nơi đều trồng được, trước đây chỉ được trồng làm cảnh, gần đây đã được trồng để thu hoạch lấy cây, lá và rễ chế thuốc.',_binary '','','',NULL,'','Dừa cạn được dùng để thông tiểu tiện, chữa bệnh đi tiểu đỏ và ít, bị bế kinh, huyết áp cao, tiêu hóa kém\n\nTheo kinh nghiệm sử dụng trong y học dân tộc của một số nước khác có cây này mọc hoang dại, rễ dừa cạn có tác dụng tẩy giun, chữa sốt. Thân và lá có tính chất săn da (astringent), lọc máu (depuratif), dùng chữa một số bệnh ngoài da và nhất là chữa đái đường Kinh nghiệm dùng dừa cạn chữa bệnh đái đường được ghi nhận ở Ấn Độ, châu Úc, nam châu Phi, quần đảo Antilles nhưng chứng minh bằng thực tế khoa học thì chưa có.','Dừa cạn','Dừa cạn, Bông dừa, Hoa hải đằng, Trường xuân hoa, Phiắc pót đông (Tày)','toàn thân','DA_XUAT_BAN','Catharanthus roseus','','dua-can',0,3,'Hoa mọc trắng hoặc hồng, mùi thơm, mọc riêng lẻ ở các kẽ lá phía trên\n','Quả gồm 2 đại, dài 2-4cm, rộng 2-3mm, mọc thẳng đứng, hơi ngả sang hai bên, trên vỏ có vạch dọc, đầu quả hơi tù, trong quả chứa 12-20 hạt nhỏ màu nâu nhạt, hình trứng, trên mặt hạt có các hột nổi, thành đường chạy dọc.\n','Lá mọc đối, thuôn dài, đầu lá hơi nhọn, phía cuống hẹp nhọn, dài 3-8cm, rộng 1-2,5cm.\n','','Cây nhỏ cao 0,4-0,8m, có bộ rễ rất phát triển, thân gỗ ở phía gốc mềm ở phần trên. Mọc thành bụi đầy, có cành đứng.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765129362/hext5xt0sudrpzbho9yf.jpg'),(238,'2025-12-07 17:45:52','1','2025-12-07 17:45:52','1',NULL,'','Trong lá trầu không có 0,8-1,8%, có khi đến 2,4% tinh dầu tỷ trọng 0,958-1,057 thơm mùi creozot (củi đốt), vị nóng. Trong tinh dầu người ta đã xác định có hai chất phenol là betel-phenol (đồng phân với chất eugenol chavibetol C10H12O2 và chavicol), kèm theo một số hợp chất phenolic khác.\nHoạt chất khácchưa rõ.','',' Ho, khó thở, sát trùng vết thương, viêm chân răng có mủ, chàm mặt (Lá).',NULL,'','Cây trầu không được trồng ở khắp nơi trong nước ta để lấy lá ăn trầu. Nó còn được trồng tại nhiều nước khác ở châu Á, vùng nhiệt đới như Malaixia, Inđônêxya, Philipin.\nLàm thuốc người ta cũng dùng lá trầu không hái như đối với lá dùng ăn trầu.',_binary '','Chúng ta giới thiệu sau đây đơn thuốc dùng lá trầu không để chữa các vết lở loét, mụn nhọt, vết chàm của trẻ em mới đẻ.\n\nLá trầu không tươi: 2 hoặc 3 lá, cắt thật nhỏ, cho vào một cốc con. Dội nước sôi vào cho vào cho ngập lá trầu không. Làm như khi ta pha chè. Đợi chừng 10 – 15 phút cho chất thuốc trong lá trầu thôi ra nước. Dùng nước này rửa các vết loét, vết chàm, mụn nhọt.\nNgày làm như vậy 2 hoặc 3 lần, nếu vết loét rửa bằng lá trầu không, còn có nước vàng rỉ ra thì có thể dùng giấy bản đốt lấy tro mà đắp vào. Rất chóng khỏi.\nNếu vết loét quá to, thì có thể dùng số lượng lá trầu không nhiều hơn.\nĐáng lẽ pha thuốc như trên, ta có thể đem lá trầu không đun với nước cho sôi kỹ để ấm mà dùng','',NULL,'Ngoài công dụng dùng để ăn trầu (lá trầu không, vôi, cau và vỏ cây), nhân dân nhiều nơi còn dùng lá trầu không giã nhỏ, cho thêm nước sôi vào rồi dùng rửa những vết loét, mẩn ngứa, viêm mạch hạch huyết.\nNước pha lá trầu không còn được dùng làm thuốc nhỏ mắt chữa viêm kết mạc, chữa bệnh chàm mặt của trả em. Ít dùng trong. Chỉ hay dùng ngoài, liều lượng tuỳ tiện.\nCó nơi còn giã lá trầu không đắp lên ngực để chữa ho hen, hoặc đắp lên vú để cho sữa không ra nữa.','Ít có tài liệu nghiên cứu. Năm 1956, Bộ môn ký sinh Trường đại học y dược Hà Nội có nghiên cứu thấy trầu không có tác dụng kháng sinh rất mạnh đối với các loại vi trùng: Tụ cầu, subtilit và trực trùng Coli (Y học tạp chí số 4, tháng 11/1956).\nNăm 1961, Phòng đông y thực nghiệm thuộc Viện vi trùng học cũng thí nghiệm lại và cũng xác định tính chất kháng sinh bay hơi của lá trầu không.\nMột số bệnh viện của ta đã dùng cao nước trầu không thí nghiệm điều trị bệnh viêm cận răng (paradentose) có kết quả.','Trầu không','Trầu không, Trầu lương, Trầu cay, Thổ lâu đằng, Phù lưu, Mjầu (Tày), Lau (Dao)','lá','DA_XUAT_BAN','Piper betle','','trau-khong',0,18,'Hoa khác gốc mọc thành bông.\n','Quả mọng không có vòi sót lại.\n','Trầu không là một loại cây mọc leo, thân nhẵn.\n','','Trầu không là một loại cây mọc leo, thân nhẵn.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765129543/vqsfp1b1kdlvqogagvys.jpg'),(239,'2025-12-07 17:49:44','1','2025-12-07 17:49:44','1',NULL,'','Thành phần chủ yếu của gỗ, lá và rễ long não là tinh dầu và long não tinh thể. Tùy theo tuổi cây, hàm lượng tinh dầu và long não tinh thể thay đổi:\nLong não thiên nhiên, có tinh thể màu trắng, mùi thơm đặc biệt, vị nóng, ở nhiệt độ thường, long não thăng hoa được, ít tan trong nước, tan nhiều trong các dung môi hữu cơ (cồn, ête, clorofoc), quay phải + 43°. Tính chất long não là một xeton.\nTinh dầu long não cất phân đoạn sẽ được tinh dầu long não trắng (dùng chế xineola), tinh dầu long não đỏ (chứa safrola, cacvacrola), tinh dầu long não xanh (chứa cadinen, camphoren, azulen).','','Tất cả các bộ phận của cây đều mang những tế bào chứa tinh dầu. Tuy nhiên có cây cho long não đặc biệt, có cây chỉ cho tinh dầu lỏng. Việc phân biệt hai cây long não cho long não đặc và cây long não chỉ cho tinh dầu rất khó nếu chỉ căn cứ vào hình thái thực vật. Hạt của cùng một cây cho long não đặc, khi trồng lại cho những cây cho long não đặc và những cây chỉ cho tinh dầu, giống như hạt của cùng một cây đu đủ cái khi trồng có thể cho khi thì là cây đu đủ đực khi thì là cây đu đủ cái .',NULL,'','Cây long não được trồng tại nhiều tỉnh ở miền Bắc nước ta như Hà Giang, Tuyên Quang, Vĩnh Phú, Phú Thọ, Cao Bằng, Lạng Sơn. Ngay tại nhiều đường phố Hà Nội cũng trồng để lấy bóng mát. Người ta cho rằng vốn dĩ cây này không có ở Việt Nam, vì không thấy nó mọc ở rừng. Những cây thấy mọc ở rừng và có mùi gần như long não thuộc những loài như Cinnamomum parthenoxylon Neissn (rè hương-vù hương), C. balansae H. Lee., C. ilicioides A. Chev., (gù hương), C. simondii H. Lee. v.v… Hiện nay ta đã bắt đầu khai thác long não ờ các tỉnh Hà Giang, Tuyên Quang, Yên Bái, Lào Cai. Nhưng long não mọc nhiều nhất tại Nhật Bản, Trung Quốc. Người ta cất gỗ, rễ, lá cây long não, để lấy tinh dầu và tinh thể long não. Đôi khi dùng một ít gỗ hay lá, cành để cho vào nồi nước xông chữa cảm cúm.',_binary '','','',NULL,'','Long não được dùng ngoài làm thuốc sát trùng, tiêu viêm, kích thích (dùng dưới dạng cồn hay dầu 5-10%). Dùng trong dưới dạng thuốc tiêm để hồi tỉnh cơ tim, chữa trụy tim hay suy nhược, hoặc dùng uống để chữa đau bụng, làm giảm lượng phân (uống mỗi ngày 0,05-0,20g, tiêm da dưới dạng dung dịch dầu 10-20%).\nLong não còn dùng trong công nghiệp chế ngà voi nhân tạo, phim ảnh, chất cách điện.\nTinh dầu long não có thể dùng ngoài xoa bóp thay long não đặc, hoặc dùng trong công nghiệp làm dung môi, hoà tan nhựa, sơn, chiết safrol, xineol, chế thuốc trừ sâu.\n','Long não','Long não, Dã hương, Chương não, Mạy khao chuông (Tày), Cà chăng diẳng (Dao)','toàn thân','DA_XUAT_BAN','Cinnamomum camphora','','long-nao',0,43,'Hoa nhỏ, mọc thành chùy ở kẽ, ngắn hơn lá.\n','Quả hình cầu, to bằng hạt tiêu, phía dưới có cuống nhỏ hình chén.\n','á mọc so le, hình bầu dục gân chính nổi rõ, hai bên có gân phụ nổi, tại góc gân phụ và gân chính có một hạch tuyển nổi, bóng; cuống lá dài 2,5-3,5cm.\n','','Cây thân gỗ cao 10-15m hay hơn tới 40-50m, đường kính thân có thể đạt hơn 2m, cành thưa nhẵn, l',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765129780/gnhoneetjn4aqxdt8hhq.jpg'),(240,'2025-12-07 17:53:49','1','2025-12-07 17:53:49','1',NULL,'','','','Công dụng: Cảm lạnh, khó tiêu, ỉa chảy, sát trùng (Vỏ sắc hoặc ngâm rượu uống).',NULL,'','Cinnamomum Blume là một chi lớn gồm khoảng 270 loài, hầu hết là cây gỗ; phân bố tập trung ở vùng nhiệt đới châu Á. Ở Ấn Độ có 20 loài; Trung Quốc 12 loài và Việt Nam 40 loài. Ở Việt Nam, nhiều loài mang tên quế, trong đó, có 3 loài là cây trồng, còn lại là mọc hoang dại.\n\nQuế có nguồn gốc ở Việt Nam, cách đây khoảng hơn 2000 năm, các triều đại phong kiến đã coi “quế Giao Chỉ” (Giao Chỉ là tên nước Việt cổ) như là sản vật quý để trao đổi và triều cống (Lê Trần Đức, 1990). Nhiều vùng quế đã được hình thành từ lâu đời ở Yên Bái; Quảng Ninh; Thanh Hoá (Thường Xuân); Quảng Nam (Trà My, Phước Sơn) và Quảng Ngãi (Trà Bồng)…\n\nQuế là cây gỗ ưa sáng và chịu bóng, nhất là thời kỳ cây còn nhỏ (1-5 năm).\nCây ưa khí hậu nhiệt đới nóng và ẩm, nhiệt độ trung bình năm cho cây sinh trưởng phát triển mạnh là 22 – 23°C; độ ẩm không thí trung bình khoảng 80%; lượng mưa hàng năm khoảng 1.600 mm hoặc hơn.\nCây mọc được trên nhiều loại đất ẩm, nhiều mùn và tơi xốp, pH : 4,5 – 5,5. Quế có bộ rễ cọc khoẻ, cắm sâu xuống đất nên ít bị đổ khi có gió bão.',_binary '','','',NULL,'','Tinh dầu quế chứa cinnamaldehyd là thành phần chủ yếu có tác dụng diệt khuẩn in vitro đối với một số vi khuẩn ở độ pha loãng cao.\n\nTác dụng kháng khuẩn đối với các giống vi khuẩn khác nhau, theo thứ tự hoạt tính giảm dần : Salmonella typhi, tụ cầu vàng, Bacillus mycoides, Bacillus subtilis, Candida albicans, Shigella ßexneri, liên cầu khuẩn tan máu, trực khuẩn lao, Sh. dysenteriae, phế cầu khuẩn.\nTác dụng mạnh đối với phẩy khuẩn tả, nồng độ ức chế tối thiểu đối với các giống phẩy khuẩn tả Eltor, Inaba và Ogawa là 2/10.000.\nTác dụng diệt Entamoeba moshkowskii với nồng độ ức chế tối thiểu 1/2.560. Còn có tác dụng ức chế cả đối với siêu vi khuẩn.\nTác dụng ức chế tương đối yếu hơn đối với các giống vi khuẩn : Sh. shigae, Sh. sonnei, trực khuẩn coli, trực khuẩn mủ xanh.\nTinh dầu quế có tác dụng diệt nấm với Trichophyton mentagrophytes. Hoạt chất cinnamaldehyd có tác dụng với Microsporum audouini, Aspergillus nidurans, Cryptococcus neoformans, Penicillium rugulosum, Sporothrix schenckii, Trichophyton rubrum, T.mentagrophytes T.violaceum, Microsporum gypseum, Histoplasma capsulation và Blastomyces dermatitidis; tác dụng ức chế chủ yếu do phản ứng của aldehyd với các nhóm thiol tham gia vào sự sinh trưởng của nấm.\nTác dụng ức chế và kích thích trung tâm của cinnamaldehyd có thể do tương tác với các nơron đáp ứng với monoamin ở hệ thần kinh trung ương, và có vai trò quan trọng trong tác dụng điều trị của vỏ thân hoặc cành quế.','Quế','Quế đơn, Quế bì, Quế Trung Quốc, Nhục quế, Mạy quẻ (Tày), Kía (Dao)','vỏ cây','DA_XUAT_BAN','Cinnamomum cassia','','que',0,43,'Cụm hoa mọc ở kẽ lá gần đầu cành thành chùy dài 7-15cm; bao hoa gồm 6 phiến gần bằng nhau, màu trăng, dài 3mm, mặt ngoài có lông nhỏ.\n','Quả hạch, hình trứng hoặc hình bầu dục, có cạnh dài 1,2 – 1,3cm, nằm trong đài tồn tại nguyên hoặc chia thùy. Vỏ và lá vò ra có mùi thơm.\n','Lá mọc so le, dày cứng và dai, hình mác, dài 12 – 25cm, rộng 4-8cm, gốc thuôn, đầu nhọn, mặt trên nhẵn, màu lục sẫm bóng, mặt dưới màu xám tro, hơi có lông lúc còn non; gân 3, hình cung, nổi rõ ở mặt dưới, gân bên kéo dài đến đầu lá, gân phụ nhiều, song song; cuống lá to, dài 1,5-2cm, có rãnh ở mặt trên.\n','','Cây to, cao 10 – 20m. Cành hình trụ, nhẵn, màu nâu.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765130020/bwtpmmc2swpzkk7tcimu.jpg'),(241,'2025-12-07 17:57:17','1','2025-12-07 17:57:17','1',NULL,'','Trong quả hồi ngoài các chất như chất nhầy, đường, chủ yếu chứa tinh dầu từ 3- 3,5% (tươi) hoặc 9-10% hay hơn (khô). Tinh dầu hồi là một chất lỏng không màu, hay vàng nhạt, tỷ trọng ở +15°c từ 0,980 đến 0,990, độ đông đặc từ 14 – 18°C. Trong tinh dầu có 80-90% anethol, còn lại là tecpen, pinen, dipenten, limonen, estragola, safrola, tecpineola v.v…\nLá hồi cũng chứa tinh dầu với thành phần gần tương tự. Độ đông đặc hơi thấp hơn (13- 14°C), nhưng nếu trộn cả tinh dầu lá và tinh dầu quả thì ta được một tinh dầu có độ đông vào khoảng 10°C.','','Hồi có vị cay, mùi thơm, tính ấm vào 4 kinh can, thận, tỳ, vị có tác dụng trừ hàn, khai vị, kiện tỳ, chống nôn, chỉ thống, trừ phong, sát trùng.\n\n',NULL,'','Cây hồi đặc biệt chỉ mọc trong một khu vực nhỏ chiếm khoảng 5.000km2 ởtỉnh Cao Bằng, Lạng Sơn, một số ít ở hai tỉnh Quảng Tây và Quảng Đông (Trung Quốc) giáp giới Việt Nam. Một số nơi khác cũng có trồng nhưng không đáng kể như Hà Giang, Tuyên Quang, Bắc Cạn, Thái Nguyên. Trước đây người ta thường lẫn nó với cây hồi Nhật Bản Illicium anisatum Lour, có chất độc, hoặc cây hồi núi cũng có chất độc.\n\nHồi hái vào hai vụ tháng 7-8 (hồi mùa) và 11- 12 (hồi chiêm). Ngoài hai vụ chính, còn một vụ quả lép rụng sớm vào tháng 3. Hồi hái về phơi nắng cho khô hẳn. Dùng cất tinh dầu hay tiêu thụ nguyên quả làm thuốc.\n\nMỗi cây hàng năm cho từ 80-100kg quả tươi và như vậy luôn trong 40-50 năm. Thường một năm được mùa, một năm kém. Trên thị trường người ta chia hồi thành ba loại.\n\nLoại 1: có 8 cánh to đều nhau, màu nâu đỏ (hồi đại hồng).\nLoại 2: có 1 cánh trở lên bị lép, màu nâu đen.\nLoại 3: có 3 cánh trở lên bị lép, màu nâu đen.\nLoại hồi xô gồm lẫn lộn cả 3 loại trên.',_binary '','Chữa trúng phong, bại liệt một bên mình: Hồi 12g, quế chi 20g, đinh hương, rau sam, dây bìm bìm, cây nghệ, lá cây dâu gió, xương bồ, huyết giác đều 12g. Tán nhỏ trộn với một bát rượu và một bát nước tiểu dùng xoa bóp.\nChữa phong thấp: Hồi, hồ tiêu, phèn chua, đều bằng nhau. Giã nhỏ, xoa bóp vào chỗ đau.\nChữa đau tức ngực,  toát mồ hôi lạnh: Hồi, ô dược, thanh bì, riềng, các vị đều nhau. Sao (trừ hồi và ô dược), tán nhỏ, uống với rượu đun nóng và đồng tiện.\nChữa đau lưng: Hồi (bỏ hạt) tẩm với nước muối sao, tán nhỏ. Mỗi lần uống 6-10g với rượu. Ngoài dùng lá ngải cứu trườm nóng vào lưng.\nChữa đau rang: Hồi, phèn chua, sáp ong, cà gai leo, lượng bằng nhau, muối một ít. Sắc lấy nước ngâm.\nChữa sai khớp bong gân: Cao dán gồm những thành phần như tinh dầu hồi, quế, menthol, camphor, ngải cứu, cúc tần','',NULL,'','Hồi là một vị thuốc được dùng trong cả đông y và tây y.\n\nTây y dùng hồi làm thuốc trung tiện (carminatii), giúp tiêu hoá, lợi sữa. Tác dụng trên hệ thống thần kinh và cơ (dịu đau, dịu co bóp) được dùng trong đau dạ dày, đau ruột và trong những trường hợp dạ dày và ruột co bóp quá mạnh. Ngoài ra còn được dùng làm rượu khai vị, làm thơm thuốc đánh răng. Tuy nhiên nếu dùng nhiều và với liều cao quá sẽ gây ngộ độc, với hiện tượng say, run chân tay, sung huyết não và phổi, trạng thái ngay có khi tới co giật như động kinh.\n\nTheo tài liệu cổ đại hồi có vị cay, tính ôn, vào 4 kinh can, thận, tỳ và vị. Có tác dụng đuổi hàn, kiện tỳ, khai vị, dùng chữa nôn mửa, đau bụng, bụng đầy chướng, giải độc của thịt cá. Những người tán hư, hoà vượng không đùng được.\n\nThường dùng hiện nay làm thuốc giúp sự tiêu hoá, ăn uống không tiêu, nôn mửa, đau nhức tê thấp. Mỗi ngày dùng 4 đến 8g dưới dạng thuốc sắc. Dùng ngoài ngâm ruợu xoa bóp chữa đau nhức, tê thấp.\nNgoài ra hồi còn được dùng làm gia vị, chế húng lìu nấu thịt bò, các thịt khác. Những vị thuốc khác mang tên hồi','Hồi','Hồi, Mạy chác, Mác hồi (Tày), Bát giác hồi hương, Hồi sao, Pít cóc (Dao)','lá, cuống, hoa, quả','DA_XUAT_BAN','Illicium verum ','','hoi',0,18,'Hoa khá to, mọc đơn độc ở kẽ lá, cánh hoa màu trắng ở phía ngoài, hồng thắm ở mặt trong.\n','Quả hồi (nhân dân vẫn gọi nhầm là hoa hồi) tiếng Thổ là mác hồi hay mác chác gồm 6-8 đại (cánh), có khi tới 12-13 đại xếp thành hình ngôi sao, đường kính trung bình 2,5-3cm, dày 6-10mm. Tươi có màu xanh, khi chín khô cứng thì có màu nâu hồng. Trên mỗi đại sẽ nứt làm hai, để lộ một hạt màu nâu nhạt, nhẵn bóng.\n','Lá mọc gần thành chùm 3-4 lá ở đầu cành, có cuống, phiến lá nguyên, dài 8-12cm, rộng 3-4cm, dòn, vò nát có mùi thơm.\n','','Hồi là một cây nhỡ cao 2-6m, hình dáng toàn cây thon hình quả trám, xanh tốt quanh năm, thân mọc thẳng, cành dễ gẫy.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765130232/aoruatn9wc1clskyj5jn.jpg'),(242,'2025-12-07 18:02:54','1','2025-12-07 18:02:54','1',NULL,'','','','Thuốc kích thích tuần hoàn, lợi trung tiện. Chữa đau bụng (Tinh dầu).',NULL,'','',_binary '','','',NULL,'','Làm gia vị, chữa đau bụng\n','Đại hồi','Hồi, Mạy chác, Mác hồi (Tày), Bát giác hồi hương, Hồi sao, Pít cóc (Dao)','','DA_XUAT_BAN','Illicium verum','','ai-hoi',0,18,'','','','','',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765130571/xppanfzuudvlug1fsoyz.jpg'),(243,'2025-12-07 18:05:47','1','2025-12-07 18:05:47','1',NULL,'','Trong toàn cây chủ yếu có tinh dầu, mùi thơm.\nLá chứa 2,9% protein.\n100g cúc tần tươi có 5,7g protit, 1g lipit, 5,1g xenluloza, 2,3g tro, 179mg Canxi, 2,3mg P, 0,5mg Fe, 4,6g caroten, 15mg vitamin C.','','',NULL,'','Cây mọc hoang dại và được trồng ở hầu hết các tỉnh nước ta, đồng bằng cũng như bờ biển. Thường trồng làm hàng rào cây xanh, vừa lấy lá làm thuốc.\n\nThu hái:\n\nThường thu hái lá non và lá bánh tẻ. Dùng tươi hay phơi hoặc sấy khô làm thuốc.\nNgười ta đào cả rễ, rửa sạch, thái mỏng phơi hay sấy khô.',_binary '','','',NULL,'Lá và rễ cây cúc tần có những tác dụng dược lý như sau:\n\nChống viêm cấp tính trên mô hình gây phù thực nghiệm chân chuột cống trắng khá mạnh.\nChống viêm mạn tính trên mô hình gây u hạt thực nghiệm dưới da chuột cống trắng yếu.\nGây thu teo tuyến ức chuột cống non.\nHạ nhiệt rõ rệt đối với mô hình gây sốt thực nghiệm.\nGiảm đau trên mô hình gây quặn đau với acid acetic.',' Chữa ho, cảm sốt, nhức đầu, sốt xuất huyết (Lá). Cả cây dùng chữa cảm mạo, nóng không ra mồ hôi, bí tiểu tiện; phong tê bại, đau nhức xương, đau thắt lưng; trẻ em ăn uống chậm tiêu.','Cúc tần','Cúc tần, Từ bi, Cây lức, Phật phà, Vật và (Tày)','Cành, lá non và rễ.','DA_XUAT_BAN','Pluchea indica','','cuc-tan',0,18,'Hoa hình đầu có cuống ngắn, màu tím nhạt, nhóm họp thành 2-3 cái. Lá bắc 4-5 dãy, hoa lưỡng tính nhiều. Mào lông màu trắng bẩn. Tràng hoa cái mảnh, 4 răng nhỏ. Tràng hoa lưỡng tính phình to ở đỉnh, có 5 thùy. Nhị 5, bao phấn có tai, hình dùi, bầu hơi có lông.\n','Quả bế hình trụ-thoi, 10 cạnh.\n','Lá gần hình bầu dục, hơi nhọn đầu, gốc thuôn dài, có răng cưa ở mép, mặt dưới có lông mịn, phiến dài 4-5cm, rộng 1-2,5cm. Cụm hoa mọc thành ngù ở ngọn.\n','','Cây nhỏ cao 2-3m, cành gầy, lúc đầu có phủ lông, sau nhẵn.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765130742/vhzfguu3nra5lk5by9hk.jpg'),(244,'2025-12-07 18:08:56','1','2025-12-07 18:08:56','1',NULL,'','','','Xạ đen thuộc loại cây dây leo thân gỗ, mọc thành búi, thân cây dạng dây dài từ 3-10m, cành tròn. Lúc non có màu xám nhạt, sau chuyển sang màu nâu, về sau có màu xanh.\nLá mọc so le, phiến lá bầu dục, hình xoan ngược, dài 7-12cm, rộng 3-5cm, dai, gân bên 7 đôi, mép có răng tháp, cuống lá 5-7mm.\nChùm hoa ở ngọn hay nách lá, dài 5-10cm, cuống hoa 2-4mm, hoa mẫu 5 cánh, cánh hoa trắng. Hoa cái có bầu 3 ô.\nQuả hình trứng, dài 1cm, khi chín có màu vàng và tách ra thành 3 mảnh, hạt có áo hạt màu đỏ hồng.\nMùa hoa: tháng 3-5, mùa quả: tháng 8-12',NULL,'','Cây mọc ở vùng thấp với độ cao 1000-1500m. Phân bố ở các nước Trung Quốc, Việt Nam, Myanmar. Ở Việt Nam, cây Xạ đen Châu âu (Celastrus hindsii) rất hiếm gặp trong tự nhiên. Phân bố rải rác ở Hà Nam, Ninh Bình, Quảng Ninh, vườn quốc gia Cúc Phương, Thừa Thiên Huế, Tây Nguyên…',_binary '','','',NULL,'','Hỗ trợ điều trị ung thư, chống oxy hóa, tăng cường sức đề kháng, tăng miễn dịch, chống viêm nhiễm, làm giảm huyết áp, phòng chống vữa xơ động mạch...','Xạ đen','Xạ đen châu Âu, Xạ đen, Cây dây gối Ấn độ, Thanh giang đằng','','DA_XUAT_BAN','Celastrus hindsii ','','xa-en',0,18,'Chùm hoa ở ngọn hay nách lá, dài 5-10cm, cuống hoa 2-4mm, hoa mẫu 5 cánh, cánh hoa trắng. Hoa cái có bầu 3 ô.\n','Quả hình trứng, dài 1cm, khi chín có màu vàng và tách ra thành 3 mảnh, hạt có áo hạt màu đỏ hồng.\n','Lá mọc so le, phiến lá bầu dục, hình xoan ngược, dài 7-12cm, rộng 3-5cm, dai, gân bên 7 đôi, mép có răng tháp, cuống lá 5-7mm.\n','','Xạ đen thuộc loại cây dây leo thân gỗ, mọc thành búi, thân cây dạng dây dài từ 3-10m, cành tròn. Lúc non có màu xám nhạt, sau chuyển sang màu nâu, về sau có màu xanh.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765130929/dragkf7mq0mtiun1cav9.jpg'),(245,'2025-12-07 18:12:39','1','2025-12-07 18:12:39','1',NULL,'','Trong lá có chứa tới 20% tannin là một chất có tác dụng làm săn da, sát khuẩn mạnh. Ngoài ra còn cafein với tỷ lệ 1,5-5%, một số vitamin B1, B2,C\nĐặc biệt tannin trong chè có tác dụng như một vitamin P vì đây là hỗn hợp của các catechin và dẫn xuất của catechin có cấu trúc hóa học của vitamin P.','','',NULL,'','Chi Camellia L. có khảng 45 loài, thường là những cây bụi hay cây gỗ, phân bố vùng nhiệt đới và cận nhiệt đới.\n\nChè là một cây có nguồn gốc Trung quốc. Nhân dân Trung quốc đã biết dùng chè từ 2.500 năm trước công nguyên, sau tới Nhật bản và nhiều nước Châu á khác. Hiện nay cây chè được trồng ở nhiều nước. Liên xô cũ cũng rất phát triển việc trồng chè. Ở nước ta chè được trồng nhiều nhất tại các tỉnh Phú Thọ, rồi tới Tuyên Quang, Hà giang, Thái Nguyên, các tỉnh miền Nam cũng trồng rất nhiều (Quảng Nam, Đà Nẵng, Đắk Lắk, Lâm Đồng)',_binary '','','',NULL,'','Kích thích thần kinh, thông tiểu, chữa ỉa chảy, lỵ (Lá sắc uống).\n\n ','Chè xanh',' Chè, Mạy chà (Tày), Che (Kho), Co chà (Thái)','lá','BAN_NHAP','Camellia sinensis','','che-xanh',0,18,'Hoa mọc đơn độc, hoặc 2-3 cái ở kẽ lá, màu trắng; lá bắc dễ rụng; đài 5 răng không đều, tràng 5 cánh; nhị nhiều xếp thành 4-5 dãy, dính vào gốc tràng; bầu 3 ô, có lông.\n','Quả nang tròn, có 3 cạnh; hạt gần tròn đôi khi hơi nhăn nheo.\n','Lá mọc so le hình trái xoan, gốc tròn hoặc thuôn, đầu nhọn thành mũi, mép khía răng cưa, mặt trên nhẵn bóng.\n','','Cây nhỏ hay cây to, có kích thước lớn, có thể cao 8-10m hoặc lớn hơn.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765131155/ku3s0nacf0v2pgxz47ch.jpg'),(246,'2025-12-07 18:17:34','1','2025-12-07 18:17:34','1',NULL,'','Lạc tiên chứa pachypodol, 4’, 7-O-dimethyl-apigenin, ermanin-4’, 7-O-dimethyl-naringenin, 3,5-dihydroxy-4,7-dimethyloxyflavanon, chrysoerpol, 2”-xylosylvitexin, vitexin.\nHàm lượng flavonoid toàn phần là 0,074%.\nNgoài ra, cây còn chứa alcaloid 0,033%, trong đó có harman.','','',NULL,'Lạc tiên được dùng là thuốc an thần, chữa mất ngủ, suy nhược thần kinh.\n\nNgọn non của cây thường được thu hái để luộc ăn vào buổi chiều hoặc trước đi ngủ vài giờ.\n\nDạng thuốc thông thường là cao lỏng có đường được pha chế như sau: lạc tiên 400g, lá vong 400g, lá gai 100g, rau má 100g. Tất cả nấu với nước, cô đặc được 100ml. Đường nấu thành siro. Pha 6 phần cao với 4 phần siro. Ngày uống 40ml, chia làm 2 lần.','Mọc hoang ở khắp nơi tại nước ta. Thường trẻ con vẫn hái quả ăn. Trước đây hầu như nhân dân ta không dùng cây này làm thuốc.\nTừ năm 1940, một dược sĩ Việt Nam từ Pháp về thấy cây này hơi giống Passiflora ở bên Pháp mà tại Pháp người ta dùng cây đó làm thuốc an thần nên đã dùng cây lạc tiên của ta chế thành thuốc làm thuốc an thần. Từ đó ta quen dùng, chứ chưa ai kiểm tra theo dõi tác dụng đến đâu. Hái toàn cây trừ rễ,dùng tươi hay phơi khô mà chế thuốc sắc hay pha rượu thuốc. Không chế biến gì đặc biệt. Chưa ai đặt vấn đề trồng.',_binary '','','',NULL,'','thuốc an thần, gây ngủ, điều kinh, chữa suy nhược thần kinh, ho, phù thũng (Cả cây sắc uống). Lá giã đắp ngoài chữa ung nhọt, lở loét ở chân, viêm mủ da.','Lạc tiên','Lạc tiên, Chùm bao, Dây nhãn lồng, Cỏ hồng tiên (Thái), Dây lưới, Mấm nêm, Mò pì, Mác quánh mon (Tày)','','DA_XUAT_BAN','Passiflora foetida','','lac-tien',0,26,'Hoa đơn độc, 5 cánh màu trắng hay hơi tím nhạt, đường kính 5,5cm lá đài màu trắng phía dưới có gân xanh, dưới lá đài có 3 gân chính với những gân phụ trông như lá mà không có phiến chỉ có gân lá không thôi. Một đĩa có 2 tầng tua, mặt tua trên có màu tím trong vàng, trong cùng có lông mịn. Trụ cao có đầu tím đỏ, 5 nhị có bao phấn màu vàng gục xuống dưới.\n','Hoa đơn độc, 5 cánh màu trắng hay hơi tím nhạt, đường kính 5,5cm lá đài màu trắng phía dưới có gân xanh, dưới lá đài có 3 gân chính với những gân phụ trông như lá mà không có phiến chỉ có gân lá không thôi. Một đĩa có 2 tầng tua, mặt tua trên có màu tím trong vàng, trong cùng có lông mịn. Trụ cao có đầu tím đỏ, 5 nhị có bao phấn màu vàng gục xuống dưới.\n','Lá mềm, mọc so le, hình tim, dài 6-10cm, rộng 5-8cm, mép lượn sóng và xẻ hơi sâu thành 3 thuỳ, đáy lá hình tim, mép lá có lông mịn, cuống lá dài 7-8cm. Đầu tua cuống thành lò xo.\n','','Lạc tiên là một loại dây mọc leo, thân mềm, trên có rất nhiều lông mềm.\n',NULL,'http://res.cloudinary.com/dxqh3xpza/image/upload/v1765131450/cl2byfvovpkcrpompeed.jpg');
